) VALUES (
  'Prueba Rápida Cardiac Combo Advanced', 'cardiologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-cardiac-combo-advanced/', 'Prueba inmunológica cualitativa', 'Amunet',
  975, 180, '$600.00 - $1,000.00 (Examen especializado con factor H-FABP)', '200% - 400% (Calculado desde costo de ~$180 a ~$195)', '[{"cantidad":5,"precio":975},{"cantidad":10,"precio":1800}]'::jsonb,
  'Troponina I y H-FABP (Proteína de unión de ácidos grasos de tipo cardiaco)', 'sangre_total', '2 gotas (~50 µL) de muestra + 1 gota (~40 µL) de buffer en cada pozo S', '10 a 15 minutos', 89.9, 91,
  '8 ng/mL para H-FABP y ≈ 0.5 ng/mL para cTnI. **Relevancia Clínica:** El corte ultrabajo de 8 ng/mL para H-FABP es revolucionario porque permite detectar la fuga citosólica de esta proteína apenas 1 a 3 horas después del infarto, brindando una ventana de diagnóstico para trombolisar mucho antes de que la Troponina I demuestre daño estructural (>0.5 ng/mL).', '2°C a 30°C', '24 meses desde fabricación', 'NOM-241 COFEPRIS (Cumplido)',
  'Diagnóstico auxiliar / Urgencias ultratempranas', 'Permite la detección de isquemia y daño miocárdico en su fase inicial (desde la hora 1) a través de la incorporación del marcador H-FABP, apoyando a determinar tempranamente el síndrome coronario agudo en casos donde la Troponina aún no se eleva.', ARRAY['Cardiología', 'Urgencias Médicas', 'Terapia Intensiva'], '- **Urgencias / Triage Hiperagudo:** ¡Sea la vanguardia en cardiología! Si el paciente llega a Urgencias apenas 60 minutos después de que inició el dolor de pecho opresivo, la Troponina I tradicional saldrá falsamente negativa. Alíese del H-FABP (positivo en 1-3 horas) para aplicar terapia urgente y salvar el corazón antes de que empiece la necrosis transmural.',
  'Adultos con sospecha de IAM reciente (menor a 3 horas de evolución) o infartos reincidentes.', 'Al ingreso a urgencias y a evaluación seriada.', 'La presencia de enfermedades del músculo esquelético puede generar falsos reactivos cruzados en algunos marcadores.', 'Activación de código infarto, internamiento y derivación del paciente a cateterismo o trombolisis.', 'Observación estrecha y repetir con la versión tradicional de Troponina a las 3-6 horas para seguridad total.',
  'Adelántese al infarto 3 horas antes de que la Troponina siquiera suba. Detecte la isquemia aguda casi en tiempo real (1-3 hrs) con el marcador exclusivo H-FABP.', NULL, 'Exclusividad tecnológica de vanguardia. Esta prueba rompe el paradigma de la "zona ciega" de los infartos recientes. Los laboratorios clásicos no siempre manejan H-FABP en turnos nocturnos, dándole a su clínica el poder de salvar músculo cardiaco en la "hora dorada".', 'Un diferencial tecnológico. Facturar un "Perfil de Isquemia Hiperaguda" a $1,000 MXN en una sala de choque, por un costo que no llega ni a los $200 MXN (Más del 400% de utilidad y prestigio clínico invaluable).', NULL,
  '[{"pregunta":"¿Por qué es tan cara en comparación con la normal?","respuesta":"Porque incluye biotecnología de H-FABP exclusiva en México, que reduce el tiempo ciego del infarto en un 60%."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida NT-proBNP:","reason":"El propio sitio de Amunet lo recomienda: \"Combina tu Cardiac Combo Advanced con NT-proBNP y arma un paquete cardíaco realmente completo.\" NT-proBNP diferencia si el dolor/disnea es isquemia aguda (Advanced positivo) o insuficiencia cardíaca concomitante.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-peptidos-natriureticos-nt-probnp/"},{"name":"Prueba rápida de Dímero D:","reason":"Tercer diagnóstico diferencial del dolor torácico: infarto (Cardiac Advanced), insuficiencia cardíaca (NT-proBNP), o tromboembolismo pulmonar (Dímero D). \"Protocolo Triple Exclusión Torácica\".","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"}]'::jsonb, '[{"name":"\"Paquete Cardíaco Completo\" (Cardiac Advanced + NT-proBNP + Dímero D):","reason":"Para el médico que quiere convertirse en centro de referencia cardiológico point-of-care. Las tres pruebas cuestan menos de $450 en insumos y se cobran como protocolo de $2,500+. Cubre los tres diagnósticos diferenciales del dolor torácico en una sola consulta. URL NT-proBNP: https://www.amunet.com.mx/tienda/prueba-rapida-de-peptidos-natriureticos-nt-probnp/ URL Dímero D: https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/","url":null}]'::jsonb, ARRAY['H-FABP', 'infarto agudo', 'isquemia temprana', 'troponina I avanzada', 'urgencias coronarias', 'marcadores cardiacos premium', 'panel cardiaco completo', 'hora dorada infarto'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
