  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de péptidos natriuréticos (NT-proBNP)', 'cardiologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-peptidos-natriureticos-nt-probnp/', 'Prueba inmunológica cualitativa', 'Amunet',
  755, 135.4, '$500.00 - $800.00', '230% - 490% (Calculado desde costo de ~$135 a ~$151)', '[{"cantidad":5,"precio":755},{"cantidad":10,"precio":1354}]'::jsonb,
  'NT-proBNP (Porción N-terminal del propéptido natriurético tipo B)', 'sangre_total', '2 gotas', '10-15 min', NULL, NULL,
  'Habitualmente 300 pg/mL a 450 pg/mL. **Relevancia Clínica:** Este nivel actúa como una regla de oro de exclusión. Si el valor está por debajo, se tiene un altísimo valor predictivo negativo para descartar casi al 100% que la disnea aguda del paciente sea de origen cardíaco.', '2°C a 30°C', '24 meses', 'NOM-241 COFEPRIS',
  'Diagnóstico diferencial y de exclusión', 'Ayuda al médico a discriminar entre causas cardiacas y pulmonares de la dificultad respiratoria. Si el NT-proBNP es negativo, prácticamente se descarta la insuficiencia cardiaca (altísimo valor predictivo negativo).', ARRAY['Cardiología', 'Neumología', 'Urgencias', 'Medicina Interna'], '- **Urgencias / Neumología:** ¡Diferencie EPOC vs Corazón al instante! Un anciano hipertenso fumador llega asfixiándose a urgencias a las 3 a.m. Aplique el NT-proBNP; si da negativo, puede garantizar que el problema es pulmonar y nebulizar con confianza, salvando el tiempo de oro.
  - **Medicina Interna:** Verifique en consultorio si su paciente obeso y diabético que presenta "hinchazón en las piernas" (edema periférico progresivo) está desarrollando insuficiencia cardíaca a escondidas.',
  'Adulto de la tercera edad, con antecedente de hipertensión, fatiga, disnea inexplicable e inflamación de miembros inferiores.', 'Diagnóstica aguda, o monitoreo al hacer ajustes en medicación antihipertensiva o diurética.', 'Se puede elevar falsamente en falla renal grave o sepsis.', 'Corrobora diagnóstico de Falla Cardiaca. Administrar diuréticos de asa / inotrópicos y seguir el protocolo del especialista.', 'Regla de oro: Descartar origen del corazón e iniciar búsqueda neumológica del ahogo.',
  'Identifique si esa disnea asfixiante o edema viene de una falla aguda del corazón o de los pulmones con 100% de confianza excluyente, directamente desde su camilla de exploración.', NULL, 'Pedir un pro-BNP a laboratorio central tarda horas. Usar este cassette descarta la causa cardiológica frente al paciente ahogándose, iluminando su decisión terapéutica (diurético vs nebulizador) de inmediato en guardia o clínica.', 'La prueba de oro de falla cardíaca. Puede facturarla como "Valoración de Función Cardíaca Urgente" en $800 MXN o $1000 MXN mientras su costo ronda apenas los ~140 pesos.', NULL,
  '[{"pregunta":"¿Es preferible un ecocardiograma?","respuesta":"El eco es confirmatorio y morfológico, pero la prueba de NT-proBNP se aplica en 15 minutos exactos y es la regla de exclusión de oro antes del costoso ECO."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida Cardiac Combo:","reason":"La insuficiencia cardíaca aguda frecuentemente es desencadenada por un infarto silencioso. Si el NT-proBNP sale positivo, aplique inmediatamente Cardiac Combo para identificar si hay necrosis miocárdica activa que causó el colapso ventricular. Protocolo: NT-proBNP (+) → Cardiac Combo → si (+), código infarto.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-troponina-cardiac-combo/"},{"name":"Prueba rápida de Dímero D:","reason":"La disnea aguda tiene tres etiologías cardiopulmonares críticas: insuficiencia cardíaca (NT-proBNP), infarto (Cardiac Combo), y tromboembolia pulmonar (Dímero D). NT-proBNP + Dímero D = diagnóstico diferencial de disnea completo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"}]'::jsonb, '[{"name":"Prueba rápida Cardiac Combo Advanced (H-FABP + Troponina):","reason":"Si ya evalúa falla cardíaca con NT-proBNP, el paso natural es descartar isquemia activa con H-FABP. H-FABP detecta daño miocárdico desde la hora 1 (JACC, 2019), lo que permite actuar antes de que la ventana terapéutica se cierre.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-cardiac-combo-advanced/"}]'::jsonb, ARRAY['Insuficiencia cardiaca', 'falla del corazón', 'disnea', 'NT-proBNP', 'probnp', 'peptido natriurético', 'cansancio crónico del corazón', 'diagnóstico diferencial disnea'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
