-- Product: Prueba rápida de Dimero D
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Dimero D', 'cardiologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/', 'Prueba inmunológica cualitativa', 'Amunet',
  465, 90, '$400.00 - $600.00 (Examen especializado urgencia)', '330% - 560% (Calculado desde costo de ~$90 a ~$93)', '[{"cantidad":5,"precio":465},{"cantidad":20,"precio":1800}]'::jsonb,
  'Productos de degradación de la fibrina (Dímero D)', 'sangre_total', '2 gotas', '10-15 min.', 95, NULL,
  '500 ng/mL FEU. **Relevancia Clínica:** Es el umbral clínico de exclusión universal. Un resultado negativo (< 500 ng/mL FEU) en un paciente con probabilidad pretest baja o moderada asegura con más de un 95% de confianza que no existe una Tromboembolia Pulmonar o Trombosis Venosa Profunda activa.', '2°C a 30°C', '24 meses', 'NOM-241 COFEPRIS',
  'Diagnóstico de exclusión (Tamizaje)', 'Identificar si hay activación de la coagulación y fibrinólisis extensa. Su principal utilidad es el enorme valor predictivo negativo: un resultado negativo permite descartar de manera confiable una Tromboembolia Pulmonar (TEP) o Trombosis Venosa Profunda (TVP) en pacientes de probabilidad baja o moderada sin requerir imagenología.', ARRAY['Urgencias', 'Traumatología', 'Medicina Interna', 'Ginecología', 'Angiología'], '- **Traumatología / Urgencias:** ¡Asegure sus post-operatorios! Un paciente (ej. post prótesis de rodilla) llega con la pantorrilla eritematosa y caliente. Antes de solicitar un Eco Doppler bilateral urgente de $3,500 MXN, aplique su Dímero D rápido. Si es negativo, usted da el alta al paciente con absoluta tranquilidad médica y legal.
  - **Ginecología:** ¡Proteja a sus pacientes bajo hormonas! Mujer joven obesa que toma anticonceptivos orales y se queja de "falta de aire misteriosa". Use esta herramienta de exclusión instantánea en su propia clínica.',
  'Adulto o persona mayor con riesgo protrombótico (vuelos largos, cáncer, embarazo, inmovilización postquirúrgica).', 'Ante evento de sospecha tromboembólica aguda.', 'Muchos falsos positivos (inflamación aguda, sepsis, cáncer). Su utilidad brilla exclusivamente para EXCLUIR en resultados negativos.', 'El paciente debe complementar evaluación imperativamente con ultrasonido doppler (piernas) o angiotomografía pulmonar para confirmar evento isquémico.', 'Exclusión completa garantizada frente al evento trombótico. Alta segura y ahorro de ecos innecesarios.',
  'Conviértase en una clínica de exclusión tromboembólica: bríndeles paz mental a sus pacientes descartando coágulos (TEP/TVP) en 15 minutos sin hacerlos ir al radiólogo.', NULL, 'Es una respuesta binaria brillante (Blanco/Negro) que detiene el algoritmo de pánico del paciente de forma costo-efectivísima, dándole autonomía resolutiva al traumatólogo o angiólogo en su sala de curaciones.', 'Cobrando un "Escrutinio Tromboembólico Preventivo" a $600 pesos (con un costo menor a $95 pesos) se le ahorra dinero al paciente y el doctor retiene márgenes impresionantes (hasta 560%) blindándose contra negligencias.', NULL,
  '[{"pregunta":"El dímero D a veces sale falso positivo porque hay inflamación","respuesta":"¡Así es! Todo Dímero D se eleva por simple inflamación o cirugía. Por eso, su meta de uso real es que cuando sea NEGATIVO, descarte radicalmente toda posibilidad de TEP y usted ahorre recursos confirmatorios."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida Cardiac Combo:","reason":"Dímero D positivo excluye TEP. Pero Cardiac Combo excluye infarto. En dolor torácico agudo, las guías ESC/AHA recomiendan evaluar AMBAS etiologías simultáneamente (estrategia multimarcador). Costo combinado: ~$240, cobrando \"Protocolo de Exclusión Torácica\" a $1,200+.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-troponina-cardiac-combo/"},{"name":"Prueba rápida NT-proBNP:","reason":"Dímero D positivo + disnea = ¿TEP o insuficiencia cardíaca? El NT-proBNP resuelve ese diagnóstico diferencial en 15 minutos. Protocolo: Dímero D → si (+) y disnea → NT-proBNP para diferenciar origen embólico vs cardíaco.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-peptidos-natriureticos-nt-probnp/"}]'::jsonb, '[{"name":"Prueba rápida Cardiac Combo Advanced (H-FABP + Troponina):","reason":"Si usted ya usa Dímero D en su protocolo de urgencia, el siguiente paso es Cardiac Combo Advanced. H-FABP detecta isquemia desde la hora 1, cerrando la \"zona ciega\" del diagnóstico cardíaco temprano. \"Kit de Urgencia Torácica Premium\" = Dímero D + Cardiac Advanced + NT-proBNP.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-cardiac-combo-advanced/"}]'::jsonb, ARRAY['Trombosis', 'Tromboembolia', 'TVP', 'TEP', 'coágulos', 'Dimero D', 'embolia', 'flebitis', 'dolor de pierna'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
