-- Product: Prueba rápida de Hemoglobina Glicosilada Cualitativa (HbA1c)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Hemoglobina Glicosilada Cualitativa (HbA1c)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-hba1c-cualitativa/', 'Prueba rápida inmunocromatográfica cualitativa in vitro', 'Amunet',
  418, 83.4, '$200.00 - $400.00', '140% - 380% (Calculado desde costo de ~$83.50)', '[{"cantidad":5,"precio":418},{"cantidad":20,"precio":1668}]'::jsonb,
  'Hemoglobina glicada (HbA1c)', 'sangre_total', '1 gota de sangre (~10 µL), depositada en tubo de extracción con diluyente. Se aplican 3 gotas.', 'Exactamente a los 8 minutos. (No interpretar después de 10 min).', 99.57, 98.44,
  'Detección exclusiva para concentraciones > 6.5% de HbA1c. **Relevancia Clínica:** Según la CDC y lineamientos médicos, un umbral de 6.5% establece asociación a la diabetes franca. Permite saber si el paciente en consultorio excede el nivel diabético seguro, sin presentar reacción o falsos positivos ante aspirina, paracetamol o bilirrubina alta.', '15°C a 30°C (NO congelar, a diferencia de otras pruebas)', 'Estable hasta fecha de caducidad impresa.', 'Registro 0171R2024 SSA (Uso para Investigación - UPI). Cumple NOM-241 COFEPRIS para fabricación.',
  'Diagnóstico auxiliar precoz / Monitoreo cualitativo / Tamizaje Gestacional', 'El objetivo de esta prueba difiere según el tipo de paciente:', ARRAY['Medicina General', 'Medicina Interna', 'Endocrinología', 'Nutrición', 'Ginecología y Obstetricia'], '- **Ginecología / Control Prenatal:** ¡Proteja a la madre y al bebé al instante! Ante cualquier factor de riesgo de diabetes gestacional en el primr o segundo trimestre, ofrezca un escrutinio inmediato en su propio sillón de exploración. Evite enviar a su paciente a hacer ayunos o filas al laboratorio, obtenga la confirmación temprana y arranque el manejo preventivo ese mismo día, elevando drásticamente el valor de su consulta prenatal.
  - **Médico General:** ¡Transforme su consulta de primer contacto! Cuando se presente ese paciente con factores de riesgo (obesidad, sedentarismo, herencia) que lleva años sin hacerse estudios, no lo deje ir a la deriva. Realice el tamizaje metabólico en solo 8 minutos y ofrézcale un diagnóstico y un plan de acción contundente antes de que salga por la puerta.
  - **Endocrinología / Medicina Interna:** ¡Cero citas de seguimiento desperdiciadas! Si su paciente diabético recurrente olvidó llevar su analítica mensual, recupere el control al instante. Verifique visualmente si su curva de los últimos 90 días rompió la barrera del 6.5%, ajuste la dosis de metformina o insulina en tiempo real y asegure su adherencia terapéutica.',
  'Adulto mayor a 45 años, personas con sobrepeso u obesidad, mujeres embarazadas, o pacientes con DM2 en control de medicación.', 'Seguimiento de control.', 'Solo detecta niveles >6.5%, no entrega valores porcentuales exactos para cálculos de dosis fina. Su rango de hematocrito aceptado es del 25% al 65%.', 'El paciente cursa en descontrol formal, ajustar tratamiento médico y referir a la brevedad biometría/química sanguínea.', 'El paciente mantiene controles adecuados (menor a 6.5%).',
  'Detecte el umbral diabético crítico del 6.5% en solo 8 minutos desde su consultorio, sin necesidad de infraestructura y reteniendo al paciente en su clínica.', NULL, 'No interfiere con medicamentos comunes (aspirina, paracetamol) y brinda precisión nivel CLIA (99.32%) al instante, empoderando su consulta para ajustes inmediatos.', 'Inversión sumamente baja (< $84 MXN por paciente), justificada como "prueba de control integral" agregando amplio valor monetario a la visita.', NULL,
  '[{"pregunta":"Es cualitativa, necesito el punto exacto","respuesta":"El valor de esta prueba es actuar como semáforo de alerta clínica inmediata. Al dar positivo (>6.5%), usted ya sabe al instante que su paciente requiere ajuste, sin esperar días por el laboratorio central."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Albúmina/Microalbuminuria:","reason":"Las guías ADA (American Diabetes Association, 2024) recomiendan tamizaje ANUAL de microalbuminuria + HbA1c para TODO paciente con diabetes tipo 2 desde el diagnóstico. HbA1c mide el control glucémico de 90 días; Microalbuminuria detecta si el riñón ya está sufriendo. Juntas = \"Evaluación Diabética Integral\" en una sola consulta.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-albumina-semicuantitativa/"},{"name":"Prueba rápida Cardiac Combo:","reason":"La diabetes es el principal factor de riesgo para enfermedad cardiovascular. Si HbA1c sale positiva (>6.5%), evaluar riesgo cardíaco con marcadores de daño miocárdico es clínicamente pertinente.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-troponina-cardiac-combo/"}]'::jsonb, '[{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"La anemia es complicación frecuente de la diabetes (nefropatía → eritropoyetina ↓ → anemia). Si el paciente diabético también tiene fatiga, el \"Panel Metabólico\" (HbA1c + Ferritina) identifica dos causas en una visita.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"}]'::jsonb, ARRAY['Hemoglobina glicosilada', 'HbA1c', 'A1c', 'control diabético', 'seguimiento diabetes', 'glucosa promedio', 'azúcar en sangre', 'control de glucemia', 'prueba 8 minutos'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
