-- Product: Prueba rápida FERRI-NET (Ferritina)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida FERRI-NET (Ferritina)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/', 'Prueba rápida inmunocromatográfica semicuantitativa in vitro', 'Amunet',
  578, 108, '$350.00 - $500.00', '200% - 360% (Calculado desde costo de ~$110)', '[{"cantidad":5,"precio":578},{"cantidad":20,"precio":2161}]'::jsonb,
  'Ferritina humana (marcador indirecto de reserva de hierro)', 'sangre_total', '1-2 gotas de sangre/suero + 1 gota de buffer', '10-15 minutos', NULL, NULL,
  'Semicuantitativo. El cartucho discierne visualmente (intensidad de la línea T vs R) la deficiencia según el género: **30 ng/mL para hombres y 13 ng/mL para mujeres**. **Relevancia Clínica:** Valores por debajo de estos umbrales confirman el vaciamiento de las reservas de hierro intracelular. Confirma anemia ferropénica activa, síndrome de piernas inquietas, o malabsorción (enfermedad celíaca) antes de que caiga la hemoglobina.', '15°C a 30°C', 'Estable hasta fecha de caducidad impresa.', 'Clave Amunet asignada (consultar etiqueta del producto)',
  'Diagnóstico auxiliar etiológico / Escrutinio de deficiencia.', 'Determinar si un cuadro de fatiga, palidez o anemia ya diagnosticada se debe específicamente a una deficiencia en los depósitos de hierro del cuerpo.', ARRAY['Medicina General', 'Ginecología', 'Hematología', 'Gastroenterología'], '- **Medicina General:** ¡No adivine el origen de la fatiga! Ante un paciente con astenia crónica, caída de cabello o palidez, confirme si hay deficiencia de hierro en 10 minutos sin esperar una cinética de hierro completa.
  - **Ginecología:** ¡Proteja a la paciente con sangrado uterino anormal o embarazo! Verifique sus reservas de hierro inmediatamente en su consultorio para iniciar suplementación (hierro oral o intravenoso) el mismo día.
  - **Gastroenterología:** Pacientes con sospecha de enfermedad celíaca o sangrado de tubo digestivo crónico. Valide el vaciamiento de depósitos de hierro al momento.',
  'Mujeres en edad reproductiva con sangrados abundantes, embarazadas, adultos mayores con fatiga, o pacientes con sospecha de intestino permeable.', 'Al diagnóstico y a los 3 meses de iniciar suplementación con hierro.', 'La ferritina es un reactante de fase aguda; puede elevarse falsamente en estados inflamatorios graves o infecciones, enmascarando una deficiencia.', 'Línea T más tenue que R (o ausente). Prescribir suplementación con hierro inmediatamente e investigar la causa de la pérdida (ginecológica o gastrointestinal).', NULL,
  'Detecte el origen exacto de la anemia y la fatiga crónica discriminando biológicamente entre hombres (30 ng/mL) y mujeres (13 ng/mL) directly en su sillón de exploración.', NULL, 'Una cinética de hierro en laboratorio cuesta más de $600 MXN y tarda 24 horas. Esta prueba le da la respuesta etiológica por menos de $115 frente al paciente, permitiendo recetar hierro bajo evidencia sólida en la primera visita.', 'Inversión bajísima. Cobrar la prueba en $400 MXN como "Perfil rápido de Fatiga/Anemia" le otorga casi 300% de margen y un paciente inmensamente agradecido por la rapidez.', NULL,
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Transferrina / Sangre Oculta en Heces (FOB):","reason":"Si FERRI-NET confirma deficiencia de hierro en un adulto mayor o varón, la siguiente pregunta obligatoria es: ¿de dónde pierde sangre? FOB detecta sangrado gastrointestinal oculto (cáncer de colon, úlcera, H. pylori sangrante). Protocolo: Ferritina baja → FOB → si (+), colonoscopia.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/"},{"name":"Prueba rápida de H. pylori (heces):","reason":"Helicobacter pylori causa gastritis crónica erosiva, que es una causa frecuente de anemia ferropénica por sangrado microscópico crónico. Si Ferritina es baja, investigar H. pylori complementa la evaluación.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori-en-heces/"}]'::jsonb, '[{"name":"Prueba rápida de HbA1c:","reason":"Pacientes con ferritina baja + fatiga frecuentemente también son prediabéticos no diagnosticados. El \"Perfil de Fatiga Metabólica\" (Ferritina + HbA1c) resuelve las dos causas más comunes de agotamiento crónico: anemia y diabetes.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-hba1c-cualitativa/"}]'::jsonb, ARRAY['Ferritina', 'anemia', 'deficiencia de hierro', 'fatiga', 'cansancio', 'sangrado', 'cinética de hierro', 'reservas de hierro'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
