-- Product: Prueba rápida de IgE (Inmunoglobulina E)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de IgE (Inmunoglobulina E)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-ige/', 'Prueba rápida inmunocromatográfica cualitativa in vitro', 'Amunet',
  375, 60, '$250.00 - $400.00', '230% - 560% (Calculado desde costo de ~$65)', '[{"cantidad":5,"precio":375},{"cantidad":20,"precio":1200}]'::jsonb,
  'Inmunoglobulina E (IgE) humana', 'sangre_total', '1-2 gotas de sangre/suero + 1 gota de buffer', '10-15 minutos', NULL, NULL,
  'Detección de concentraciones patológicamente elevadas de IgE total. **Relevancia Clínica:** Dado que la IgE se encuentra normalmente en cantidades reducidas en el torrente sanguíneo, un resultado positivo detecta un aumento súbito y exagerado del sistema inmune frente a alérgenos benignos. Confirma objetivamente la naturaleza "alérgica" de la sintomatología.', '15°C a 30°C (NO congelar)', 'Estable hasta fecha de caducidad.', 'Clave Amunet asignada (consultar etiqueta del producto)',
  'Escrutinio inicial de atopia y reacciones de hipersensibilidad.', 'Diferenciar si un cuadro clínico respiratorio, dérmico o sistémico es causado por una respuesta alérgica verdadera o por una etiología viral/bacteriana.', ARRAY['Medicina General', 'Pediatría', 'Neumología', 'Dermatología', 'Urgencias'], '- **Medicina General / Pediatría:** ¡Deje de prescribir antibióticos por error! Ante un niño con escurrimiento nasal crónico o tos persistente, confirme en 10 minutos si su problema es asma/rinitis alérgica o una infección. 
  - **Dermatología / Urgencias:** ¡Documente la alergia in situ! En pacientes con urticaria o erupciones agudas, documente de inmediato el disparo de IgE para justificar un tratamiento potente con corticosteroides o antihistamínicos sistémicos.',
  'Niños con sospecha de asma, pacientes con rinitis alérgica estacional, o personas con reacciones dérmicas por ingesta de alimentos.', 'Ante eventos episódicos agudos o en la evaluación basal diagnóstica.', 'La prueba detecta IgE TOTAL elevada, NO especifica a qué alérgeno reaccionó el paciente (polvo, cacahuate, polen).', 'Confirmación de respuesta atópica. Iniciar antihistamínicos/corticoides y referir a Alergología para panel de alérgenos específicos si la causa es desconocida.', NULL,
  'Separe al instante una infección viral de una crisis alérgica verdadera y recete con total precisión frente al paciente, usando una sola gota de sangre.', NULL, 'Los paneles de IgE en laboratorio son costosos y demoran. Esta prueba funge como un "filtro" primario ultrabarato (< $70 MXN) que le da justificación clínica a su receta de antihistamínicos en tiempo real.', 'A menos de $70 MXN por prueba, se ofrece como "Screening Alergológico de Consultorio" por $300 MXN, generando más del 400% de margen. El paciente sale con diagnóstico objetivo y receta justificada en la misma consulta.', NULL,
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"Muchos pacientes con cuadro \"alérgico\" (fatiga + palidez + tos crónica) realmente tienen anemia ferropénica, no alergia. IgE + Ferritina = diagnóstico diferencial de fatiga crónica con componente atópico. Si IgE es negativa y hay fatiga, Ferritina identifica la causa real.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"},{"name":"Prueba rápida de H. pylori (sangre):","reason":"El H. pylori puede causar urticaria crónica por mecanismo autoinmune. En pacientes con IgE elevada + ronchas recurrentes que no responden a antihistamínicos, la literatura médica recomienda descartar infección por H. pylori como causa subyacente (Annals of Allergy, 2019).","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori/"}]'::jsonb, '[{"name":"Prueba rápida Cardiac Combo:","reason":"La elevación de IgE también se asocia a síndromes coronarios agudos (Kounis syndrome). Si el paciente alérgico presenta dolor torácico durante la reacción, evaluar marcadores cardíacos es clínicamente prudente.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-troponina-cardiac-combo/"}]'::jsonb, ARRAY['IgE', 'alergia', 'rinitis', 'asma', 'urticaria', 'hipersensibilidad', 'prueba de alergias', 'ronchas'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
