-- Product: Prueba rápida de Albúmina Semicuantitativa y Cualitativa (Microalbuminuria)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Albúmina Semicuantitativa y Cualitativa (Microalbuminuria)', 'metabolicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-albumina-semicuantitativa/', 'Prueba rápida inmunocromatográfica competitiva in vitro de orina', 'Amunet',
  250, 35, '$150.00 - $300.00', '200% - 750% (Calculado desde costo de ~$40)', '[{"cantidad":5,"precio":250},{"cantidad":20,"precio":700}]'::jsonb,
  'Albúmina humana en orina', 'orina', '3 gotas (~120 µL) de muestra preparada con el tubo colector', '5 minutos (no interpretar después de 10 minutos)', NULL, NULL,
  'Detección de concentraciones patológicas entre **20 µg/mL y 200 µg/mL**. **Relevancia Clínica:** Niveles por encima de 20 µg/mL en orina diagnostican formalmente **Microalbuminuria**. Esto marca el inicio del daño renal (nefropatía) e indica un riesgo cardiovascular severo en pacientes diabéticos tipo 1 y 2, así como daño vascular en pacientes hipertensos.', '15°C a 30°C (NO congelar)', 'Estable hasta fecha de caducidad.', 'Clave Amunet asignada (consultar etiqueta del producto)',
  'Diagnóstico y prevención de daño de órgano blanco.', 'Prevenir la insuficiencia renal crónica descubriendo el daño renal en su etapa inicial 100% reversible, antes de que progrese a proteinuria masiva.', ARRAY['Nefrología', 'Endocrinología', 'Cardiología', 'Medicina Interna', 'Medicina General'], '- **Médico General / Diabetólogo:** ¡Salve riñones en su sala de consulta! A todo paciente diabético o hipertenso se le debe evaluar el riñón anualmente. En lugar de mandar recolección de orina de 24 hrs que el paciente nunca hace, pídale una muestra de orina en el baño de su clínica y valide su filtrado glomerular al instante.
  - **Cardiología:** ¡Identifique el riesgo CV! La microalbuminuria es un marcador independiente de morbimortalidad cardiovascular extrema en hipertensos. Identifíquelo al momento y justifique el de uso IECAs o ARA-II agresivos.',
  'Adultos con Diabetes Mellitus (1 y 2), pacientes con Hipertensión Arterial de larga evolución.', 'Escrutinio anual en diabéticos sin microalbuminuria previa.', 'La orina muy diluida puede generar falsos negativos (por eso se prefiere la primera de la mañana). El ejercicio intenso o fiebre también pueden causar albuminuria transitoria temporal.', 'El riñón del paciente está fugando proteínas. Se debe iniciar tratamiento inmediato de nefroprotección (IECAs / ARA-II / iSGLT2) y referir a cuantificación por laboratorio / nefro.', NULL,
  'Anticípese a la insuficiencia renal años antes de que la creatinina se eleve; detecte la microalbuminuria en 5 minutos obligando a sus pacientes diabéticos a tomar en serio su salud renal.', NULL, 'La recolección de orina de 24 horas es incómoda y poco práctica para el paciente. Su clínica ofrece la comodidad VIP de saber si el riñón está fallando en solo unos minutos con prueba de flujo lateral.', 'Costo extraordinariamente barato (< $45 MXN). El médico eleva su prestigio diagnosticando lo que otros ignoran, cobra 300% de margen y justifica la prescripción de medicamentos nefroprotectores premium.', NULL,
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida HbA1c:","reason":"El combo de oro ADA para el paciente diabético: HbA1c evalúa control glucémico de 90 días, Microalbuminuria detecta si ya hay daño renal. Cobrar como \"Evaluación Diabética Integral\" en una sola consulta.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-hba1c-cualitativa/"},{"name":"Prueba rápida Cardiac Combo:","reason":"La microalbuminuria es un marcador independiente de riesgo cardiovascular (KDIGO Guidelines). Si se detecta albuminuria, evaluar daño cardíaco con marcadores de necrosis miocárdica complementa la estratificación de riesgo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-troponina-cardiac-combo/"}]'::jsonb, '[{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"La nefropatía diabética causa anemia por eritropoyetina reducida. Si el paciente tiene microalbuminuria positiva + fatiga, evaluar ferritina identifica anemia renal temprana. \"Panel Renal-Nutricional\" completo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"}]'::jsonb, ARRAY['Microalbuminuria', 'albúmina en orina', 'daño renal', 'riñón', 'nefropatía diabética', 'nefroprotección', 'proteínas en orina', 'insuficiencia renal'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
