-- Product: Prueba rápida de H. pylori (Helicobacter pylori)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de H. pylori (Helicobacter pylori)', 'gastrointestinal', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori/', 'Prueba rápida inmunocromatográfica cualitativa in vitro', 'Amunet',
  160, 65, '$250.00 - $450.00', '210% - 590% (Calculado desde costo de ~$70)', '[{"cantidad":2,"precio":160},{"cantidad":20,"precio":1300}]'::jsonb,
  'Anticuerpos de tipo IgG contra antígeno de *Helicobacter pylori*', 'sangre_total', '2-3 gotas de sangre + 1 gota de buffer (consultar inserto DRAM002)', '10 minutos', NULL, NULL,
  'Detección exclusiva para respuesta inmunológica montada contra la bacteria en suero. **Relevancia Clínica:** La bacteria produce ureasa y daña crónicamente la mucosa gástrica provocando úlceras (1-10%) o un riesgo elevado de carcinoma gástrico a largo plazo. La aparición de los anticuerpos IgG conforma la defensa sistémica y confirma históricamente u operativamente la exposición o colonización gástrica del patógeno.', '15°C a 30°C', 'Estable hasta fecha de caducidad.', 'Clave Amunet asignada (consultar etiqueta del producto)',
  'Diagnóstico etiológico no invasivo y Escrutinio.', 'Separar la gastritis química o por estrés de una infección bacteriana activa por H. pylori que requiere tratamiento de erradicación con antibióticos, evitando que progrese a metaplasia intestinal o úlcera péptica.', ARRAY['Gastroenterología', 'Medicina Interna', 'Medicina General'], '- **Medicina General:** ¡No recete solo bombas de protones! Ante el altísimo volumen de pacientes con ardor epigástrico y dispepsia ("gastritis"), diferencie en 10 minutos si necesita Omeprazol o una terapia triple antibiótica.
  - **Gastroenterología:** ¡Tamizaje no invasivo rápido! Ahorre a los pacientes jóvenes con dispepsia no complicada (sin signos de alarma) el procedimiento invasivo de endoscopia, o utilícela como paso previo para justificar la biopsia.',
  'Adultos jóvenes o de mediana edad con dolor epigástrico crónico, acidez, reflujo, o antecedentes familiares de úlcera estomacal / cáncer gástrico.', 'Diagnóstico inicial (screening).', 'Al detectar anticuerpos IgG, la prueba permanece positiva meses o años después de una erradicación exitosa (cicatriz serológica). NO es útil para confirmar que el tratamiento funcionó (allí se prefiere antígeno en heces o aliento).', 'El paciente ha estado expuesto o tiene colonización. En un paciente sintomático sin tratamiento previo (naïve), justifica sobradamente iniciar protocolo de erradicación (Ej: Claritromicina + Amoxicilina + IBP).', NULL,
  'Detecte a la bacteria causante de las úlceras estomacales en 10 minutos con una gota de sangre, justificando la venta de su tratamiento antibiótico sin enviar al paciente al laboratorio.', NULL, 'Las pruebas de aliento son molestas y la endoscopia cuesta miles de pesos. Esta prueba ofrece un tamizaje de primer contacto baratísimo (< $80 MXN) que le empodera para resolver la raíz bacteriana de la colitis/gastritis en la misma consulta.', 'Cobrar $350 MXN por un escrutinio de cáncer gástrico e infección por H. pylori da un aura de alta especialidad al médico general, reportando más de $250 pesos de utilidad neta en 10 minutos por paciente.', NULL,
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida H. pylori en Heces (Antígeno):","reason":"La serología (sangre) detecta anticuerpos IgG que persisten meses-años post-erradicación. Si da positivo en paciente sin tratamiento previo, confirme infección ACTIVA con la versión fecal que detecta antígeno directo. Protocolo Maastricht V: serología (+) → confirmar con antígeno fecal antes de tratar.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori-en-heces/"},{"name":"Prueba rápida de Transferrina/FOB (Sangre Oculta en Heces):","reason":"La OMS declaró a H. pylori carcinógeno Clase I en 1994. Un ensayo clínico en Taiwan (JAMA 2019) demostró que combinar H. pylori + FOB en la misma visita detecta problemas del tracto GI alto (H. pylori → cáncer gástrico) y bajo (FOB → cáncer colorrectal) simultáneamente.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/"}]'::jsonb, '[{"name":"Prueba rápida de CA 19-9:","reason":"Si H. pylori es positivo y el paciente tiene síntomas crónicos (>6 meses), agregar marcador tumoral CA 19-9 (páncreas/GI) evalúa riesgo oncológico del tracto digestivo alto. \"Panel Gastroenterológico Premium.\"","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-ca-19-9/"}]'::jsonb, ARRAY['Helicobacter pylori', 'gastritis', 'úlcera', 'dolor de estómago', 'dispepsia', 'agruras', 'bacteria del estómago', 'prueba rápida estómago'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
