  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Helicobacter pylori (Ag) en heces', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori-en-heces/', 'Prueba inmunológica cualitativa', 'Amunet',
  290, 130, '$350.00 - $500.00', '140% - 280% (Calculado desde un costo unitario de ~$130 a ~$145)', '[{"cantidad":2,"precio":290},{"cantidad":20,"precio":2600}]'::jsonb,
  'Antígenos de Helicobacter pylori', 'heces', 'Una porción de heces recolectada con el hisopo aplicador incluido (~50 mg o 50 µL si es líquida) disuelta en el buffer.', '10 a 15 minutos', 86.4, 99,
  'Detección cualitativa de presencia o ausencia de antígeno fecal.', '2°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Activo / Confirmatorio post-tratamiento', 'Detectar de forma directa el antígeno de *H. pylori* excretado en heces para confirmar una **infección gástrica activa** (a diferencia de los anticuerpos en sangre que solo indican memoria inmunológica). También es el estándar no invasivo para corroborar la erradicación del patógeno semanas después del tratamiento antibiótico.', ARRAY['Gastroenterología', 'Medicina Interna', 'Medicina General'], '- **Consultorio General:** Paciente con dispepsia, agruras crónicas o dolor epigástrico urente. En lugar de recetar empíricamente IBP ("omeprazol"), envíele a recolectar su muestra y pruebe la presencia de antígeno esa misma tarde.
  - **Monitoreo post-tratamiento:** Un mes después de terminar el agresivo cóctel antibiótico de erradicación, se utiliza esta prueba para dar el "alta microbiológica" asegurando que el antígeno ya no se detecta (garantizando curación de la úlcera).',
  'Adultos con sospecha de gastritis crónica, enfermedad ulcerosa péptica, reflujo resistente a tratamiento, o familiares de pacientes con cáncer gástrico.', 'Al diagnóstico de dispepsia y 4 semanas post-tratamiento.', 'El uso reciente de inhibidores de bomba de protones (IBP), bismuto o antibióticos puede dar falsos negativos al suprimir la carga bacteriana (se recomienda suspender IBP 2 semanas antes).', 'Indica infección activa. Iniciar terapia de erradicación (Ej. triple o cuádruple terapia con claritromicina/amoxicilina/IBP).', 'Si los síntomas persisten y la sospecha clínica es alta de todos modos, derivar a endoscopia superior con toma de biopsia.',
  'El estándar de oro no invasivo para dictaminar una infección gástrica activa y corroborar su cura definitiva, sin requerir dolorosas endoscopias.', NULL, 'Mientras la serología en sangre (anticuerpos) engaña al clínico manteniéndose positiva por años tras curar al paciente, esta prueba en heces busca el "cuerpo" de la bacteria. Es el test ideal para retener al paciente gastrointestinal en su clínica en lugar de mandarlo al laboratorio en cada control.', 'Cobrando un "Escrutinio de H. pylori" en $400 pesos por un costo de 130 pesos, se obtiene un margen atractivo sobre uno de los motivos de consulta más frecuentes en México.', NULL,
  '[{"pregunta":"¿El paciente no quiere traer la muestra?","respuesta":"Ofrecemos el beneficio del anonimato local; el paciente puede recolectar la muestra en la comodidad del baño de su propia casa/clínica y el cartucho procesarla discretamente en el anexo de su consultorio en 10 minutos."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Transferrina/FOB (Sangre Oculta en Heces):","reason":"El Taiwan trial (JAMA, 2019) demostró que usar H. pylori fecal + FOB con la MISMA muestra de heces permite evaluar tracto GI superior (H. pylori → cáncer gástrico, úlcera) e inferior (FOB → cáncer colorrectal) en una sola recoleción. \"Panel Gastrointestinal Completo\" en una sola muestra.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/"},{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"H. pylori causa gastritis erosiva crónica → sangrado microscópico → anemia ferropénica. Si el paciente tiene H. pylori confirmado + fatiga, evaluar ferritina identifica la consecuencia hematológica de la infección.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"}]'::jsonb, '[{"name":"Prueba rápida de CA 19-9 + AFP:","reason":"Si H. pylori fecal es positivo y el paciente tiene síntomas crónicos, agregar marcadores tumorales gastrointestinales eleva la consulta a \"Escrutinio Oncológico Digestivo\". URL CA 19-9: https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-ca-19-9/ URL AFP: https://www.amunet.com.mx/tienda/prueba-rapida-de-afp/","url":null}]'::jsonb, ARRAY['Helicobacter', 'dolor de estómago', 'gastritis', 'úlcera péptica', 'antígeno en heces para helicobacter', 'ardor de estómago', 'dispepsia', 'H. pylori Ag'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
