-- Product: Prueba rápida de Sífilis
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Sífilis', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-sifilis/', 'Prueba inmunológica cualitativa (Treponémica)', 'Amunet',
  150, 36, '$150.00 - $300.00', '100% - 730% (Calculado desde costo unitario de ~$36)', '[{"cantidad":2,"precio":150},{"cantidad":5,"precio":255},{"cantidad":20,"precio":720}]'::jsonb,
  'Anticuerpos anti-Treponema pallidum', 'sangre_total', '1-2 gotas de sangre (~20-50 µL)', '10 a 15 min.', 99, 99,
  'Detección cualitativa.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS, Registro Sanitario: 1596R2024 SSA',
  'Diagnóstico Inicial (Tamizaje Treponémico Permanente) / Control Prenatal', 'Detectar de forma directa anticuerpos específicos generados contra la bacteria *Treponema pallidum*. Identifica infecciones tanto agudas en estado de chancro (sífilis primaria/secundaria) como sífilis latente asintomática, y perdura reactiva toda la vida tras el contagio.', ARRAY['Ginecología y Obstetricia', 'Medicina General', 'Urología', 'Infectología'], '- **Control Prenatal / Ginecología:** ¡Obligatorio por NOM! Embarazada en primer y tercer trimestre requiere tamizaje inmediato para prevención de sífilis congénita (ceguera, malformaciones del feto). Hágala al instante y brinde Penicilina Benzatinica si cursa reactiva activa.
  - **Urología / ITS:** Paciente masculino de 30 años se presenta con úlcera en glande o erupción maculopapular en palmas de las manos. Permite al urólogo brindar el tratamiento inmediato en la misma visita.',
  'Mujeres en control de embarazo (rutina), personas sexualmente activas con prácticas de riesgo, individuos con llagas genitales indoloras (chancro).', 'Anual en poblaciones en riesgo o 1 a 2 veces durante el embarazo.', 'Por ser una prueba "Treponémica", los anticuerpos permancen positivos por el resto de la vida del paciente incluso tras una cura exitosa con penicilina ("cicatriz serológica"). Un positivo crónico no siempre indica infección activa de riesgo requerida tratar.', 'Si el paciente nunca recibió tratamiento, administrar Penicilina Benzatínica y realizar una prueba No-Treponémica (VDRL cuantitativo) en laboratorio para establecer el grado de actividad o titulación.', 'Tranquilidad, indica la ausencia de contacto infeccioso con sífilis de un lapso de 3 a 6 semanas retrospectivas.',
  'El escudo fundamental para las clínicas ginecológicas y urológicas para blindar a las madres y silenciar la infección silente de las llagas genitales en un test de 10 minutos.', 'Tamizaje de sífilis a $35 de costo con >99% de sensibilidad. Margen del 400-900%. Obligatoria en prenatal. Si no la ofreces, la están mandando a otro lado.', 'Es drásticamente económica, de flujo ultrarrápido por pinchazo en dedo e impide el "patient drop-out" donde el paciente asintomático no va al laboratorio tras recibir la orden por pudor, bloqueando focos de contagio.', 'Margen significativo debido a un ticket bajísimo de entrada de 36 pesos en caja clínica. Empaquetable como "Check-up Prenatal Exprés" a un alto costo percibido.', 'Sífilis es tamizaje obligatorio en control prenatal (NOM-007). Si los ginecólogos de tu zona mandan a referencia, estás perdiendo ese volumen. A $35 de costo y $200-$350 de cobro, el margen es enorme. Además, la sífilis está en rebrote en México — la demanda crece.',
  '[{"pregunta":"¿Diferencia de una Sífilis curada de una activa?","respuesta":"No, esta detecta la cicatriz y la actividad perpetuamente (Treponémica). El protocolo clínico dicta usarla como tamizaje altamente sensible; si sale positiva, usted ya dirige certeramente al laboratorio solo por una titulación VDRL. Pone la criba perfecta."}]'::jsonb, '[{"pregunta":"Ya hago RPR/VDRL","respuesta":"** RPR/VDRL son no treponémicas (detectan reaginas). Esta es treponémica directa (detecta anticuerpos anti-T. pallidum). Son complementarias: la rápida como tamizaje, tu RPR para seguimiento de títulos post-tratamiento."}]'::jsonb,
  '[{"name":"Prueba Combo VIH/Sífilis:","reason":"La OMS recomienda fuertemente el test dual rápido VIH/Sífilis para screening prenatal (WHO Policy Brief, 2023). La úlcera sifilítica abierta incrementa 2-5 veces el riesgo de transmisión de VIH. Tamizar ambas en un solo pinchazo es el estándar.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"Prueba rápida de Embarazo hCG (Sangre):","reason":"Si la paciente de control prenatal aún no confirma gestación, el \"Panel Prenatal Express\" = hCG + Sífilis cubre dos obligatorios NOM en una visita.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-embarazo-hcg-sangre/"}]'::jsonb, '[{"name":"Prueba Combo Sífilis + VIH 1&2:","reason":"Migración natural: en lugar de comprar sífilis por separado ($36/prueba), el combo dual ($75/prueba) agrega VIH por un costo incremental mínimo y duplica el valor diagnóstico por consulta.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"}]'::jsonb, ARRAY['Sífilis', 'sífilis congénita', 'VDRL rápido', 'ITS', 'treponema pallidum', 'chancro', 'llaga genital', 'tamizaje embarazo', 'ETS'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
