-- Product: Prueba rápida de VIH 4ta generación (1.2 y p24)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de VIH 4ta generación (1.2 y p24)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-vih-12-p24/', 'Prueba inmunocromatográfica simultánea (Antígeno + Anticuerpo)', 'Amunet',
  250, 115.6, '$300.00 - $500.00', '140% - 330% (Calculado desde costo unitario de ~$115)', '[{"cantidad":2,"precio":250},{"cantidad":5,"precio":578}]'::jsonb,
  'Anticuerpos Inmunoglobulinas contra VIH Tipo 1 y 2 + Antígeno P24 (Proteína temprana retroviral).', 'sangre_total', '1 a 2 gotas de sangre al cassette gemelo.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa dicotómica (Ac e Ag separados en dos tiras/zonas).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Escrutinio Diagnóstico Ultrasensible (4ta Generación)', 'Reducir sustancialmente el "período de ventana" del virus del VIH de 3 meses a tan solo escasos 15 o 30 días post-exposición, detectando al instante no solamente si el cuerpo ya creó defensas (Anticuerpos frente al Tipo 1 o Tipo 2) sino evaluando activamente las propias piezas virales circulantes en sangre temprana (Antígeno de núcleo p24 que no requiere de la fabricación de anticuerpos).', ARRAY['Médicos Internistas', 'Infectólogos', 'Unidades CAPASITS', 'Urgencias', 'Medicina General'], '- **Consultorio ITS / Manejo Post Exposición (PEP):** Un paciente sumamente ansioso acude indicando una relación desprotegida hace un mes y su prueba tradicional sale negativa (3ra Gen es ciega). Ofrezca la 4ta Generación con Antígenos para detectar la replicación aguda del p24.
  - **Urgencias (Pinchazos):** Para evaluar basalmente al personal médico o paciente fuente tras accidentes ocupacionales punzocortantes en áreas hospitalarias.',
  'Adultos sexualmente activos preocupados por exposiciones de riesgo muy recientes (semanas), profesionales de salud con accidentes con agujas, personas en profilaxis PrEP.', 'Ante contacto de sospecha (Repetir a  2, 6 semanas y a los 3 meses para liberación).', 'Ninguna prueba en seco diagnóstica infecciones el mismo fin de semana de la exposición, pero esta ventana es la más agresivamente recortada disponible pre-PCR clínica.', 'Si la línea T de "VIH 1.2" o la "P24" (o ambas) encienden, es un test Presuntivo Positivo. Activar confidencialmente protocolo NOM, aconsejar y enviar sangre del paciente a test confirmatorio molecular o Western Blot/Elisa Avanzado en laboratorios de referencia nacional, e iniciar derivación a infectólogo para Terapia Antirretroviral (TAR) temprana.', 'Aportar inmensa calma al paciente, aconsejar métodos de barrera, y recomendar re-evaluación a los 3 meses si el contacto fue documentado de extremo riesgo.',
  'Bárrales el paso al virus cerrando el agobiante periodo de ventana: Entregue al paciente aterrado certezas en tan solo 2 a 4 semanas post-exposición con detección biológica de cuarta generación.', NULL, 'Las escrupulosas analíticas de ELISA de Cuarta Gen en clínicas CENSIDA toman burocracia. Al realizarlo en su clínica frente a los ojos del paciente mediante tecnología Point-Of-Care, usted entrega alivio psicológico incalculable de manera inmediata y le gana terreno clínico al debilitamiento del CD4.', 'Cobrando un "Escrutinio Serológico Ultrasensible VIH" a 450 pesos usted retiene altos márgenes, un margen digno del mayor avance en Point of Care infectológico de la década.', NULL,
  '[{"pregunta":"¿Cuál es la diferencia con una prueba VIH normal de la cruz roja?","respuesta":"Las pruebas donadas de cruz roja (de 1ra a 3ra gen) únicamente buscan Anticuerpos, lo que significa que el paciente recién contagiado dará \"Negativo Falso\" porque su cuerpo tardará meses en fabricarlos. La 4ta Gen no espera, busca las basuras del propio virus (P24) en fase hiperaguda."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Sífilis:","reason":"Todo protocolo de ITS dicta una visión integral: un contagio no descarta otro. La úlcera sifilítica incrementa transmisión de VIH 2-5x. Tamizar Sífilis junto a VIH es obligatorio (NOM-039).","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-sifilis/"},{"name":"Prueba rápida de Tuberculosis:","reason":"La coinfección TB/VIH es la principal causa de muerte en pacientes con VIH en México y el mundo (OMS). Si VIH es positivo, evaluar TB es clínicamente mandatorio.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/"}]'::jsonb, '[{"name":"Combo VIH/Sífilis:","reason":"Si su clínica tamiza VIH frecuentemente, migre al combo dual: un solo cartucho, un solo pinchazo, dos diagnósticos. Ahorra tiempo al paciente y al médico. La OMS lo recomienda para screening prenatal.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"}]'::jsonb, ARRAY['VIH 4ta generación', 'HIV', 'Antígeno p24', 'periodo de ventana', 'prueba rápida de SIDA', 'tamizaje VIH ultrasensible', 'sida', 'infección aguda de vih', 'post-exposición ITS'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
