  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de VIH 1.2 (3ra generación)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-12-3ra-generacion/', 'Prueba inmunocromatográfica cualitativa serológica', 'Amunet',
  190, 77.2, '$200.00 - $400.00', '110% - 410% (Calculado desde un costo unitario de ~$77)', '[{"cantidad":2,"precio":190},{"cantidad":5,"precio":386}]'::jsonb,
  'Anticuerpos Inmunoglobulinas contra VIH Tipo 1 y 2.', 'sangre_total', '1-2 gotas.', '10 a 15 min.', 99.8, NULL,
  'Detección cualitativa.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Escrutinio Diagnóstico poblacional estándar', 'Detectar si el sistema inmune del portador produjo anticuerpos por un contagio cronológico superior a 3 meses a causa del Virus de Inmunodeficiencia Humana (Tipo 1, pandémico global, y Tipo 2, restrictivo endémico).', ARRAY['Unidades médicas primarias', 'campañas altruistas de Salud Pública', 'Consultorios de paso', 'Salud Ocupacional', 'Medicina General'], '- **Medicina General Integral / Ingreso Laboral:** Para realización rutinaria del protocolo anual de despistaje del paciente general preocupado por su historial clínico a largo plazo en prácticas convencionales.',
  'Adultos sometidos a cirugías preoperatorias, chequeos de salud anual, control poblacional rural.', 'Anual para toda persona sexualmente activa.', 'El "periodo de ventana ciega". No logra detectar infecciones hiper-recientes (aquellas acaecidas de una a seis semanas atrás), por lo que si el paciente expresa una situación accidental de ayer, requiere la paciencia cronológica pertinente.', 'Notificación clínica empática, solicitar Western Blot/Ensayo de ELISA en laborfatorio para ratificar protocolo diagnóstico, asesoramiento terapéutico vital.', 'Notificación con re-confirmación de que el paciente no acudió alarmado por un suceso del último trimestre.',
  'Herramienta esencial del control prenatal universal y preoperatorio, entregando fiabilidad epidemiológica en 15 minutos en un formato económico.', NULL, 'Reduce la incertidumbre del paciente asintomático mediante entrega inmediata, en oposición a una prolongada espera de 3 días para un sobre cerrado de recabar un laboratorio químico.', 'Ticket de entrada bajo (desde ~$77 pesos), ideal para integrarlo virtualmente gratis en consultas completas preoperatorias de $600 pesos, desmarcando el valor de su trato clínico humanizado.', NULL,
  '[{"pregunta":"¿Es de 4ta generación?","respuesta":"Es serología clásica de anticuerpos de 3ra. Su costo-eficacia es excelente cuando se evalúan tamizajes no expuestos ayer en la noche, garantizando excelencia para la población estándar sin mermas de precisión en la ventana crónica."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Sífilis:","reason":"En tamizajes poblacionales o preoperatorios, VIH y Sífilis son las dos ITS crónicas que deben descartarse. Si el presupuesto no alcanza para el combo, ambas por separado suman menos de $115 de costo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-sifilis/"},{"name":"Prueba rápida de Tuberculosis:","reason":"En pacientes VIH+ o con sospecha de inmunosupresión, TB es la coinfección más frecuente y letal.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/"}]'::jsonb, '[{"name":"Prueba VIH 4ta generación (1&2 y p24):","reason":"Si el paciente reporta exposición reciente (<3 meses), la 3ra generación es ciega. Escalar a 4ta Gen detecta antígeno p24 viral directo, acortando la ventana de 3 meses a ~2 semanas.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-vih-12-p24/"},{"name":"Combo VIH/Sífilis:","reason":"Para clínicas con alto volumen, migrar al combo dual reduce piquetes y tiempo. Un solo cartucho por $75 hace ambas pruebas.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"}]'::jsonb, ARRAY['VIH rápido', 'anticuerpos VIH 1 y 2', 'prueba sida económica', 'tamizaje ITS poblacional', 'examen preoperatorio', 'HIV test'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
