  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Combo Pruebas Rápidas de Sífilis + VIH 1.2', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/', 'Prueba inmunocromatográfica "2 en 1"', 'Amunet',
  750, 75, '$300.00 - $550.00', '300% - 630% (Calculado desde costo unitario de ~$75)', '[{"cantidad":10,"precio":750}]'::jsonb,
  'Anticuerpos anti-Treponema pallidum y Anticuerpos anti-VIH (1 y 2)', 'sangre_total', '2 gotas (~50 µL) de muestra + 1 gota (~40 µL) de buffer en cada pozo S distribuidas en los pocillos duales del cassette.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Integral de ITS / Obligato Cíclico en Embarazos', 'Una optimización logística y dolorosa notable: realizar simultáneamente con una sola gota un despistaje de la temida Síndrome de Inmunodeficiencia Adquirida y la Sífilis, dos demonios sistémicos característicos de la infección de transmisión sanguínea-vertical y sexual.', ARRAY['Ginecología (Control prenatal)', 'Urología', 'Infectología', 'Consultas Comunitarias', 'Medicina General Integral'], '- **Ginecología / Control Prenatal:** ¡Doble protección perinatal por un solo piquete! La norma médica obligatoria dicta blindar al feto descartando VIH maternal o Sífilis congénita de inmediato en un control primario. Ofrezca confort a su paciente encinta con el combo instantáneo.
  - **Consultorio ITS Exprés:** Pacientes sexualmente activos con múltiples parejas que solicitan tamizaje integral de ITS. Resultado de ambas pruebas en 10 minutos con una sola toma de muestra.',
  'Gestantes en control prenatal, personas con prácticas de riesgo, pacientes que solicitan panel rutinario de ITS.', 'Base de screening semestral o anual para factores de riesgo.', 'La detección de anticuerpos por Treponema arrastra memoria de infecciones curadas del pasado (Sífilis curada dictará Sífilis positiva en prueba test), y requiere descartar periodo de ventana para VIH.', 'En VIH, corroborar vía Western Blot y escalar a TARVA referida. En Sífilis re-determinar titular VDRL activa (RPR) y clavar Penicilina en urgencia si no contaba historial.', 'Paz completa en el horizonte crónico del paciente.',
  'Tamizaje dual VIH + Sífilis con una sola muestra de sangre capilar por $75 de costo. Ideal para control prenatal obligatorio y consultas de ITS, eliminando la necesidad de dos pruebas separadas.', NULL, 'Comodidad absoluta del usuario ("Patient experience"). Un cartucho estético, doble franja y dictamen conjunto de 15 minutos en escritorio derrochan modernismo preventivo.', 'Extremadamente rentable. El combo "VIH y VDRL" en red de laboratorios frisa los $700-$900 pesos con dolorosas idas venosas en ayuno. Usted realiza un exudado venoso capilar simple y domina la consulta cobrando 400 MXN extras, empoderando el prestigio con creces.', NULL,
  '[{"pregunta":"¿Al ser dos juntas pierde precisión de lectura cruzada?","respuesta":"De ninguna forma. Son dos membranas aisladas e independientes montadas en el mismo plástico amigable del cassette para garantizar esterilidad cruzada química intachable."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Tuberculosis:","reason":"Todo paciente con VIH+ debe tamizarse para TB (OMS). Si el combo detecta VIH, TB es la siguiente evaluación crítica.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/"},{"name":"Prueba rápida de Embarazo hCG (Sangre):","reason":"\"Panel Prenatal Express\" = hCG + Combo VIH/Sífilis = tres resultados esenciales del control prenatal NOM en 15 minutos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-embarazo-hcg-sangre/"}]'::jsonb, '[{"name":"Prueba VIH 4ta generación (1&2 y p24):","reason":"Si un paciente con exposición reciente (<3 meses) necesita VIH con detección temprana + Sífilis, use el combo para Sífilis y complemente con la 4ta Gen para cubrir la ventana aguda de VIH.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-vih-12-p24/"}]'::jsonb, ARRAY['Combo ITS', 'doble prueba VIH sífilis', 'panel rápido VDRL', 'ETS integradas', 'tamizaje prenatal rápido', 'co inefcción ITS', 'prueba duo'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
