  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Mononucleosis (Enfermedad del Beso)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-mononeuclosis/', 'Prueba inmunocromatográfica cualitativa', 'Amunet',
  350, 55, '$250.00 - $400.00', '250% - 620% (Calculado desde un costo unitario de ~$55)', '[{"cantidad":5,"precio":350},{"cantidad":20,"precio":1100}]'::jsonb,
  'Anticuerpos heterófilos (IgM) asociados a Mononucleosis infecciosa (IM / Virus Epstein-Barr)', 'sangre_total', '1-2 gotas', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa dicotómica (Presencial positivo / negativo).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Agudo Rápido y Diferencial', 'Discriminar si una faringoamigdalitis severa con adenopatías y fiebre arrastrada corresponde al Virus de Epstein-Barr (Mononucleosis) evitando la prescripción innecesaria de antibióticos (Amoxicilina) frente a un patógeno viral.', ARRAY['Pediatría', 'Medicina Familiar', 'Medicina General', 'Infectología', 'Otorrinolaringología'], '- **Pediatría y Medicina Juvenil:** ¡Corte la prescripción empírica de Amoxicilina! Paciente adolescente (13-20 años) reporta 5 días de dolor de garganta intenso, ganglios gigantes y fiebre. Mídanle en la misma consulta: si el Test resulta positivo es el clásico "Beso", advierta reposo absoluto, hidratación y evite el exantema maculopapular que ocurre al administrar aminopenicilinas a un paciente con mononucleosis.',
  'Adolescentes, universitarios, adultos jóvenes con cuadro de fatiga extrema y placas pus en amígdalas que mimetizan una bacteria estreptocócica.', 'Ante evento inflamatorio adeno-faringeo sospechoso.', 'Al detectar anticuerpos tipo "IgM" (frescos), pacientes infantes menores (pre-escolares) podrían desarrollar heterófilos a niveles más indetectables que en los adolescentes adultos, derivando en algunos falsos negativos del lactante.', 'Abortar uso antibiótico, instaurar reposo absoluto (prohibir deportes de contacto debido a la esplenomegalia — riesgo de rotura esplénica) y manejo sintomático con analgésicos.', 'Si en verdad las placas faríngeas gritan una infección bacteriana severa, virar a prescribir antibiótico certero (Evaluar Estreptococo A).',
  'Detecte mononucleosis infecciosa (Epstein-Barr) en 10 minutos en pacientes febriles para evitar el uso innecesario de antibióticos que puedan desencadenar exantema y ruptura esplénica por mala praxis médica en adolescentes.', NULL, 'Enviar monospot/IgM EBV al laboratorio central tarda tres días caros y los padres buscan resolución inmediata. Resolver la etiología del cuadro agudo en consultorio aporta valor diagnóstico diferencial en la primera consulta.', 'Costo de inversión bajo ($55-$70 por prueba) con precio sugerido de $250-$350, generando un margen significativo y alto valor percibido por la familia.', NULL,
  '[{"pregunta":"¿Se confunde con Estreptococo?","respuesta":"El cuadro de placas faríngeas puede confundir visualmente entre etiología bacteriana y viral. La recomendación es mantener ambas pruebas disponibles (Mononucleosis en sangre + Strep A en hisopo) para diagnóstico diferencial por contraste."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Estreptococo A (Hisopo):","reason":"El diagnóstico diferencial obligado de toda faringitis aguda. Faringitis severa = ¿Estreptococo bacteriano (requiere penicilina urgente, previene fiebre reumática) o Virus Epstein-Barr/Mononucleosis (reposo, prohibido aminopenicilinas)? Ambas pruebas juntas = \"Panel Diferencial de Faringitis\".","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-estreptococo-a/"},{"name":"Prueba rápida de IgE:","reason":"En pacientes con faringitis recurrente + rinitis, IgE descarta componente alérgico subyacente. La rinitis alérgica crónica puede mimetizar y agravar cuadros infecciosos faríngeos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ige/"}]'::jsonb, '[{"name":"Prueba TORCH IgG/IgM:","reason":"Ampliar faringitis + linfadenopatía en adolescentes/embarazadas con TORCH para descartar toxoplasmosis, rubéola, CMV y herpes. \"Panel Linfadenopatía\" = Mono + TORCH.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-torch-igg-e-igm/"}]'::jsonb, ARRAY['Enfermedad del beso', 'Epstein Barr', 'EBV virus', 'fatiga crónica dolor de garganta', 'placas pus adolescent', 'monospot rapida', 'lgM mononucleosis'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
