-- Product: Prueba rápida de Estreptococo Grupo A
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Estreptococo Grupo A', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-estreptococo-a/', 'Prueba inmunocromatográfica de Hisopo', 'Amunet',
  450, 85, '$200.00 - $350.00', '120% - 310% (Calculado desde un costo unitario de ~$85)', '[{"cantidad":5,"precio":450},{"cantidad":20,"precio":1700}]'::jsonb,
  'Antígenos directos del esqueleto capsular de Streptococcus pyogenes (Estreptococo beta-hemolítico del Grupo A).', 'hisopo_orofaringeo', 'Hisopo vigoroso sobre amígdalas y faringe posterior, luego rotado en el buffer de extracción incluido.', 'Rápido; en un umbral promedio de 5 a 10 min.', NULL, NULL,
  'Detección cualitativa binaria.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Confirmatorio Rápido Etiológico', 'Diferenciar si una faringoamigdalitis o faringitis aguda exudativa se debe a infección bacteriana por S. pyogenes o a un agente vírico, orientando la decisión de prescripción antibiótica. Un resultado positivo confirma etiología bacteriana y justifica el inicio oportuno de antibioticoterapia (penicilina/amoxicilina) para prevenir complicaciones como fiebre reumática aguda y cardiopatía reumática.', ARRAY['Otorrinolaringólogos', 'Pediatría', 'Medicina Familiar de Urgencias (Farmacias Anexas con médicos de cabecera)', 'Medicina General en invierno'], '- **Pediatra en Pleno Invierno:** ¡Salón del kínder entero con amigdalitis! Reciba al infante con fiebre alta repentina de 39°C. No adivine ante gargantas enrojecidas. Haga el raspado, obtenga el cassette rosa en 10 min frente a sus padres, y decida si libera receta de amoxicilina/penicilina con soporte clínico, asegurando cero secuelas cardiológicas en la niñez.',
  'Pediátrico predominantemente (5-15 años, entorno escolar), o adultos con odinofagia severa sin síntomas nasales, fiebre alta y adenopatía cervical.', 'Episodio agudo dolor amigdalar.', 'No detecta otros portadores de bacterias menos relevantes (estreptoco C o G o D). Una toma inadecuada del hisopo (superficial o sin contacto amigdalar) puede resultar en falsos negativos por insuficiencia de muestra bacteriana.', 'Prescribir penicilina V o amoxicilina por 10 días completos según guías clínicas para erradicación del S. pyogenes.', 'Si la sospecha clínica es alta a pesar del resultado negativo, referir a cultivo faríngeo (36-48 hrs). En ausencia de confirmación bacteriana, manejar como cuadro viral con analgésicos y evitar prescripción antibiótica innecesaria.',
  'Confirme en 5 minutos si la faringoamigdalitis febril es bacteriana (S. pyogenes) y requiere antibiótico, o viral y debe manejarse sintomáticamente.', NULL, 'El cultivo faríngeo tarda 2-4 días, forzando prescripciones empíricas. Esta prueba rápida permite decidir antibioticoterapia en el momento, documentando el resultado frente al paciente y contribuyendo al uso racional de antibióticos.', 'Alto factor volumen-retención. Se gasta $85 pesos de un producto y es una de las pruebas más solicitadas en consultorios pediátricos cobrándola como prueba confirmatoria en $300 pesos más.', NULL,
  '[{"pregunta":"¿Cómo lidio a un falso negativo?","respuesta":"Asegurar un hisopado firme sobre los pilares amigdalinos, tocando depósitos de exudado o placas para obtener muestra representativa."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Mononucleosis:","reason":"Diagnóstico diferencial obligado. Amigdalitis con adenopatía en adolescentes puede ser Strepto A (requiere penicilina) o EBV (reposo, prohibir aminopenicilinas). Ambas pruebas juntas = \"Panel Diferencial Completo de Faringitis\".","url":"https://www.amunet.com.mx/tienda/prueba-rapida-mononeuclosis/"},{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"En temporada invernal, si Strep A sale negativo, el siguiente paso es descartar virus respiratorios con un solo hisopado nasofaríngeo.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, '[{"name":"COMBO RESPIRATORIO MAX (Flu A/B + COVID + RSV):","reason":"Si su consultorio pediátrico maneja alto volumen invernal, el panel triple (influenza + COVID + VSR) con un solo hisopo es la herramienta definitiva.","url":"https://www.amunet.com.mx/tienda/combo-respiratorio-max-influenza-a-b-sars-cov-2-rsv/"}]'::jsonb, ARRAY['Estreptococo a', 'pyogenes faringe', 'amígdalas placas', 'hisopo de garganta rapido', 'prueba angina infecciosa bacteriana', 'escarlatina', 'fiebre reumática prevencion', 'estreptest'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
