-- Product: Prueba Rápida DENGUE NET (Ag NS1 + IgG/IgM)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba Rápida DENGUE NET (Ag NS1 + IgG/IgM)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-para-dengue/', 'Prueba de escrutinio inmunocromatográfica COMBINADA de Flujo Lateral', 'Amunet',
  498, 87, '$300.00 - $500.00', '200% - 470% (Calculado desde un costo unitario de ~$87)', '[{"cantidad":5,"precio":498},{"cantidad":20,"precio":1740}]'::jsonb,
  'Antígeno de pico vírico de Dengue (Proteína temprana *NS1*) y Anticuerpos tardíos anti-Dengue (Immunoglobulinas G o M de fase de restauración).', 'sangre_total', '1-2 gotas goteado a pozos múltiples duales.', '15 min. (Lectores de ventana simultánea).', NULL, NULL,
  'Detección Presencial cualitativo. Separada zona NS1 ag y zona Ab.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , 1003 R2024 SSA',
  'Diagnóstico Activo de todo Espectro (Triage de urgencia en zonas Tropicales Costeras).', 'Detección simultánea del antígeno NS1 y anticuerpos IgG/IgM para cubrir todas las etapas de la infección por Dengue (4 serotipos). El antígeno NS1 es detectable desde las primeras 24 horas post-infección (fase febril aguda, días 1-6), mientras que los anticuerpos IgG/IgM captan pacientes en fase tardía (>6 días) con respuesta inmune establecida y posibles complicaciones hemorrágicas.', ARRAY['Medicina de Urgencias', 'Paramédicos/Triage', 'Unidades Salud de primer nivel (Campesina/Suburbano)', 'Infectología'], '- **Urgencias de Zonas Tropicales:** Paciente con vómito, cefalea periorbitaria, fiebre alta y mialgia intensa. No recuerda picaduras. La prueba NS1 positiva indica viremia activa: proceder a aislamiento, hidratación intravenosa y vigilancia estrecha para prevenir progresión a dengue hemorrágico.',
  'Adultos / Jóvenes y pediátricos en áreas endémicas sur o portadores viajeros de las regiones endémicas con fiebres incapacitadoras en menos de una a 2 semanas.', 'Episodio agudo u observación control tras fiebres endémicas incesantes (Brote de vectores Dengue activo en temporada pluvial del charco).', 'Puede haber una sutil y muy poco predominada falsa reacción del flavivirus (Zika, Chikungunya o Fiebre Amarilla de vacunas), a ser en extremo riguroso en clínica, no distingue al Serotipo específico 1 al 4 numérico solo confirma "Dengue Flavivirus" generál.', 'Si NS1 (Brote vivo Activo), hidratación intravenosa intensa en cuadro agudo (riesgo de extravasación y hemorragia). AINEs (incluyendo ibuprofeno y aspirina) estrictamente contraindicados por riesgo hemorrágico. Manejo antipirético exclusivo con paracetamol.', 'Proceder triage a otros brotes febriles parecidos con el protocolo de urgencia para Chikungunya o ZIKV vírica local.',
  'Detecte tempranamente (con NS1) al dengue el día 1 que quiebra huesos, o capte su recuperación tardía oculta (IGG/IGM) al mismo tiempo con 2 pruebas gemelas integradas combatiendo la peor plaga estacional de lluvias al instante de su consultorio.', NULL, 'En un cuadro grave de Dengue con riesgo de extravasación y hemorragia, el PCR-RT tarda 48 horas y la biometría plaquetaria requiere laboratorio. Esta prueba permite decidir hospitalización inmediata frente a la cama del paciente.', 'Margen significativo en zonas endémicas. Los perfiles de Dengue en laboratorio se cotizan en ~$800. Con un costo de $87, ofrecer un "Check-Dengue Express" a ~$400 genera un margen atractivo con alto volumen en temporada de lluvias.', NULL,
  '[{"pregunta":"¿Por qué llevaría el Dengue completo y no el barato IgM?","respuesta":"El barato IgM le falla a usted en atrapar al enfermo del \"Día Dos\" porque el paciente aun NO elabora sus IGM; para esa gran ventana ciega existe el brillante descubrimiento de esta caja en usar la bioproteina víral circulante inicial NS1 Antigen, no pierden un cazo si llevan este cartucho doble con NS1 en guardia tropicales de turismo."}]'::jsonb, '[]'::jsonb,
  '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Diagnóstico diferencial de fiebres en zonas endémicas: Dengue (mosquito), COVID (respiratorio) e Influenza pueden coexistir en la misma temporada. Si NS1 es negativo, descartar virus respiratorios.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, '[{"name":"Prueba rápida de Dímero D:","reason":"Dengue hemorrágico puede causar coagulación intravascular diseminada (CID). Si el paciente tiene Dengue positivo con signos de alarma (sangrado, petequias), el Dímero D evalúa coagulopatía de consumo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"}]'::jsonb, ARRAY['Dengue', 'rompehuesos rápido test', 'moscos aedes', 'antígeno fiebre tropical NS1 Dengue', 'Dengue IgM IgG', 'tamizaje costa mosquitos fiebre', 'detecta Dengue dia uno agudo', 'diferencial chikungunya sintomatologia'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
