  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba Rápida DENGUE IgG - IgM (Solo Anticuerpos Serológicos)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-dengue-igg-e-igm/', 'Prueba Inmunocromatográfica Serológica cualitativa lateral.', 'Amunet',
  342, 63, '$250.00 - $400.00', '260% - 530% (Calculado desde un costo unitario de ~$63)', '[{"cantidad":5,"precio":342},{"cantidad":20,"precio":1260}]'::jsonb,
  'Anticuerpos IgM (infección aguda/reciente) e IgG (infección previa/memoria inmune) anti-Dengue.', 'sangre_total', '1-2 gotas de sangre.', '10-15 minutos.', NULL, NULL,
  'Detección cualitativa con bandas separadas (IgM: infección reciente/activa; IgG: infección previa o reinfección).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMDEN02.',
  'Diagnóstico Confirmatorio Retrospectivo/Tardío.', 'Prueba económica para confirmar exposición a Dengue en pacientes con cuadro febril prolongado (>7 días post-infección). Detecta la respuesta inmune tardía (IgM para infección reciente, IgG para infección previa), útil cuando el antígeno NS1 ya no es detectable.', ARRAY['Centros Comunitarios Rurales (Secretaría o similares)', 'Farmacias adjuntas populares de Tránsito', 'Pediatría suburbana'], '- **Consultorio Local y Seguimiento Social:** En contexto de brote epidémico, tamizar pacientes con cuadro febril prolongado (>7 días) con artralgias y malestar general. La presencia de IgM confirma infección reciente por Dengue; IgG indica exposición previa. Orientar reposo, hidratación y vigilancia de complicaciones post-infecciosas.',
  'Adultos que regresan de zonas endémicas con cuadro febril prolongado, artralgias persistentes y fatiga post-infecciosa.', 'Ante evento prolongado (convalecencia).', 'No detecta la proteína de brote temprano (Día Primero Fiebriño al Cuarto), por lo que sí está asediado el mosco ayer fallará (falsos negativos iniciales por ausencia de inmunidad creada que pide tiempo).', 'IgM positiva = infección reciente o activa. Prescribir reposo, paracetamol (evitar AINEs) y vigilancia de plaquetas y signos de alarma. IgG positiva sola = infección previa; en contexto de reinfección, vigilar riesgo de dengue severo.', 'Descartar otras causas de fiebre: Zika, Chikungunya, leptospirosis, o virosis sistémicas (CMV, EBV).',
  'Confirme de forma rápida y económica si el paciente tiene anticuerpos de Dengue en zonas endémicas, orientando al grueso de pacientes que el dengue ya los asedia en su recuperación a menos de un dolar costo unitario.', NULL, 'En el pueblo, pagar un ELISA de Dengue es una fantasía. Con un costo unitario de $63 y precio sugerido de $300, esta prueba permite confirmar Dengue y orientar el manejo sintomático en consultorios de zonas endémicas con alto volumen de pacientes febriles.', 'Margen significativo por volumen (Margen rentista superior constante). Se justifica para abaratar la medicina privada solidaria popular del país.', NULL,
  '[{"pregunta":"¿Me queja el paciente que lo picaron ayer y dio negativo?","respuesta":"Correcto, esta versión es exclusivamente si requiere anticuerpos creados del cuerpo tardío. Para atraparlo de un día de incubado, usted debía de haber escalado el nivel y usar un modelo Combo NS1 el cual tenemos."}]'::jsonb, '[]'::jsonb,
  '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Diagnóstico diferencial de fiebres en zonas costeras: Dengue, COVID e Influenza pueden coexistir en la misma temporada. Si IgG/IgM Dengue es negativo, descartar virus respiratorios.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, '[{"name":"Prueba Rápida DENGUE NET (NS1 + IgG/IgM):","reason":"Escalamiento natural. La versión con NS1 detecta virus activo desde el día 1 de fiebre, mientras esta solo detecta anticuerpos del día 5+. Para no depender de cuántos días lleva enfermo el paciente, migre al combo NS1.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-para-dengue/"}]'::jsonb, ARRAY['Anticuerpos dengue', 'Dengue convaleciente rapida', 'Dengue IgG / lgM economico', 'diagnostico viral mosco postvacacional', 'fiebre rural escrutinio tropical'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
