  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antígeno SARS-CoV-2 (Nasofaríngea)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-sars-cov-2/', 'Prueba inmunológica cualitativa (Flujo Lateral)', 'Amunet',
  200, 70, '$250.00 - $400.00', '150% - 470% (Calculado desde un costo unitario de ~$70 a ~$100)', '[{"cantidad":2,"precio":200},{"cantidad":5,"precio":425},{"cantidad":10,"precio":700}]'::jsonb,
  'Partículas virales de la proteína N (Nucleocápside) del SARS-CoV-2.', 'Muestra nasofaríngea (hisopo).', 'Un hisopado profundo embebido en el buffer de lisis incluido.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa de antígeno de Nucleocápside del SARS-CoV-2.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Agudo Rápido / Tamizaje', 'Confirmar o descartar en minutos la presencia activa del virus causante del COVID-19 mediante la captura del antígeno nucleocápside directamente desde la faringe posterior, identificando individuos infecciosos que propagan la enfermedad independientemente de sus síntomas.', ARRAY['Medicina General', 'Urgencias', 'Salud Ocupacional', 'Pediatría', 'Medicina Interna'], '- **Consultorio General / Triage:** Paciente arriba con tos seca, cefalea intensa y anosmia (pérdida de olfato) tras una reunión social hace 4 días. Realice un hisopado inmediato para aislar al portador antes de que contamine la sala de espera, sin aguardar las costosas 48 horas de un PCR asfixiando el rastreo de contactos.
  - **Filtro de Salud Ocupacional:** Una constructora o maquiladora necesita tamizar operarios con "gripa" antes de que ingresen al galpón y paren la producción completa por brote pandémico.',
  'Adultos o pediátricos con cuadro respiratorio sospechoso, o contactos de un positivo conocido con 3 a 7 días de exposición aguda.', 'Ante indicio febril respiratorio / Triage pandémico.', 'Si se toma con mala técnica (raspado nasal superficial en lugar de faringe profunda), o si el paciente se encuentra en el día 15 de infección (donde el virus ya no está en faringe sino en pulmones profundos), el cartucho arrojará Falso Negativo por falta de proteínas Muestra.', 'El paciente cursa con una replicación viral masiva. Aislamiento inmediato, control de oxigenometría estricta, y monitorización estrecha de tormenta de citoquinas en días posteriores.', 'Si los síntomas son altamente sugestivos de COVID, y está saturando bajo, aislar precautoriamente y referir a prueba molecular (PCR) o TAC pulmonar ya que el virus puede haber descendido a tracto inferior. Alternativamente preescribir manejo para otras IRAs (Influenza).',
  'Diagnostique SARS-CoV-2 en su consultorio con hisopado nasofaríngeo, obteniendo resultados en 15 minutos a un costo de menos de $100 por prueba.', NULL, 'En la urgencia de reincorporación laboral o vuelo aeroportuario, el PCR asfixia logística y financieramente. Brinde resultados inmediatos respaldados por tecnología de anticuerpos monoclonales, generando confianza tanto para el paciente como para trámites laborales.', 'Costo unitario de ~$70 pesos con precio sugerido de $250-$400. Margen de 250%-470% por aplicación. Alto volumen en temporada invernal.', NULL,
  '[{"pregunta":"¿El cartucho detecta las nuevas variantes Delta/Omicron/Kraken?","respuesta":"Sí, puesto que el reactivo reconoce a la Proteína Nucleocápside (N) estructural básica interna y no la proteina Pico (Espiga/Spike) que es la que sufre incontables mutaciones con cada cepa evasiva."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"COVID severo = tormenta de citoquinas con hiperferritinemia. Si el paciente COVID+ empeora al día 6-8, Ferritina elevada predice necesidad de esteroides y hospitalización.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"},{"name":"Prueba rápida de Dímero D:","reason":"COVID + disnea súbita = riesgo de trombosis pulmonar. Dímero D evalúa coagulopatía de consumo que complica el cuadro viral.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"}]'::jsonb, '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Un solo hisopado, 3 resultados. Evita prescripciones empíricas adivinando si es Influenza o COVID.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, ARRAY['Prueba COVID hisopo', 'antígeno rápida sars cov 2', 'coronavirus nariz profundidad', 'test ag covinet', 'test laboral covid', 'prueba covid económica', 'hisopado nasofaríngeo'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
