INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antígeno SARS-CoV-2 (Saliva)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-en-saliva-sars-cov2/', 'Prueba inmunológica cualitativa (No Invasiva)', 'Amunet',
  188, 64, '$250.00 - $400.00', '160% - 525% (Calculado desde un costo unitario de ~$64 a ~$94)', '[{"cantidad":2,"precio":188},{"cantidad":5,"precio":395},{"cantidad":10,"precio":640}]'::jsonb,
  'Partículas virales de la proteína N del SARS-CoV-2 presentes en glándulas salivales.', 'saliva', 'Suficiente para empapar depósito de reacción.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Agudo Rápido (No Invasivo)', 'Proveer un diagnóstico análogo al hisopo nasofaríngeo confirmando la presencia viral respiratoria del SARS-CoV-2 explotando el reservorio epitelial salival, ideal para escrutinios sin llanto ni traumas.', ARRAY['Pediatría', 'Odontología (Tamizaje pre-dental)', 'Escuelas (Enfermería)', 'Medicina General'], '- **Pediatría / Cuarto de Urgencias Infante:** Madre desesperada llega con su hijo de 4 años envuelto en perretas febriles de Covid. Nadie logra sujetar la cabeza para el doloroso hisopo en nariz. Se utiliza esta prueba ofreciendo una esponjillas a masticar/gotas lúdicas, dando un resultado pacífico, amable y certero sin destruir el lazo paciente-médico pediátrico por el dolor de un raspado.
  - **Tamizaje Geriátrico:** Ancianos o adultos con anatomía nasal desviada u oscura hemofilia donde perforar el moco representa un peligro epistáxico.',
  'Niños renuentes al dolor, adultos neurodivergentes o ansiosos, ancianos.', 'Ante indicio febril respiratorio / Requerimientos de aislamiento en colegios.', 'Abstenerse beber agua, fumar o cepillarse los dientes 30 min previos al escupitajo anula resultados si se lava la carga viral bucal.', 'El paciente cursa con una replicación viral masiva. Aislamiento estricto de la burbuja familiar pediátrica.', 'Control clínico de temperatura, re-evaluar si fiebre o tos asciende notablemente.',
  'Evite la incomodidad de los hisopos nasofaríngeos ofreciendo una detección indolora, precisa y pacífica del COVID-19 por medios de la saliva para niños, colegios y pacientes ansiosos.', NULL, 'La saliva como muestra ofrece una experiencia no invasiva, especialmente valorada en pediatría. Muchas familias priorizan la comodidad del niño, y una alternativa indolora al hisopo nasal agrega valor diferencial a la consulta.', 'Costo unitario de ~$64 pesos. Al ofrecer la alternativa no invasiva (saliva vs hisopo nasal), la percepción de valor por parte del paciente aumenta significativamente.', NULL,
  '[{"pregunta":"¿Es menos precisa que la del tubo por nariz?","respuesta":"Estudios clínicos han demostrado que la carga viral en saliva es comparable a la del hisopo nasofaríngeo durante la fase aguda de contagio (primeros 5-7 días), lo que respalda su uso como muestra alternativa."}]'::jsonb, '[]'::jsonb,
  '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Si Saliva COVID+ pero persiste la duda de Influenza, complementar con el panel nasofaríngeo dual para diagnóstico diferencial completo.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"},{"name":"Prueba Rápida DENGUE NET:","reason":"En zonas endémicas costeras, una fiebre pediátrica puede ser Dengue, COVID o ambos. Si Saliva COVID resulta negativa, evaluar Dengue.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-para-dengue/"}]'::jsonb, '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID nasofaríngea):","reason":"Diferencia COVID vs Influenza con un solo hisopado. Ofrezca saliva como alternativa no invasiva y el combo nasal como \"panel diferencial premium\".","url":"https://www.amunet.com.mx/tienda/pruebas-rapidas-de-influenza-a-y-b-antigeno-para-sars-cov2-nasofaringea/"}]'::jsonb, ARRAY['Covid escupir rápido', 'prueba antígeno en saliva', 'no dolorosa covid niños', 'prueba paleta saliva sars cov 2', 'pre-operatorio infantil covid', 'tamizaje escolar no invasivo', 'alternativa hisopo nasal'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
