-- Product: Prueba Rápida COVID-19 Anticuerpos IgG/IgM
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba Rápida COVID-19 Anticuerpos IgG/IgM', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-para-covid19-presencia-de-anticuerpos-igg-e-igm/', 'Prueba Inmunocromatográfica Cualitativa (Sangre)', 'Amunet',
  410, 74, '$250.00 - $400.00', '200% - 440% (Calculado desde un costo unitario de ~$74)', '[{"cantidad":5,"precio":410},{"cantidad":10,"precio":740}]'::jsonb,
  'Anticuerpos defensivos Inmunoglobulina G (Tardía/Crónica) e Inmunoglobulina M (Reactiva Aguda) contra proteínas N y S del SARS-CoV-2.', 'sangre_total', '1-2 gotas goteado a pozos múltiples duales de reacción sérica.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa (bandas separadas para IgM e IgG).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Confirmatorio Retrospectivo / Historial Inmunológico', 'Ser el faro revelador frente a un paciente que sufrió una "gripota que lo tiró a la cama" la semana pasada o el mes pasado, revelando permanentemente si su sistema inmunológico armó una defensa de tipo Aguda (M) contra un ataque activo de COVID o si retiene una sólida memoria cicatrizante de una batalla vencida (IgG).', ARRAY['Medicina Laboral (Campañas de regreso al trabajo masivo)', 'Unidades Check-up', 'Infectología'], '- **Medicina Laboral y Contratación:** Recursos Humanos pide a los operarios saber si un brote general en un ala de fábrica ya creó memoria de rebaño. Pinchar dedo por sangre para IgG arroja si ya se pueden levantar cuarentenas porque el empleado superó asintomáticamente una ola previa.
  - **Paciente Aterrado Curado:** Consulta privada "Hace veinte días no podía respirar y tosía sin parar, doctor, cree que fue el infame Coronavirus y ya creé defensas?". Un hisopo ya no sirve en su día 20 porque no hay virus narigudo de antígeno; esta prueba serológica es la ÚNICA que mira el rastro químico (IgG/IgM) para brindarle paz crónica y ratificar el evento.',
  'Adultos convalecientes, escrutinios médicos ejecutivos o asintomáticos interesados por su historial epidemiológico inmune.', 'Ante sospechas post-cuadro séptico.', 'Catastrófica su venta para diagnosticar "infección aguda del Día 1"; los anticuerpos le toman al humano entre 7 a 15 días en existir formados; arroja Cero si se aplica bajo fiebre de incubación aguda (Se debe usar Antígenos Nasales/Saliva en ese frente primario vital).', 'Si Banda M sube a roja, paciente se cura aún de la estela aguda post-COVID infecciosa y con secuelas inflamatorias. Si Banda G aparece brillante rojo, el paciente logró una "alta biológica defensiva antigua".', 'Ese resfriado pesado que los tiró no fue el patógeno SARS o el paciente es extremadamente inmunodeprimido en humoral.',
  'Confirme exposición previa a SARS-CoV-2 y estado inmunológico (IgM aguda / IgG memoria) con sangre capilar en 15 minutos, ideal para medicina laboral y seguimiento post-infección.', NULL, 'Un perfil de inmunoglobulinas en laboratorio externo puede costar $500+ y tardar días. Con esta prueba de $74 pesos se obtiene un resultado serológico orientador en 15 minutos, útil para certificados de alta laboral.', 'Costo unitario de ~$74 pesos. Útil como componente de paquetes de vigilancia epidemiológica o certificados de alta laboral post-COVID.', NULL,
  '[{"pregunta":"¿Me queja el paciente que lo contagió y le picó y dio negativo?","respuesta":"Correcto, recuérdenles la cátedra médica en biología, sus células defensivas toman una quincena en nacer; un negativo en sangre agudo no lo salva de estar infectado, lo derivamos hoy a hisopado nasal Antigénico para atinar a corto plano infectivo."}]'::jsonb, '[]'::jsonb,
  '[{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Si los IgG/IgM son negativos pero el paciente tiene síntomas respiratorios activos, descartar infección aguda con antígenos nasofaríngeos de Flu + COVID.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, '[{"name":"Prueba rápida de Dímero D:","reason":"COVID severo/post-COVID = riesgo elevado de trombosis venosa. \"Protocolo Post-COVID\" (anticuerpos + Dímero D) para detectar complicaciones trombóticas.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"}]'::jsonb, ARRAY['Anticuerpos rápidos covid', 'IgG e IgM sars cov 2', 'inmunidad prueba rápida de resfriado', 'tamizaje retrospectivo coronavirus defensas', 'anticuerpos sangre covid'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
