-- Product: COMBO COVFLU-NET: Influenza A, Influenza B y SARS-CoV-2
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'COMBO COVFLU-NET: Influenza A, Influenza B y SARS-CoV-2', 'infecciosas', 'https://www.amunet.com.mx/tienda/pruebas-rapidas-de-influenza-a-y-b-antigeno-para-sars-cov2-nasofaringea/', 'Prueba Inmunocromatográfica Combo Nasofaríngea', 'Amunet',
  1780, 178, '$450.00 - $700.00', '150% - 290% (Calculado desde un costo unitario de ~$178)', '[{"cantidad":10,"precio":1780}]'::jsonb,
  'Antígenos Nucleocápside virales independientes: Subclados (H1N1/H3N2) tipo A y cepas tipo B de la Gripe, y la proteina N de SDCov-2 (Covid-19).', 'Muestra unificada nasofaríngea (hisopo).', 'Un hisopado nasofaringeo procesado en buffer y goteado en los pozos de reacción A/B y COV.', 'Rápido; en un umbral promedio simultáneo de 15 min.', NULL, NULL,
  'Detección cualitativa diferencial (bandas separadas para Flu A, Flu B y SARS-CoV-2).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Diferencial Respiratorio Estacional', 'Resolver el diagnóstico diferencial respiratorio que frecuentemente se complica frente a dos sintomatologías clónicas entre sí: La Flu severa y un encarnizado Covid19. De un solo tortuoso hisopo un clínico dilucida el rumbo certero de la pandemia.', ARRAY['Medicina Interna', 'Neumología', 'Unidades Cuidados Críticos', 'Urgencias', 'Medicina General de Hospitales de 1er nivel'], '- **Urgencias en Picos Invernales (Diciembre):** Servicio de urgencias con alta demanda de pacientes con síntomas respiratorios: tos, disnea, artralgias y fiebre >39°C. La vacunación no descarta portación activa. Con un solo rasgado nasofaríngeo dictamine camas apartadas rojas de Covid de alas de aislamiento en Flu A para que no hagan mezclas víricas mortales unificando el pasillo en incubadora.',
  'Adulto mayor o diabético con disnea de inicio súbito, que requiere diferenciación para decidir entre oseltamivir (Influenza) o manejo de soporte (COVID).', 'Episodio agudo grave estacional.', 'Ventanas temporales similares a la cepa singular de Ag (falsos por mala técnica o ventana muy muy rezagada alveolar neumónica donde el hisopo alto no raspa flora traqueal).', 'Aislar al paciente. Influenza A positiva: iniciar oseltamivir dentro de las primeras 48 horas. COVID positivo: manejo según gravedad (ambulatorio o soporte con esteroides si hay compromiso neumónico).', 'Resfriado común (Rinovirus), Adenovirus vírico transitorio normal u otro virus sinestésico (VRS en niños). Orienta el manejo ambulatorio.',
  'Un solo hisopado, 3 resultados: diagnostique Influenza A, Influenza B y COVID-19 simultáneamente por $178 pesos, evitando pruebas duplicadas y acelerando el tratamiento.', 'Un hisopado, 3 resultados en 15 min. Tu laboratorio se posiciona como centro de diagnóstico respiratorio diferencial. En temporada invernal, este combo puede ser el 30-40% de tu facturación de urgencias.', 'El panel molecular FilmArray de laboratorio cuesta $5,000-$12,000 y puede tardar horas. Esta prueba rápida a ~$178 pesos ofrece orientación diagnóstica diferencial en 15 minutos, permitiendo decisiones terapéuticas oportunas.', 'Costo unitario de ~$178 pesos. Al resolver Flu + COVID en un solo hisopado, se evitan dos pruebas separadas y se ofrece valor diferencial significativo.', 'Este es tu producto estrella de temporada invernal. En vez de ofrecer "COVID rápido" y "Influenza rápida" por separado (2 hisopados, 2 pruebas, 2 cobros logísticos), ofreces UN panel diferencial con UN hisopo. El médico que te refiere pacientes febriles en diciembre-febrero va a preferir mandártelos a ti que al laboratorio que solo hace COVID.',
  '[{"pregunta":"¿Al juntarlas pierde sensibilidad de carga vírica compartida?","respuesta":"No. El buffer de lisis disgrega todos los virus presentes en la muestra nasofaríngea, permitiendo que cada línea de reactividad capture su patógeno objetivo de forma independiente, sin interferencia cruzada."}]'::jsonb, '[{"pregunta":"El FilmArray cuesta igual y da 20 patógenos","respuesta":"** El FilmArray cuesta $5,000-$12,000 por prueba y necesitas el equipo ($50,000+ USD). Este combo cuesta $178 y no requiere equipamiento. Para el 90% de los cuadros respiratorios febriles, Flu A/B + COVID es suficiente para orientar el tratamiento."}]'::jsonb,
  '[{"name":"Prueba rápida de Mononucleosis:","reason":"Si FLU+COVID salen negativos en un joven con faringitis + adenopatía, Mononucleosis (EBV) es el siguiente diferencial. \"Protocolo Faringitis Pediátrica Completo.\"","url":"https://www.amunet.com.mx/tienda/prueba-rapida-mononeuclosis/"},{"name":"Prueba rápida de Dímero D:","reason":"COVID severo = riesgo de trombosis pulmonar. Si COVFLU detecta COVID+, evaluar coagulopatía con Dímero D.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-dimero-d/"},{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"COVID + hipoxia = tormenta de citoquinas con hiperferritinemia. Ferritina predice gravedad al día 6-8.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"},{"name":"Combo Respiratorio MAX (+ RSV):","reason":"Si tu laboratorio atiende pediatría o geriatría, sube al panel de 4 virus incluyendo RSV.","url":"https://www.amunet.com.mx/tienda/combo-respiratorio-max-influenza-a-b-sars-cov-2-rsv/"},{"name":"Strep A:","reason":"Para los casos donde el combo sale todo negativo y se sospecha faringoamigdalitis bacteriana.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-estreptococo-a/"}]'::jsonb, '[{"name":"COMBO RESPIRATORIO MAX (Flu A/B + COVID + RSV):","reason":"El premium pediátrico-geriátrico total agregando VSR (Virus Sincitial Respiratorio) para los dos extremos de la vida.","url":"https://www.amunet.com.mx/tienda/combo-respiratorio-max-influenza-a-b-sars-cov-2-rsv/"}]'::jsonb, ARRAY['Combo gripa rápida', 'combo influenza y cov 2 hisopo', 'test dual pandemia respiratoria invernal covflu net', 'prueba Oseltamivir prescripción certera'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
