-- Product: COMBO RESPIRATORIO MAX: Influenza A, B + SARS-CoV-2 + RSV (Virus Sincitial)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'COMBO RESPIRATORIO MAX: Influenza A, B + SARS-CoV-2 + RSV (Virus Sincitial)', 'infecciosas', 'https://www.amunet.com.mx/tienda/combo-de-pruebas-rapidas-para-ag-sars-cov2-vsr-influenza-a-y-b/', 'Prueba Inmunocromatográfica Combo Nasofaríngea', 'Amunet',
  1235, 240.8, '$600.00 - $900.00', '140% - 270% (Calculado desde un costo unitario de ~$240 a ~$247)', '[{"cantidad":5,"precio":1235},{"cantidad":10,"precio":2408}]'::jsonb,
  'Antígenos independientes para: Virus Influenza A/B, Virus Sincitial Respiratorio (RSV) y SARS-CoV-2 (COVID-19).', 'Muestra unificada nasofaríngea (hisopado).', 'Un hisopado nasofaríngeo profundo procesado en buffer unificado y distribuido en los canales de reacción.', 'Rápido y simultáneo (15 minutos).', NULL, NULL,
  'Detección cualitativa diferencial (bandas separadas para Flu A, Flu B, RSV y SARS-CoV-2).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , 1820 R2025 SSA',
  'Diagnóstico Diferencial Respiratorio Múltiple (Pediátrica/Geriátrica)', 'Panel diagnóstico diferencial de 4 virus respiratorios (Flu A/B, RSV, SARS-CoV-2) con un solo hisopado. Especialmente relevante en lactantes y adultos mayores durante temporada invernal, donde el VSR causa bronquiolitis severa que requiere intervención hospitalaria inmediata.', ARRAY['Cuidados Intensivos Neonatales', 'Pediatría', 'Neumología Geriátrica', 'Urgencias'], '- **Urgencias UCI Pediátricas:** Lactante ingresa con tiraje intercostal, cianosis y sibilancias. Con un solo hisopado nasofaríngeo se confirma VSR positivo en 15 minutos, permitiendo iniciar manejo de bronquiolitis (nebulización, oxígeno, aspiración de secreciones) y descartando Influenza, lo que evita la prescripción de oseltamivir innecesario.',
  'Lactantes (<2 años) y adultos mayores (>65 años), poblaciones con mayor riesgo de complicaciones respiratorias por VSR.', 'Ante indicio del Síndrome de deficiencia respiratoria agudo grave asilado.', 'La calidad del hisopado nasofaríngeo es determinante. Una toma superficial puede producir falsos negativos en los 4 analitos simultáneamente.', 'VSR positivo: manejo de bronquiolitis (soporte respiratorio, hidratación). Influenza positiva: oseltamivir. COVID positivo: manejo según gravedad y protocolo vigente. Aislamiento en todos los casos.', 'Descartar VSR como causa, considerar Parainfluenza / adenovirosis inespecíficas pero de cuadros manejables con broncodilatadores suaves en casa respirando libres.',
  'Diagnostique 4 virus respiratorios (Influenza A/B, RSV y COVID-19) con un solo hisopado por $240 pesos, ideal para pediatría y geriatría en temporada invernal.', 'Panel premium de 4 virus respiratorios por ~$240. Tu laboratorio se convierte en centro de referencia respiratoria para pediatras y geriatras de la zona. El equivalente molecular (FilmArray) cuesta $8,000+.', 'El PCR múltiple de laboratorio puede costar $8,000+ con resultados al día siguiente. Esta prueba rápida a ~$240 pesos identifica 4 virus en 15 minutos, evitando prescripciones empíricas innecesarias en la población más vulnerable.', 'Costo unitario de ~$240 pesos con precio sugerido de $600-$900. Diferencial importante vs PCR múltiple de laboratorio ($5,000-$8,000), posicionando al consultorio como centro de diagnóstico respiratorio.', 'Si tu laboratorio recibe muestras de pediatras o geriatras, este combo es obligatorio. El RSV (Virus Sincitial Respiratorio) es la primera causa de hospitalización en lactantes y tiene mortalidad significativa en adultos mayores. Con este panel, tu laboratorio ofrece el diagnóstico diferencial respiratorio más completo del mercado rápido.',
  '[{"pregunta":"¿En adultos les interesa el Virus Sincitial?","respuesta":"Sí, estudios epidemiológicos recientes demuestran que el VSR causa morbilidad y mortalidad significativa en adultos mayores institucionalizados, haciendo este panel igualmente relevante para geriatría."}]'::jsonb, '[{"pregunta":"¿Los médicos piden RSV?","respuesta":"** Los pediatras sí, cada vez más. Y los geriatras están empezando. Con la vacuna RSV para adultos mayores recién aprobada, la demanda de diagnóstico RSV va a crecer. Posiciónate ahora."}]'::jsonb,
  '[{"name":"Prueba rápida de Tuberculosis:","reason":"Cuadro neumónico que no resuelve después de descartar virus respiratorios: evaluar TB, especialmente en VIH+ o inmunosuprimidos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/"},{"name":"Combo VIH/Sífilis:","reason":"Si el paciente tiene neumonía atípica + factores de riesgo para VIH, complementar con ITS.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"CovFlu-Net (3 virus):","reason":"Versión más económica para cuando no se necesita RSV. Ofrece ambos: combo de 3 para general, combo de 4 para pediatría/geriatría.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"},{"name":"S. pneumoniae (orina):","reason":"Para diferenciar neumonía viral de bacteriana.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-streptococcus-pneumoniae/"}]'::jsonb, '[]'::jsonb, ARRAY['Panel VSR y flu rápido', 'infecciones respiratorias aguda panel consultorio ag'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
