  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antígeno Streptococcus pneumoniae (Orina)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-streptococcus-pneumoniae/', 'Prueba inmunocromatográfica cualitativa (Orina)', 'Amunet',
  500, 85, '$300.00 - $500.00', '200% - 480% (Calculado desde un costo unitario de ~$85 a ~$100)', '[{"cantidad":5,"precio":500},{"cantidad":20,"precio":1700}]'::jsonb,
  'Antígenos cápsulares libres de la bacteria Streptococcus pneumoniae filtrados por el glomérulo renal.', 'orina', '3 gotas de orina empleando el gotero pipeta sobre el pocillo S.', '10 a 15 min.', NULL, NULL,
  'Detección cualitativa (positivo si antígeno capsular de S. pneumoniae presente en orina).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMSPN01',
  'Diagnóstico Auxiliar Etiológico de NAC', 'Identificar S. pneumoniae como agente etiológico de Neumonía Adquirida en la Comunidad (NAC) mediante detección de antígeno capsular en orina. Especialmente útil en pacientes geriátricos que no pueden producir esputo de calidad para cultivo. Un resultado positivo orienta la antibioticoterapia dirigida (betalactámicos) en 15 minutos.', ARRAY['Medicina de Urgencias', 'Medicina Interna', 'Neumología Geriátrica', 'Infectología de UCI'], '- **Urgencias de 3era Edad:** Adulto mayor asilado con fiebre, estertores y tos seca. La radiografía muestra consolidación en lóbulo inferior. El paciente toso. Solícitale una orina simple por cánula uretral allí mismo en camilla y la prueba estalla reactiva a Neumococo, guiando el esquema antibiótico contundente contra Gram-Positivos en 15 minutos evitando escalar mortalmente por adivinanzas fúngicas.',
  'Adulto mayor o paciente comórbido con NAC severa, sepsis respiratoria, o incapacidad de producir esputo para cultivo.', 'Ante indicio del Síndrome Respiratorio Inferior Condensado / Neumonía.', 'Un "falso negativo" puede ser clínicamente engañoso si el paciente padece patología atípica de Gram negativismo intrahospitalaria como Klebsiella o patógenos vírales puros. La vacuna Neumocócica "Prevenar o Neumovax" reciente de dos semanas a un mes puede inducir a un "Falso Positivo Vacunal" en orina del infante y adulto (al expeler el antígeno inyectado en orina postvacunal).', 'El neumococo está destruyendo activamente. Inicie antibióticos betalactámicos en altas dosis hospitalarias empíricas en su esquema protocolario frente al Neumococo de neumonía/Meningitis.', 'Derivar a hemocultivar por que la sepsis/neumonía puede ser por hongos, virus agudos o Gram Negativos de escape resistentes (Buscar M. Pneumoniae en atípica).',
  'Identifique neumonía neumocócica con una muestra de orina (no requiere esputo), orientando la antibioticoterapia en 15 minutos.', 'Amplía tu menú con etiología neumocócica en orina. Los internistas y urgenciólogos necesitan saber si es neumococo ANTES de que llegue el cultivo de esputo. Tú se lo das en 15 min.', 'Obtener un esputo de calidad para cultivo es difícil en pacientes geriátricos, y el cultivo demora 48+ horas. La detección de antígeno neumocócico en orina ofrece resultados en 15 minutos, permitiendo dirigir la antibioticoterapia antes de que la ventana terapéutica se cierre.', 'Costo unitario de ~$85 pesos. En urgencias, la identificación etiológica rápida de NAC permite dirigir la antibioticoterapia y justifica honorarios especializados.', 'Los hospitales te refieren pacientes con NAC (Neumonía Adquirida en la Comunidad) que no pueden producir esputo. Con esta prueba, tu laboratorio ofrece etiología neumocócica en orina en 15 minutos — algo que ni el cultivo de esputo logra cuando la muestra es mala. Es un diferenciador frente a otros laboratorios.',
  '[{"pregunta":"¿Detecta neumonía en cualquier fluido?","respuesta":"La ventaja de usar orina como muestra es que los fragmentos del polisacárido capsular del S. pneumoniae se filtran por el glomérulo renal, evitando la contaminación por flora orofaríngea normal que complica los cultivos de esputo."}]'::jsonb, '[{"pregunta":"Mis médicos no la piden","respuesta":"** Porque no saben que existe. Comunícalo a tu red de médicos referentes: \"Ahora ofrecemos antígeno neumocócico en orina, resultado mismo día.\" La demanda se genera con la oferta."}]'::jsonb,
  '[{"name":"Prueba rápida de Mycoplasma pneumoniae (Antígeno):","reason":"La dupla respiratoria inferior. Neumonía con orina negativa para neumococo: considere Neumonía Atípica (\"del caminante\") hisopando Mycoplasma y rectifique a Azitromicina.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-mycoplasma-pneumoniae/"},{"name":"COMBO COVFLU-NET (Influenza A/B + COVID):","reason":"Si S. pneumoniae orina da negativo, descartar etiología viral respiratoria.","url":"https://www.amunet.com.mx/tienda/combo-flu-covid-prueba-rapida/"}]'::jsonb, '[{"name":"COMBO RESPIRATORIO MAX (Flu A/B + COVID + RSV):","reason":"Ante una neumonía, descartar etiología viral antes de confirmar bacteriana. \"Panel Neumónico Completo\" = S. pneumoniae orina + Resp MAX hisopo.","url":"https://www.amunet.com.mx/tienda/combo-respiratorio-max-influenza-a-b-sars-cov-2-rsv/"}]'::jsonb, ARRAY['Neumonía orina rápida', 'NAC neumococo antigeno orina', 'streptococcus pneumoniae rápida ancianos diagnóstico esputo', 'etiología neumonía', 'patología respiratoria inferior'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
