) VALUES (
  'Prueba rápida de Mycoplasma pneumoniae (Antígeno)', 'infecciosas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-mycoplasma-pneumoniae/', 'Prueba inmunocromatográfica cualitativa (Orofaríngea)', 'Amunet',
  1125, 210, '$500.00 - $800.00', '120% - 280% (Calculado desde un costo unitario de ~$210 a ~$225)', '[{"cantidad":5,"precio":1125},{"cantidad":10,"precio":2100}]'::jsonb,
  'Antígenos directos de la diminuta bacteria atípica intracelular Mycoplasma pneumoniae (Carente de pared celular).', 'Muestra celular por Hisopado Orofaríngeo del epite', 'Aplicación intensa del raspado del hisopo sobre la solución de buffer de lisis.', 'Rápido; en un umbral promedio de 10 a 15 min.', NULL, NULL,
  'Detección cualitativa de antígeno de M. pneumoniae en exudado orofaríngeo.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMMYC01',
  'Diagnóstico Auxiliar de Neumonía Atípica (Walking Pneumonia)', 'Diagnosticar neumonía atípica por *Mycoplasma pneumoniae*, bacteria sin pared celular que es intrínsecamente resistente a betalactámicos (penicilinas, amoxicilina). Responsable de hasta el 40% de las NAC en pacientes de 5-25 años. Un resultado positivo redirige el tratamiento de betalactámicos (ineficaces) a macrólidos (azitromicina), resolviendo cuadros de tos crónica >2 semanas que no responden al tratamiento convencional.', ARRAY['Pediatría', 'Neumología Infantil', 'Otorrinolaringólogos', 'Medicina Familiar', 'Medicina Escolar'], '- **Pediatra de Consultorio Escolar Privado:** Un niño de 8 años con tos crónica desgarradora seca nocturna arrastrada por 3 semanas ("se ahoga en la cama"), febrícula leve intermitente perdiendo peso y sus Rx pulmonares tienen una borrosidad de "vidrio esmerilado". Sus padres gastaron $2000 en amoxicilina inútil. El doctor interviene hisopando, detecta *Mycoplasma* en 15 mins "Point Of care", retira penicilinas, introduce Clorhidrato de Azitromicina. En dos días el niño duerme plácidamente. Magia y retención clase dorada del cliente.',
  'Niños >5 años, adolescentes y adultos jóvenes (5-25 años) con tos seca subaguda persistente (>2 semanas), febrícula intermitente y/o infiltrado intersticial en radiografía ("neumonía atípica del caminante").', 'Episodio subagudo de tos crónica escolar resistente a betalactámicos iniciales.', 'Mal hisopado = Falso negativo drástico carente de epitelio raspado fuerte donde se alberga el germen intracelular adherido.', 'Suspender betalactámico y prescribir macrólido (azitromicina 5 días o claritromicina 10 días). Informar medidas de higiene para prevención de contagio intradomiciliario.', 'Considerar otras etiologías: virosis persistente (adenovirus), asma, hiperreactividad bronquial post-infecciosa. Manejo sintomático con broncodilatadores y/o corticoides inhalados según cuadro clínico.',
  'Diagnostique neumonía atípica por Mycoplasma en 15 minutos para redirigir de betalactámicos (ineficaces) a macrólidos (curativos), resolviendo toses crónicas escolares de semanas.', 'Mycoplasma es el patógeno que todo pediatra sospecha pero nadie confirma porque el cultivo es imposible y la serología tarda. Dale la respuesta en 15 minutos y te conviertes en su laboratorio de cabecera.', 'El cultivo de Mycoplasma es técnicamente difícil y tarda semanas. En la práctica, la mayoría de los clínicos prescribe betalactámicos empíricos que son ineficaces contra M. pneumoniae. Esta prueba rápida permite redirigir a macrólidos en 15 minutos.', 'Costo unitario de ~$210 pesos con precio sugerido de $500-$800. Resolver una "tos crónica de semanas" en 15 minutos genera alto valor percibido y fidelización del paciente.', 'El Mycoplasma es responsable del 40% de las neumonías en pacientes de 5-25 años. El cultivo de Mycoplasma es técnicamente difícil y tarda semanas. La serología (IgM) tarda días. Con esta prueba rápida, tu laboratorio ofrece resultado mismo día para una etiología que normalmente tarda semanas en confirmarse. Es un diferenciador enorme para pediatras.',
  '[{"pregunta":"¿Su incidencia es tan alta como se rumora en prepas?","respuesta":"M. pneumoniae es responsable de hasta el 40% de las neumonías adquiridas en la comunidad en pacientes de 5 a 25 años. En consultorios pediátricos y de medicina escolar, la frecuencia justifica ampliamente tener esta prueba disponible."}]'::jsonb, '[{"pregunta":"Es muy de nicho","respuesta":"** Cualquier pediatra ve 5-10 \"toses de 3 semanas\" por mes en temporada escolar. A $500-$800 por prueba y un costo de $210, haz la cuenta."}]'::jsonb,
  '[{"name":"COMBO RESPIRATORIO MAX (Flu A/B + COVID + RSV):","reason":"Para fiebres de 39°C agudas y severas donde se deben diferenciar virus respiratorios de patógenos atípicos intrapulmonares.","url":"https://www.amunet.com.mx/tienda/combo-respiratorio-max-influenza-a-b-sars-cov-2-rsv/"},{"name":"Prueba rápida de Estreptococo A (Hisopo):","reason":"Si el infante cursa dolor intenso al tragar y pus blanca en garganta, descartar fiebre escarlatina bacteriana superior antes de asumir atípica intrapulmonar.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-estreptococo-a/"},{"name":"S. pneumoniae (orina):","reason":"Panel Neumonía Etiológico (Mycoplasma hisopo + Neumococo orina) = atípica + típica cubiertos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-streptococcus-pneumoniae/"}]'::jsonb, '[{"name":"Prueba rápida de S. pneumoniae (orina):","reason":"\"Panel Neumonía Etiológico\" (Mycoplasma hisopo + Neumococo orina) cubre neumonía atípica Y típica. Dos etiologías, dos muestras, una consulta.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-streptococcus-pneumoniae/"}]'::jsonb, ARRAY['test walkin pneumoniae', 'hisopo pneumoniae tos severa neumonía', 'neumonía atípica antígeno rápido', 'tos traqueobronquitis colegios niños test ambulatorio'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
