-- Product: Prueba rápida de Embarazo (hCG en Sangre y Suero)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Embarazo (hCG en Sangre y Suero)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-embarazo-hcg-sangre/', 'Prueba Inmunocromatográfica de detección serológica de Hormona (Flujo Lateral)', 'Amunet',
  380, 15, '$150.00 - $300.00', '¡Hasta 900%! (Al ser el ticket comercial de consulta de descarte más seguro y estresante del día en emergencias hospitalarias).', '[]'::jsonb,
  'Hormona Gonadotropina Coriónica humana (hCG).', 'orina', '3 gotas.', 'De 3 a 5 min. (Ultrapredicción inmediata Point of Care).', NULL, NULL,
  'Detección cualitativa de hCG (positivo/negativo).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS',
  'Diagnóstico Rápido de Gestación', 'Confirmación rápida de gestación mediante detección de hCG en sangre capilar. Principal ventaja sobre las pruebas urinarias: no depende del grado de concentración de la orina y puede realizarse en cualquier momento del día. Especialmente útil en urgencias prequirúrgicas donde se requiere resultado inmediato sin necesidad de muestra urinaria.', ARRAY['*Todas*', 'Principalmente Medicina de Urgencias Hospitalarias pre-operatorios obligatorios', 'Ginecología', 'Otorrinolaringólogos (Tomografías TAC en mujeres de edad fértil)', 'Traumatología'], '- **Urgencias e Imageneología Cero-Riesgos:** Paciente femenina de 24 años ingresa a urgencias con cuadro quirúrgico agudo. No puede proporcionar muestra de orina. El protocolo prequirúrgico exige descartar embarazo antes de administrar medicamentos teratógenos o radiación. Con sangre capilar se obtiene resultado en 5 minutos, cumpliendo el requisito médico-legal y protegiendo tanto a la paciente como al equipo médico.',
  'Mujeres de edad productiva reproductiva (13-50 años) frente a Amenorrea o frente a exposición en entornos de intervención clínica (Medicamentos controlados).', 'Ante todo proceso de retraso de ciclo, pre-prescripción de controlados agresivos, u hospitalización de rutinas quirófánicas.', 'Un resultado negativo puede ser falso si la prueba se realiza demasiado pronto (se requieren 6-11 días post-implantación para niveles detectables de hCG). Raramente, un resultado positivo en varones puede asociarse a tumores germinales testiculares. La prueba no distingue embarazo intrauterino de ectópico: ante resultado positivo con dolor abdominal agudo, solicitar ecografía transvaginal urgente para descartar embarazo ectópico.', 'Confirmar en USG (Ecosonografía vital por edad gestacional de embarazo), Prescribir profilácticos de folatos maternales.', 'Si persiste la amenorrea, repetir la prueba en 1-2 semanas para descartar ovulación tardía.',
  'Confirme o descarte embarazo con sangre capilar en 5 minutos, cumpliendo el requisito prequirúrgico obligatorio antes de radiología, anestesia o medicamentos teratogénicos, a un costo de ~$20 pesos por prueba.', NULL, 'La sub-beta hCG cuantitativa de laboratorio es el estándar de oro pero requiere extracción venosa, proceso y horas de espera. En urgencias pre-quirúrgicas, esta prueba ofrece confirmación/descarte en 5 minutos con sangre capilar. A diferencia de las pruebas de orina de farmacia, no se ve afectada por la dilución urinaria.', 'Costo unitario de ~$15-$30 pesos. Producto indispensable en urgencias y pre-quirúrgico. El margen es enorme (hasta 900%) pero el verdadero valor es el cumplimiento del protocolo médico-legal.', NULL,
  '[{"pregunta":"¿Tiene que ser orina en ayunas como dicen por las de las farmacias caseras patito azules grandes que anuncian en televisión masiva para detectar tempranamente?","respuesta":"Lo hermoso de este test paramédico en formato cassette \"Sangre\", es que la sangre capilar (venosa/Goteo de punción digital) es un concentrado idéntico invariable en la medianoche o en pleno medio día, permitiendo a la mujer estar segura de la prueba que el médico aplica ante el estrés."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Combo VIH/Sífilis:","reason":"Embarazo confirmado → tamizaje prenatal obligatorio (NOM-007). VIH + Sífilis en la misma visita con un solo pinchazo adicional.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"Prueba rápida TORCH IgG/IgM:","reason":"\"Panel Prenatal Ampliado\" = hCG + TORCH (Toxoplasmosis, Rubéola, CMV, Herpes) para evaluar infecciones teratogénicas.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-torch-igg-e-igm/"}]'::jsonb, '[{"name":"Combo VIH/Sífilis:","reason":"\"Panel Prenatal Express\": hCG + VIH/Sífilis = tres estudios prenatales obligatorios (NOM-007) en una consulta.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"}]'::jsonb, ARRAY['Confirmación hCG pipeteo rápido suero prueba de embarazo sangre rápida cassette', 'amenorrea confirmación confiable de pipeta doctor sangre rápida'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
