-- Product: Prueba rápida de AFP (Alfa-fetoproteína Marcador Tumoral)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de AFP (Alfa-fetoproteína Marcador Tumoral)', 'oncologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-afp/', 'Prueba inmunocromatográfica de Marcador Tumoral en Sangre', 'Amunet',
  450, 45, '$250.00 - $400.00', '450% - 780% (Calculado desde un costo unitario de ~$45)', '[{"cantidad":10,"precio":450}]'::jsonb,
  'Alfa-fetoproteína (AFP) anormal humana.', 'sangre_total', '2 Gotitas en el POC pocillo (Pipeteo capilar).', 'Rápido; en un umbral promedio de 15 min.', NULL, NULL,
  'Detección Cualitativa si la concentración de AFP está significativamente elevada rebasando los limites biológicos saludables de un adulto.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMAFP01',
  'Diagnóstico Auxiliar / Tamizaje Temprano / Control Tumoral', 'Ser el marcador pronóstico de primera mano frente a masas o lesiones que delatan malignidad. En adultos normales la AFP es indetectable; si brilla positiva, señala de manera ominosa una desregulación por Cáncer Hepático, Cáncer Testicular, Cáncer Ovárico Temprano o de Vías Biliares, actuando como un faro precoz para intervenir lesiones agresivas tempranas, o como seguimiento si regresión post-corte curativa existió.', ARRAY['Ginecología y Obstetricia Oncológica', 'Urólogos Pélvicos (Manejo Testicular jóvenes)', 'Hepatología (Cirrosis complicadas vs Hepatocarcinoma)', 'Medicina Preventiva Chequeos Masters'], '- **Chequeo Funcional o Evaluación en Hígado Graso Crónico (USG de abdomen):** Paciente con 10 años de Hepatitis B/Cirrosis entra con una "bolita en el hígado en ultrasonido" y un dolor constante y se nota ictericia ligera (Ojos amarillos). Un test rápido en consulta dispara Positividad a un escalofriante color rojizo a AFP; el Clínico refiere en la misma cita una biopsia/TAC urgente frente al temible y silente Carcinoma Hepatocelular Temprano operándolo.
  - **Sospecha de tumor testicular:** Varón joven (20-35 años) con masa escrotal sólida. AFP positiva orienta el diagnóstico hacia tumor germinal testicular (no seminomatoso), facilitando la referencia urológica expedita. La detección temprana se asocia a tasas de curación >95%.',
  'Cirróticos portadores crónicos o asediados de cáncer testiculares en bultos (Jóvenes) o como monitor en Ginecología Prenatal para defectos crónicos.', 'Ante evento incidental sospechoso radiológico u screening a población portadora Hepatica vírica de control (Por ejemplo paciente curado con VIH o Hepatitis que está propenso de recaída y desarrollo fatal de Hepatocarcinoma del alcoholizado crónico obeso).', 'Un "falso positivo" puede ser clínicamente engañoso si la paciente está gestante y suelta niveles alterados de Alfafetoproteinas del feto malformadas, pero que asustan falsamente para "cancéres de ovarios adultas". No sustituye biópsias para confirmación anatomopatológicas firmes (Manejo integral).', 'Cita inmediata para evaluación por Resonancias/TAC abdomino-pélvicas buscando "el nido que lo vomita al torrente". Si su paciente está tratado de Hepatocarcinoma hace un año significa "reincidencia diseminada del tumor residual que renació".', 'Seguir si el USG ecográfico demuestra bultos agresivos ya que no todo tumor cancerígeno la produce; derivar al Oncólogo en escrutinio protocolario total en base al algoritmo.',
  'Evalúe sospecha de carcinoma hepatocelular o tumores germinales testiculares con AFP por $45 pesos, orientando la referencia tras hallazgos ecográficos sospechosos.', NULL, 'Los marcadores tumorales en laboratorio externo tardan 1-3 días y cuestan $300-$600 por analito. Esta prueba permite una orientación diagnóstica inmediata en consultorio, ideal para complementar hallazgos ecográficos sospechosos.', 'Costo unitario de $45 pesos con precio sugerido de $250-$400. Margen de 450%-780%. Ideal para integrar en paquetes de Check-Up Hepático o Masculino.', NULL,
  '[{"pregunta":"¿Detecta próstata generalizado?","respuesta":"No. La AFP es específica para tumores germinales (testiculares en varones jóvenes) y hepatocelulares (pacientes cirróticos). Para próstata, utilice la prueba de PSA cualitativa o semicuantitativa del catálogo."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Transferrina/FOB (Sangre Oculta en Heces):","reason":"Escrutinio abdominal: AFP evalúa hígado, FOB mira tracto inferior (colon, pólipos, cáncer colorrectal).","url":"https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/"},{"name":"Prueba rápida de CA-125:","reason":"Aliado gemelar: en mujeres con masas abdominopélvicas confusas, AFP (hígado/germinal) + CA-125 (ovario) = \"Panel de Masa Abdominal Femenina\".","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-125/"}]'::jsonb, '[{"name":"Kit de Pruebas Rápidas Tumorales:","reason":"\"Check-Up Oncológico Completo\" de múltiples marcadores. Mayor ticket y mayor cobertura preventiva.","url":"https://www.amunet.com.mx/tienda/kit-de-pruebas-rapidas-tumorales/"}]'::jsonb, ARRAY['tamizaje hígado prueba rápida oncología antígenos', 'test oncológico cáncer marcador de prevención hepatocelular diagnóstico'], ARRAY['medico'],
