-- Product: Prueba rápida de CA-125 (Marcador Tumoral Ovárico)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de CA-125 (Marcador Tumoral Ovárico)', 'oncologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-125/', 'Prueba inmunocromatográfica de Marcador Tumoral en Sangre', 'Amunet',
  900, 135.4, '$450.00 - $700.00', '150% - 410% (Calculado desde un costo unitario de ~$135 a ~$180)', '[{"cantidad":5,"precio":900},{"cantidad":10,"precio":1354}]'::jsonb,
  'Antígeno carbohidrato 125 (CA-125), glicoproteína de alto peso molecular asociada a tumores ováricos epiteliales y otras patologías pélvicas.', 'sangre_total', '3 Gotas.', 'Rápido; en un umbral promedio de 10 a 15 min de revelación in-situ.', NULL, NULL,
  'Detección cualitativa de hCG (positivo/negativo).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMCAO01',
  'Diagnóstico Auxiliar Oncológico Ginecológico', 'Marcador tumoral para evaluación de masas pélvicas y seguimiento oncológico ovárico. El cáncer de ovario es frecuentemente asintomático o presenta síntomas inespecíficos (distensión abdominal, saciedad temprana). Un CA-125 elevado (>35 U/mL) ante masa pélvica ecográfica sospechosa orienta la referencia quirúrgica urgente y el seguimiento post-tratamiento.', ARRAY['Ginecología y Obstetricia', 'Ultrasonidistas (dupla post-ecográfica ante masa pélvica sospechosa)', 'Medicina Interna Check Ups ejecutivos a femeninas maduras premium'], '- **Ginecología Check-Up General "Mamá 55 años" ECO:** Paciente pre y posmenopáusica entra con queja simple de "Doctor me siento empachada distendida estreñida permanentemente, los pantalones ya no me cierran y siento pujo para orinar". El USG trasvaginal halla "un bulto ovárico solido". Ante el hallazgo ecográfico de masa ovárica sólida, el CA-125 en consultorio permite obtener orientación diagnóstica en 15 minutos, acelerando la referencia al oncólogo ginecólogo. Posterior a cirugía, el monitoreo seriado de CA-125 permite detectar recurrencia tempranamente.',
  'Mujeres con antecedentes familiares de cáncer de mama u ovario (BRCA1/2), dolor pélvico crónico no intestinal, sangrado postmenopáusico en mujeres de 50-65 años, y pacientes en seguimiento oncológico post-tratamiento para monitoreo de respuesta terapéutica.', 'Ante evento incidental sospechoso ecográfico gineco pélvico o escrutinio screening rutinario familiar clase Premium.', 'Un "falso positivo" puede ocurrir en mujeres de 20 a 35 años con endometriosis, enfermedad pélvica inflamatoria, menstruaciones intensas o quistes funcionales benignos que elevan CA-125 por inflamación (no por malignidad). No utilizar como tamizaje aislado en mujeres en edad fértil sin justificación ecográfica.', 'CA-125 elevado. Referir a evaluación especializada con TAC abdominopélvico para estadificación y programar valoración oncológica quirúrgica.', 'Un porcentaje mínimo de tumores Ovario No producen (Mucinoso) el químico. Seguir vigilancia semestral preventiva de USG si duele el abdomen.',
  'Evalúe sospecha de patología ovárica con CA-125 en sangre capilar por ~$135 pesos, complementando hallazgos ecográficos pélvicos con un marcador tumoral en 15 minutos.', NULL, 'Cuando un ultrasonido revela una masa pélvica sospechosa, enviar marcadores a laboratorio externo demora días. El CA-125 en consultorio permite obtener orientación oncológica inmediata, acelerando la referencia especializada cuando las horas cuentan.', 'Costo unitario de ~$135 pesos con precio sugerido de $450-$700. Ideal para integrar en paquetes de Check-Up Ginecológico o seguimiento oncológico post-cirugía.', NULL,
  '[{"pregunta":"¿El cartucho sirve sin USG?","respuesta":"Su mayor valor es complementar un hallazgo ecográfico sospechoso. Como tamizaje general aislado tiene limitaciones por falsos positivos (endometriosis, EPI, menstruación). Se recomienda integrar en paquetes de Check-Up Ginecológico junto con ecografía pélvica."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Embarazo hCG (Sangre):","reason":"En mujeres en edad fértil con dolor pélvico + masa anexial, CA-125 + hCG descartan embarazo ectópico que puede simular patología ovárica.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-embarazo-hcg-sangre/"},{"name":"Prueba rápida de AFP:","reason":"AFP + CA-125 = \"Panel de Masa Abdominal Femenina\" (hígado + ovario) para dolor abdominal en mujeres.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-afp/"}]'::jsonb, '[{"name":"Kit Tumorales + PCR VPH:","reason":"\"Panel Onco-Ginecológico Integral\": CA-125 (ovario) + CA 15-3 (mama) + VPH PCR (cérvix) = vigilancia oncológica ginecológica completa. URL VPH: https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/ URL CA 15-3: https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-ca-153/","url":null}]'::jsonb, ARRAY['CA-125 Cáncer de ovarios rápida marcador tumoral sangre consultorio', 'prueba ginecologia quiste prevencion ca125', 'antígenos masa ovárica check-up femenil prueba', 'tumor maligno ginecóloga rápida diagnostico', 'criba de abdomen mujer dolor screening'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
