-- Product: Prueba rápida de Antígeno CA 15-3 (Marcador Tumoral Mama)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antígeno CA 15-3 (Marcador Tumoral Mama)', 'oncologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-ca-153/', 'Prueba inmunocromatográfica cualitativa (Sangre/Suero/Plasma)', 'Amunet',
  900, 155, '$450.00 - $700.00', '150% - 350%', '[{"cantidad":5,"precio":900},{"cantidad":10,"precio":1550}]'::jsonb,
  'Antígeno Carbohidrato 15-3 (CA 15-3), mucina epitelial polimórfica secretada por células de cáncer de mama.', 'sangre_total', '3 gotas.', '10 a 15 min.', 96.4, 98.8,
  'Detección cualitativa; resultado positivo cuando la concentración supera aproximadamente 30 U/mL. **Relevancia Clínica:** Este umbral está alineado con el límite superior normal del CA 15-3 en suero. Concentraciones superiores se asocian a actividad tumoral activa, especialmente recurrencia o enfermedad metastásica en cáncer de mama.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMCAM01',
  'Monitoreo Oncológico y Diagnóstico Auxiliar', 'Prueba auxiliar de seguimiento para pacientes con antecedente de cáncer de mama. Concentraciones superiores a 30 U/mL se asocian con sospecha de recurrencia o enfermedad metastásica, orientando la solicitud oportuna de estudios de imagen complementarios.', ARRAY['Oncología Médica', 'Cirugía Oncológica de Mama', 'Ginecología', 'Medicina Interna (Chequeo a sobrevivientes)'], '- **Seguimiento Post-Quimioterapia:** Paciente femenina que superó Cáncer de Mama hace 2 años acude a revisión por dolor óseo difuso. El médico dispara la prueba CA 15-3 en consultorio; al pintar positivo, acelera el protocolo de escrutinio Gammagráfico óseo asumiendo recaída metastásica de seno.',
  'Mujeres con historial personal de cáncer de mama en remisión, en terapia activa, o casos de mastopatía severa BI-RADS sospechoso que aguardan biopsia.', 'Seguimiento trimestral o semestral en pacientes oncológicas o ante nuevos síntomas sospechosos.', 'Un "falso positivo" (elevaciones benignas) puede ocurrir en hepatopatías, insuficiencia renal, o anemia megaloblástica, e incluso en cánceres de ovario/gastrico. No es una prueba para "screening general de mujeres sanas sin mastografía".', 'Canalización estricta a Oncología para estadiaje PET-CT/Mastografía contrastada urgente por recrudecimiento tumoral activo.', 'El tratamiento está funcionando o no hay carga tumoral mamaria sistémica detectable. Seguir pautas normativas radiológicas anuales.',
  'Integre el marcador tumoral CA 15-3 en su consultorio para dar seguimiento a pacientes con antecedente de cáncer de mama, detectando posibles recurrencias en 15 minutos sin depender de laboratorio externo.', NULL, 'En el seguimiento oncológico, los resultados de laboratorio pueden tardar días. Con esta prueba rápida, el profesional obtiene un resultado orientador en 15 minutos, permitiendo una consulta de seguimiento más completa y oportuna.', 'Con un costo unitario de aproximadamente $155 pesos y la posibilidad de facturar el marcador tumoral como parte de una consulta de seguimiento oncológico, el margen es significativo y el valor agregado al paciente es evidente.', NULL,
  '[{"pregunta":"¿Sustituye a la mastografía?","respuesta":"¡Absolutamente no! El CA 15-3 es un marcador sistémico sérico para rastrear actividad/metástasis. Se usan juntos: Eco/Masto mira la anatomía, CA 15-3 evidencia la sangre si las células viajan."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de CA-125:","reason":"Mama y ovario comparten carga genética (BRCA). \"Panel Onco-Femenino\" = CA 15-3 mama + CA-125 ovario.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-125/"}]'::jsonb, '[{"name":"Prueba rápida de CA-125:","reason":"\"Panel Onco-Feminino\" (CA 15-3 mama + CA-125 ovario). Pacientes con seguimiento de mama necesitan vigilancia ovárica.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-125/"}]'::jsonb, ARRAY['CA 15-3 cáncer de mama prueba rápida mastectomía seguimiento tumoral', 'marcador de mamas', 'nódulo mamario mastografía antígeno mama sangre', 'test ca153 oncólogo ginecólogo criba metástasis'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
