-- Product: Prueba rápida de PSA (Antígeno Prostático Específico Semicuantitativa)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de PSA (Antígeno Prostático Específico Semicuantitativa)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-psa-antigeno-prostatico-especifico/', 'Prueba inmunocromatográfica Semicuantitativa (Sangre/Suero/Plasma)', 'Amunet',
  186, 63, '$350.00 - $600.00', '270% - 850% (Calculado desde un costo unitario ultra competitivo de ~$63)', '[{"cantidad":2,"precio":186},{"cantidad":20,"precio":1260}]'::jsonb,
  'Antígeno Prostático Específico (PSA).', 'sangre_total', '1 gota de suero/plasma o 2 gotas de sangre total/capilar + 1 gota de buffer.', 'Rápido; en unos 15 min.', 99.45, 99.2,
  'Lectura semicuantitativa en 4 rangos: Negativo (<3 ng/mL), Positivo 3-10 ng/mL, Positivo 10 ng/mL, Positivo >10 ng/mL. La intensidad de la línea T respecto a la línea de referencia R determina el rango. **Relevancia Clínica:** Concentraciones <3 ng/mL se consideran normales; entre 3-10 ng/mL sugieren hiperplasia prostática benigna o prostatitis (requiere PSA libre para discriminar); >10 ng/mL se asocian con alta probabilidad de cáncer prostático.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'DMPSA01 (etiquetado UPI — Uso para Investigación)',
  'Tamizaje Prostático Masculino', 'Prueba semicuantitativa de tamizaje para la detección de concentraciones elevadas de PSA en sangre capilar, útil como auxiliar en la evaluación de la próstata. Clasifica el resultado en rangos clínicamente relevantes (<3, 3-10, >10 ng/mL) que orientan la conducta médica: seguimiento, estudios complementarios o referencia a urología.', ARRAY['Urología Selecta', 'Medicina Familiar/General de CheckUp', 'Geriatría'], '- **Tamizaje en consulta de medicina general:** Paciente varón de 55 años con síntomas urinarios obstructivos (nicturia frecuente, chorro débil). Durante la consulta de control, el médico realiza la prueba rápida de PSA con sangre capilar. El resultado muestra un rango de 3-10 ng/mL, lo que sugiere hiperplasia prostática y permite orientar la referencia a urología con evidencia objetiva, facilitando la aceptación del paciente.',
  'Varones mayores de 45-50 años con síntomas urinarios obstructivos bajos (nicturia, chorro débil, sensación de vaciado incompleto), o varones asintomáticos en tamizaje preventivo anual.', 'Anualmente obligatorio para hombres a partir de 45 años.', 'No sustituye la biópsia de Próstata en casos de sospecha dura, prostatitis, actividad física intensa o presión perineal prolongada pueden elevar el PSA y generar falsos positivos. La hiperplasia prostática benigna también eleva el PSA sin implicar malignidad. El tacto rectal complementario es indispensable.', 'Refiera directo a Urología para la palpación del "tacto de piedra o borde elástico" Prostático y programación del USG Transrectal/Ecografía vesical residual biópsica.', 'Resultado dentro de rango normal. Continuar tamizaje anual según edad y factores de riesgo.',
  'Ofrezca a sus pacientes masculinos mayores de 45 años un tamizaje prostático rápido e indoloro con sangre capilar, clasificando el resultado en rangos clínicos precisos en solo 10 minutos.', NULL, 'Muchos pacientes posponen la visita al laboratorio por falta de tiempo o temor. Ofrecer el tamizaje de PSA directamente en consultorio con un piquete de dedo elimina esa barrera, aumentando la oportunidad de detección oportuna.', 'Con un costo unitario de ~$63 (presentación de 20 pzas), el PSA semicuantitativo permite ofrecer paquetes preventivos masculinos ("Check-Up Prostático") con un margen atractivo, agregando valor clínico a la consulta.', NULL,
  '[{"pregunta":"¿Es mejor cuantitativa?","respuesta":"La prueba semicuantitativa ofrece un semáforo de riesgo clínico: Normal (<3 ng/mL), Zona Gris (3-10 ng/mL) donde se requiere PSA libre para discriminar, y Zona de Alto Riesgo (>10 ng/mL). Es ideal para orientar la conducta médica sin esperar días por un resultado de laboratorio."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Microalbuminuria:","reason":"Paquete Senior \"Próstata + Riñón\": PSA evalúa próstata, microalbuminuria evalúa función renal.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-microalbuminuria/"},{"name":"Prueba rápida de Transferrina/FOB:","reason":"Paquete Senior \"Próstata + Colon\": PSA + FOB cubren los dos cánceres más frecuentes en hombres >50.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/"}]'::jsonb, '[{"name":"Kit de Pruebas Rápidas Tumorales:","reason":"\"Check-Up Masculino\" (PSA próstata + AFP hígado). Hombres >50 necesitan tamizaje prostático Y hepático. URL AFP: https://www.amunet.com.mx/tienda/prueba-rapida-afp/","url":null}]'::jsonb, ARRAY['tacto rectal escape', 'test antígeno prostatico screening en dedo', 'hiperplasia benigna próstata cáncer rápido consulta'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
