INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de PSA (Antígeno Prostático Específico Cualitativa)', 'otros', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-psa-antigeno-prostatico-especifico-cualitativa/', 'Prueba inmunocromatográfica Cualitativa (Sangre/Suero/Plasma)', 'Amunet',
  160, 50, '$250.00 - $400.00', '400% - 700%', '[{"cantidad":2,"precio":160},{"cantidad":20,"precio":1000}]'::jsonb,
  'Antígeno Prostático Específico (PSA).', 'sangre_total', '2 gotas.', '10 a 15 min.', 99, 99,
  'Detección cualitativa con umbral de >3 ng/mL. **Relevancia Clínica:** Un resultado positivo indica concentraciones de PSA por encima de lo normal, lo que puede asociarse con hiperplasia prostática, prostatitis o cáncer prostático. Requiere estudios complementarios para diferenciación.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMPSA02',
  'Diagnóstico Dicotómico Rápido (Positivo/Negativo)', 'Prueba cualitativa de tamizaje rápido (positivo/negativo) para detección de PSA elevado. A diferencia de la versión semicuantitativa que ofrece rangos, esta versión ofrece un resultado dicotómico ideal para tamizaje masivo donde se requiere alta velocidad y decisión binaria.', ARRAY['Medicina de Salud Ocupacional Fabril de obreros (Escrutinios grupales)', 'Médicos de Guardia nocturnos'], '- **Screening laboral masivo / Feria de salud:** En una jornada de salud masculina para empleados mayores de 50 años, el médico ocupacional aplica la prueba cualitativa de PSA a cada participante con sangre capilar. Los resultados positivos (>3 ng/mL) se derivan a valoración médica individual con la versión semicuantitativa o a laboratorio para PSA cuantitativo, optimizando recursos sin gastar en pruebas de mayor costo para toda la población.',
  'Varones mayores de 45 años en tamizajes poblacionales (laborales, ferias de salud, campañas preventivas) o en urgencias con retención urinaria aguda donde se requiere orientación rápida.', 'Ante tamizaje poblacional.', 'No da la graduación de peligro exacta, un PSA de 500 ng/mL (posible metástasis) se mostrará igual que un PSA de 10 ng/mL (hiperplasia benigna). Para mejor estratificación, considerar la versión Semicuantitativa en consultorio privado.', 'Canalizar a Ultrasonidos prostáticos y bloqueadores de testosterona como Dutasteride guiados por Urología.', 'Descartada una urgencia de la próstata secretora extrema.',
  'La prueba más económica del catálogo para tamizaje de PSA: resultado positivo/negativo desde $50 MXN por prueba, ideal para jornadas de salud y programas ocupacionales.', NULL, 'Un PSA cuantitativo en laboratorio cuesta $300-$500 por persona. Para un tamizaje de 100 empleados, esta prueba reduce el costo de primera línea a ~$50 por persona, reservando el laboratorio solo para los positivos.', 'Alto volumen con márgenes robustos. A un costo de ~$50 por prueba y cobrando $250-$400 por aplicación en programa ocupacional, el margen por evento es sustancial.', NULL,
  '[{"pregunta":"¿Cuál pido, Cualitativa o Semicuantitativa?","respuesta":"Para consulta urológica privada donde se requiere estratificar el riesgo: use la Semicuantitativa (rangos Normal/Gris/Alta). Para tamizaje masivo en jornadas de salud con criterio positivo/negativo: la Cualitativa es la opción más costo-eficiente."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Sífilis:","reason":"Completando paquetes laborales \"De Ingreso a Compañía\" con tamizaje ITS.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-sifilis/"},{"name":"Prueba rápida de Antidoping 5 drogas:","reason":"Panel laboral completo = PSA + Antidoping + Sífilis.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-antidoping/"}]'::jsonb, '[{"name":"PSA Semicuantitativa Amunet:","reason":"Si el paciente requiere mayor precisión diagnóstica, la versión Semicuantitativa estratifica por rangos clínicos (<3, 3-10, >10 ng/mL).","url":"https://www.amunet.com.mx/tienda/prueba-rapida-psa-antigeno-prostatico-especifico/"}]'::jsonb, ARRAY['Prostatinet test prósata cualitativa si no', 'tamizaje criba obreros checkup económico rápida próstata antígeno', 'urología prueba sangre digital'], ARRAY['medico'],
  TRUE, NOW(), NOW()
)
