-- Product: Prueba rápida de Transferrina / Sangre Oculta en Heces (FOB)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Transferrina / Sangre Oculta en Heces (FOB)', 'oncologicas', 'https://www.amunet.com.mx/tienda/prueba-rapida-transferrina-sangre-oculta-en-heces-fob/', 'Prueba inmunocromatográfica cualitativa combinada (Heces)', 'Amunet',
  400, 65, '$350.00 - $550.00', '430% - 740% (Calculado desde un costo unitario de ~$65 a ~$80)', '[{"cantidad":5,"precio":400},{"cantidad":20,"precio":1300}]'::jsonb,
  'Hemoglobina Humana intacta (FOB) y Transferrina humana (Proteína transportadora de hierro de altísima estabilidad gástrica).', 'heces', 'Aplicación intensa del raspado sumergido en buffer. 3 gotas de buffer sobre el casete.', 'Rápido; en unos 15 min.', 97.9, 99.7,
  'Detección cualitativa. Límite de detección: FOB (Hemoglobina) 50 ng/mL; Transferrina 40 ng/mL. **Relevancia Clínica:** La combinación de ambos marcadores permite diferenciar sangrado digestivo alto (Transferrina positiva, FOB negativa) de sangrado digestivo bajo (ambas positivas), orientando la decisión entre endoscopia alta o colonoscopia.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'DMTRF01 (etiquetado UPI — Uso para Investigación)',
  'Tamizaje Fundamental "Cáncer Colorrectal" y Diferenciador Hemorrágico Gastroenterológico (Alto/Bajo).', 'Prueba no invasiva de tamizaje para detectar sangrado oculto gastrointestinal y diferenciar su origen. La hemoglobina se degrada por los ácidos del tracto digestivo alto, por lo que puede dar falsos negativos en sangrado gástrico. La transferrina, al ser más estable, sobrevive la digestión completa. Esto permite una interpretación diferencial: Transferrina (+) y FOB (-) = sangrado alto (estómago/esófago/duodeno); ambas (+) = sangrado bajo (colon/recto).', ARRAY['Gastroenterología', 'Oncología Preventiva', 'Cirujanos Proctólogos', 'Medicina Interna (Pacientes Geriátricos Anémicos)'], '- **Adulto de 60 años con Anemia ferropénica y fatiga:** El internista solicita muestra fecal. La prueba muestra Transferrina positiva y FOB negativa, indicando sangrado digestivo alto. Se refiere a endoscopia superior para descartar úlcera péptica o neoplasia gástrica. El colon queda descartado como origen al tener FOB negativa. Resultado diferencial en 15 minutos.',
  'Adultos proctológicos sospechosos de Cáncer Colorrectal (Mayores de 50 años), Hemorragias sospechosas y "evacuación gástrica oscura dudosa tipo melenas".', 'Anualmente obligatorio para hombres a partir de 50 años en prevención del asintomático Tumor de Colon o Úlceras silenciosas asintomáticas que sangran por uso de analgésicos crónicos de dolor de artritis (AINEs).', 'No reemplaza Endoscopias y Colonoscopías en diagnósticos definitivos de la mucosa, sino que filtra/Tamiza quién si las necesita de urgencia impostergable. Menstruaciones o sangrado rectal franco (Hemorroidal obvio rojo brillante) lo hace positivizar inútilmente.', 'Si Transferrina es Positiva y FOB Negativo: Busque la fuga Arriba (Endoscopia Alta de Estómago o duodeno). Si ambas son reactivas Busque la fuga Abajo (Cancer Colorrectal Colonoscopía o Fisuras perianales severas).', 'Revisión Anual obligatoria Geriátrica, y tratar hemorroides por inflamación ciega; "Felicidades, el cáncer color rectal silencioso sangrante no está activo hoy".',
  'Supere el test de guayaco tradicional con una prueba inmunocromatográfica dual (Transferrina + Hemoglobina) que no requiere dieta previa y diferencia el origen del sangrado digestivo, todo por $65-$80 pesos por prueba.', 'Adiós al guayaco. Esta prueba es inmunocromatográfica (sin restricción dietética), con doble marcador (Hemoglobina + Transferrina) que diferencia sangrado alto vs bajo. Tu gastroenterólogo decide si pide endoscopia alta o colonoscopia BASADO en tu resultado. Eso es valor agregado.', 'El test de guayaco clásico requiere restricción dietética (3 días sin carnes rojas) y no diferencia el origen del sangrado. Esta prueba usa anticuerpos monoclonales específicos para hemoglobina humana, eliminando falsos positivos alimentarios y ofreciendo información diferencial (alto vs bajo) en 5 minutos.', 'Con un costo unitario de ~$65-$80, esta prueba orienta la decisión de solicitar colonoscopia o endoscopia (estudios de $5,000-$15,000 MXN), lo que la convierte en una herramienta de tamizaje altamente justificable y rentable.', 'Si tu laboratorio ofrece sangre oculta por guayaco, REEMPLÁZALO con esto. La inmunocromatografía no requiere dieta previa (el guayaco sí), es más específica (no reacciona a carnes rojas), y además diferencia sangrado alto de bajo. Tus gastroenterólogos van a preferirte frente al laboratorio que todavía usa guayaco.',
  '[{"pregunta":"¿El paciente debe dejar de comer carne 3 días antes y no cepillarse los dientes para no escupir sangre?","respuesta":"A diferencia del test de guayaco, esta prueba utiliza anticuerpos monoclonales anti-hemoglobina humana. No reacciona con sangre animal ingerida (carnes rojas), eliminando la necesidad de restricción dietética previa."}]'::jsonb, '[{"pregunta":"El guayaco me cuesta $5","respuesta":"** Y te genera falsos positivos alimentarios que confunden al médico y requieren repetición. A $65-$80 puedes cobrar $350+ por un resultado confiable sin dieta. El margen es mejor y la calidad superior."}]'::jsonb,
  '[{"name":"Prueba rápida H. pylori en Heces (Antígeno):","reason":"Si FOB sale positivo (hay sangrado GI), evaluar H. pylori como causa etiológica de úlcera sangrante es el protocolo gastroenterológico estándar. Un ensayo clínico taiwánes (JAMA, 2019) demostró que ambas pruebas en la misma muestra de heces cubren tracto GI alto y bajo.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-helicobacter-pylori-en-heces/"},{"name":"Prueba rápida FERRI-NET (Ferritina):","reason":"Si FOB sale positivo, significa sangrado crónico → pérdida de hierro → anemia. Evaluar ferritina cuantifica la consecuencia hematológica del sangrado. \"Panel de Anemia por Sangrado\" = FOB + Ferritina.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-ferritina/"},{"name":"CA 19-9 / AFP:","reason":"Para clientes oncológicos que quieren panel digestivo completo. URL CA 19-9: https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-19-9/ URL AFP: https://www.amunet.com.mx/tienda/prueba-rapida-de-afp/","url":null}]'::jsonb, '[{"name":"Kit de Pruebas Rápidas Tumorales:","reason":"Si FOB es positivo + paciente >50 años, el siguiente paso es evaluar marcadores tumorales (CA 19-9, AFP, CEA). \"Panel Oncológico Digestivo Completo.\"","url":"https://www.amunet.com.mx/tienda/kit-de-pruebas-rapidas-tumorales/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
