-- Product: Prueba BIONET MULTI PCR Rápida (RT-LAMP)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba BIONET MULTI PCR Rápida (RT-LAMP)', 'molecular', 'https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/', 'Tiras/Consumibles de Inmunoensayo Fluoresceína-Biotina', 'Amunet',
  2400, 120, 'NO APLICA de forma aislada. Forma parte de la factura integral del Ensayo Molecular "PCR RÁPIDO" cobrado globalmente (Desde $600.00 hasta $1,500.00 según la diana Viral VPH/VIH).', 'Significativo al combinar con kits específicos de amplificación. La tecnología LAMP elimina la necesidad de termocicladores costosos.', '[]'::jsonb,
  'Amplicones Moleculares/Fragmentos masificados Marcados por cebadores FAM (Fluoresceína) y FITC/Biotina (DNA/RNA diana ultra amplificado).', 'heces', NULL, 'De de 10 a 15 min *después de la lisis amplificada*.', NULL, NULL,
  NULL, '15°C a 30°C (Verificar inserto).', NULL, 'NOM-241 COFEPRIS , DLBIO01',
  'Visualizador Cromatográfico Molecular Dicotómico Cuasi-Confirmador', 'Tira reveladora visual para lectura de resultados de amplificación molecular isotérmica (LAMP/RPA). Tras la fase de amplificación en incubadora a 65°C, la tira detecta los amplicones mediante flujo lateral inmunocromatográfico (líneas de captura FAM/biotina). Permite al clínico visualizar el resultado molecular (positivo/negativo) sin necesidad de termocicladores, electroforesis ni fluorometría, democratizando el diagnóstico molecular para consultorios que no cuentan con infraestructura de laboratorio.', ARRAY['Clínicas Infectológicas HIV-VPH Premium', 'Laboratorios de Análisis Clínicos Periféricos que desean competir con corporativos de PCR', 'Epidemiólogos Rápidos de Campo (Tamizajes rurales y hospitalarios portátiles)'], '- **Infectólogo Moderno en Oficina VPH Positivo Confirmado en Ventana:** La paciente jura que su pareja tuvo una verruga extraña papilar en la boca hace una semana; la chica tiene el PAP negativo (Tarda años en ulcerar) pero la histería y terror la carcome. El "Doctor Gold" hisopa la boca, macera el ADN en 5 minutos en Lisis Mágnetica Amunet, mete al incubador de calor de su mesa por 40 min, destapa e introduce la TIRA BIONET; en 10 minutos se marcan dos franjas Rojas en consultorio: "Usted ya es portadora genética Molecular de Cáncer Virus de Papiloma genotipo agresivo que estallaría en meses" - La paciente llora y comienza terapias Oncovirulentas preventivas ese mismo día salvando su matriz gracias al peritaje de ADN Molecular Médico In-House de "Vanguardia Extrema".',
  'Pacientes con factores de riesgo para infecciones de transmisión sexual de alta relevancia clínica (VIH, VPH).', 'Para confirmar sospechas agudas inmunes negativas y como "Cierre Pericial".', 'Requiere seguimiento estricto del protocolo de 3 pasos (extracción → amplificación → visualización). La contaminación cruzada es el principal riesgo: usar guantes nuevos, área de trabajo limpia, y evitar aerosoles sobre los tubos para prevenir falsos positivos.', 'Informar Diagnóstico Estándar de ORO Biología Molecular Genómico; Intervención Clínica Inmediata Directa al protocolo más severo de especialidad Inmunóloga/VIH-SIDA Oncovirus.', 'El Paciente NO tiene ni un rastro o copia genética flotante del virus en estudio. Alta Certeza del más del 99% de libertad.',
  'Diagnóstico molecular (ADN/ARN) directamente en consultorio mediante tecnología LAMP portátil, sin necesidad de termocicladores ni infraestructura de laboratorio molecular. Resultados en menos de 1 hora.', 'Componente indispensable para tus kits VPH y VIH PCR de Amunet. Sin tiras Bionet, no puedes leer el resultado. Incluye siempre 1 tubo de tiras por cada kit molecular que compres.', 'Los laboratorios de referencia cobran $3,000-$5,000 por pruebas moleculares con resultados en 5-7 días. Con la plataforma Bionet LAMP, el costo de insumos ronda los $300-$500 y los resultados se obtienen en 1 hora, reteniendo tanto el margen como la relación con el paciente.', 'Costo de insumos por prueba: ~$300-$500 (extracción + primers + tira). Precio sugerido al paciente: $1,200-$2,500. Margen de 300-700%.', 'Si tu laboratorio va a ofrecer PCR rápida de VPH o VIH con los kits Amunet, las tiras Bionet son el componente obligatorio de lectura. Son como el "gel de agarosa" pero en formato de tira visual — sin necesidad de electroforesis ni fluorómetro.',
  '[{"pregunta":"¿Cómo es posible PCR de consultorio sin termociclar un equipo inmenso de la Universidad?","respuesta":"La tecnología LAMP (Loop-Mediated Isothermal Amplification) amplifica ADN a temperatura constante (~65°C) mediante desplazamiento de cadena, a diferencia del PCR convencional que requiere ciclos térmicos (94-60-72°C). Esto permite usar una incubadora simple en lugar de un termociclador de laboratorio."}]'::jsonb, '[{"pregunta":"¿Por qué comprar por separado?","respuesta":"** Porque las tiras son universales para CUALQUIER kit molecular Amunet. Un tubo de 20 tiras te sirve para 20 pruebas, ya sean VPH, VIH, o ambas."}]'::jsonb,
  '[{"name":"Kit PCR VPH (VPH-NET):","reason":"Las ampoletas de genética molecular específica para Virus del Papiloma Humano.","url":"https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/"},{"name":"Kit PCR VIH (VIHLAMP-NET):","reason":"Para detección molecular de ARN retroviral.","url":"https://www.amunet.com.mx/tienda/pcr-rapida-para-vih-1-y-2/"},{"name":"Incubadora Portable Amunet:","reason":"Sin la incubadora (60° a 65°C constantes), la biología molecular no funciona. Equipo indispensable.","url":"https://www.amunet.com.mx/tienda/incubadora-portable/"}]'::jsonb, '[{"name":"Kit PCR VPH + Kit PCR VIH:","reason":"Maximice la inversión en la plataforma Bionet con ambos kits moleculares. URL VPH: https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/ URL VIH: https://www.amunet.com.mx/tienda/pcr-rapida-para-vih-1-y-2/","url":null}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
