-- Product: Prueba PCR Rápida Diagnóstico de VPH (Virus de Papiloma Humano)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba PCR Rápida Diagnóstico de VPH (Virus de Papiloma Humano)', 'molecular', 'https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/', 'Kit Extractor y Amplificador Molecular Isotérmico DNA de Genotipos (VPH-NET)', 'Amunet',
  2650, 265, '$1,200.00 - $2,500.00', '350% - 800%.', '[]'::jsonb,
  'Ácido Desoxirribonucleico (ADN) perteneciente de la cepa del Virus Papiloma Humano. Detección de genotipos de alto riesgo oncogénico (HR-VPH): 16, 18, 31, 33 y 45.', 'Hisopado Frotis Cervical ginecológico, Uretral u d', NULL, 'Protocolo completo (extracción magnética + incubación a 65°C + lectura en tira): aproximadamente 40-60 minutos in situ.', NULL, NULL,
  NULL, NULL, NULL, 'NOM-241 COFEPRIS , DLVPH01',
  'Diagnóstico Molecular Oro Confirmador Preventivo de Oncología Genital', 'Prueba de detección molecular de ADN del Virus del Papiloma Humano en sus genotipos de alto riesgo oncológico (16, 18, 31, 33, 45). Mediante tecnología de amplificación isotérmica (LAMP), permite identificar infección por VPH en fase preclínica, complementando el Papanicolaou y la colposcopia en la prevención del cáncer cervicouterino. Especialmente útil cuando el citológico muestra atipia significación indeterminada (ASC-US).', ARRAY['Ginecológico VIP', 'Oncólogos Mastologos', 'Urólogos Especialistas en Papilomatosis Venérea', 'Clínicas Preventivas ETS Integrales'], '- **Consultorio Displásico VPH Premium Cérvix:** Paciente con contacto sexual de riesgo para VPH y citología normal solicita tipificación molecular. Se realiza hisopado cervical, extracción de ADN e incubación isotérmica (~55 min). Resultado en tira Bionet confirma genotipos de alto riesgo, permitiendo iniciar protocolo de seguimiento colposcópico y vigilancia estrecha el mismo día.',
  NULL, 'Recomendado 1 vez al año en Check Ups Femeniles de Vida Sexual Peligrosa Inestable, o cada "X 5 años a mayores de 25 sano según Guía Americana" como Tamizaje.', 'Requiere estricto seguimiento del protocolo de extracción paso a paso. A diferencia de las pruebas inmunocromatográficas de casete, esta prueba molecular es sensible a errores de técnica que manchen muestras cruzadas de polvo. Y debe acoplarse y facturar comprando las "Tiras Reveleadoras MultiBionet".', 'Referir a colposcopia para evaluación directa del cérvix. Según hallazgos, proceder con biopsia dirigida y/o tratamiento ablativo según protocolo clínico.', 'Ausencia de ADN de genotipos de alto riesgo. Repetir según guías clínicas (cada 3-5 años en mujeres >30 años).',
  'Detecte ADN de VPH de alto riesgo directamente en su consultorio ginecológico con tecnología molecular (LAMP) en aproximadamente 1 hora, sin necesidad de equipo de laboratorio costoso ni envío de muestras externas.', 'Deja de mandar VPH a referencia. Con el kit LAMP de Amunet, tu laboratorio hace tipificación molecular de VPH en 1 hora a $385 de insumo. El referenciamiento te cuesta ingresos y pacientes — retenlos.', 'Un laboratorio externo cobra $3,000-$5,000 por tipificación de VPH. Con el kit Bionet, el costo de insumos ronda los $300-$500, permitiendo ofrecer el servicio a $1,500-$2,500 con un margen significativo. La integración con colposcopia permite ofrecer diagnóstico molecular + evaluación visual en una sola consulta, reteniendo el valor completo del procedimiento sin necesidad de laboratorio externo.', NULL, 'Esto es ENORME para tu laboratorio. La tipificación de VPH por PCR convencional la mandas a referencia ($3,000-$5,000 al paciente, con resultado en 5-7 días). Con el kit Amunet, HACES LA PCR EN TU LABORATORIO por $385 de insumo y cobras $1,500-$2,500, resultado en 1 hora. No necesitas termociclador — la tecnología LAMP amplifica a temperatura constante con tu incubadora.',
  '[{"pregunta":"¿Necesito un microscopio o la ultra máquina PCR 4000 de tubos fríos caros?","respuesta":"No. El kit VPH-NET utiliza perlas magnéticas para extracción de ADN sin centrífuga. El proceso consiste en: extraer ADN, incubar a 65°C (incubadora Amunet portátil), y revelar en tira Bionet MULTI. Sin termocicladores ni equipamiento de laboratorio molecular."}]'::jsonb, '[{"pregunta":"Necesito un termociclador","respuesta":"** NO. La tecnología LAMP amplifica a 65°C constantes. Tu incubadora Amunet porta­til ($2,500-$5,000) reemplaza un termociclador de $20,000 USD. Cero inversión en equipamiento pesado."},{"pregunta":"¿Es tan sensible como mi referencia?","respuesta":"** La amplificación LAMP tiene sensibilidad comparable a PCR convencional para detección cualitativa. Para tipificación cuantitativa o genotipificación extendida (>5 genotipos), el laboratorio de referencia sigue siendo necesario. Pero para detección cualitativa de alto riesgo (16, 18, 31, 33, 45), este kit cubre el 80% de tu demanda."}]'::jsonb,
  '[{"name":"Tiras Reveladoras BIONET MULTI:","reason":"Componente indispensable para la lectura visual de los resultados de amplificación molecular.","url":"https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/"},{"name":"Combo VIH/Sífilis:","reason":"Criba ginecológica integral: PCR VPH (cervix) + serológica VIH/Sífilis (prenatal) = \"Panel Check-Up Zero Risk\".","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"Incubadora Portable Amunet:","reason":"Equipo indispensable para la amplificación isotérmica LAMP.","url":"https://www.amunet.com.mx/tienda/incubadora-portable/"},{"name":"Cepillo para Muestras Cervicales:","reason":"ESENCIAL. La calidad de la muestra determina el resultado. El cepillo Amunet tiene punta suave que no lastima y recoge más células.","url":"https://www.amunet.com.mx/tienda/cepillo-para-muestras-cervicales/"}]'::jsonb, '[{"name":"Kit de Pruebas Rápidas Tumorales (CA-125 + CA 15-3):","reason":"\"Panel Onco-Ginecológico Integral\": VPH PCR (cérvix) + CA-125 (ovario) + CA 15-3 (mama) = prevención oncológica completa. URL CA-125: https://www.amunet.com.mx/tienda/prueba-rapida-antigeno-ca-125/ URL CA 15-3: https://www.amunet.com.mx/tienda/prueba-rapida-de-antigeno-ca-153/","url":null}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
