-- Product: Prueba PCR Rápida Diagnóstico de VIH 1 y 2
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba PCR Rápida Diagnóstico de VIH 1 y 2', 'molecular', 'https://www.amunet.com.mx/tienda/pcr-rapida-para-vih-1-y-2/', 'Kit Extractor y Amplificador Molecular Isotérmico RNA Retroviral (VIHLAMP-NET)', 'Amunet',
  10, NULL, '$1,500.00 - $3,000.00 (El Cierre del Peritaje final Infectológico).', 'Significativo (+400%).', '[]'::jsonb,
  'Ácido Ribonucleico (ARN) del Virus de la Inmunodeficiencia Humana tipos 1 y 2.', 'sangre_total', NULL, 'Protocolo "Extracción ARN" + lisis térmica + 5 a 10 min de revelado visual de tiras. Tiempo total aproximado: 1 hora.', NULL, NULL,
  NULL, NULL, NULL, 'DLVIH01 (etiquetado UPI — Uso para Investigación)',
  'Prueba auxiliar de detección molecular temprana (uso en investigación)', 'Prueba de detección molecular de ARN retroviral del VIH-1 y VIH-2 mediante amplificación isotérmica. Su principal ventaja frente a las pruebas serológicas (anticuerpos/antígenos) es la capacidad de detectar la infección en fase temprana (período de ventana), cuando las pruebas inmunológicas convencionales aún no son reactivas. Esto es especialmente relevante en exposiciones recientes de alto riesgo. **Nota importante:** Esta prueba es para uso en investigación. Para el diagnóstico formal de VIH, deben seguirse los algoritmos establecidos por la NOM-010-SSA2 y guías de CENSIDA (prueba rápida inicial + confirmatoria por laboratorio de referencia).', ARRAY['Infectología', 'Clínicas especializadas en ITS', 'Epidemiología (programas PrEP/PEP)', 'Urgencias'], '- **Evaluación post-exposición de alto riesgo:** Paciente con exposición sexual de alto riesgo reciente (<72 horas). La prueba serológica convencional resulta no reactiva (esperado en periodo de ventana). La PCR molecular permite detectar ARN viral antes de la seroconversión, orientando la decisión de iniciar profilaxis post-exposición (PEP) con antirretrovirales de forma oportuna.',
  NULL, 'Ante exposición reciente de alto riesgo donde las pruebas serológicas aún están en periodo de ventana.', 'El ARN viral es sensible a degradación por RNasas ambientales. El manejo de muestra requiere técnica aséptica estricta (guantes, ambiente limpio). No apto para ambientes contaminados si no se sigue el protocolo molecular. **Esta prueba es para uso en investigación y no sustituye el algoritmo diagnóstico de la NOM-010-SSA2.**', 'Referir a la red COESIDA/CAPASIT para confirmación y seguimiento. Iniciar terapia antirretroviral según protocolo. Apoyo psicológico. Notificación epidemiológica obligatoria.', 'Resultado orientador negativo. Informar al paciente sobre la importancia de pruebas de seguimiento a los 30, 60 y 90 días. Reforzar medidas preventivas.',
  'Acorte el periodo de ventana diagnóstico del VIH con detección molecular de ARN viral en su consultorio, obteniendo resultados orientadores en aproximadamente 2 horas para casos de exposición reciente de alto riesgo.', 'PCR de VIH en tu laboratorio a $300-$500 de insumo. Los corporativos cobran $5,000+. Recupera el diferencial y posiciónate como laboratorio con capacidad molecular.', 'Los laboratorios de referencia cobran $3,000-$8,000 por carga viral molecular con resultados en días. Con la plataforma Bionet LAMP, el clínico obtiene un resultado orientador en ~1 hora, reteniendo al paciente y sus honorarios en el consultorio.', NULL, 'Si tu laboratorio recibe pacientes con exposición reciente de alto riesgo, la prueba serológica puede estar en periodo de ventana (no reactiva). La PCR molecular detecta ARN viral ANTES de la seroconversión. Los laboratorios de referencia cobran $3,000-$8,000 por carga viral molecular. Con este kit, tu costo es $300-$500.',
  '[{"pregunta":"¿El test reemplaza a un recuento de Western Blot Confirmador a Ciegas por Gobierno?","respuesta":"Legalmente la salud pública sigue guías tradicionales obsoletas anticuadas que el gobierno norma en pasos largos de crujir los dientes tardíos; en Medicina Privada Eficaz Rápida la biológia Molecular de PCR que posee en sus manos (Bionet VIH) ha destronado al viejo occidente anticuperpo entregando dictamines más veloces de Oro permitiendo a Usted medicarlo (Con PEP preexposición e interrupción) que es lo valioso del asunto, antes que el Virus gane su sistema central mientras usted rogaba cita burocrática del seguro gratuito a 60 días."}]'::jsonb, '[{"pregunta":"Es UPI, ¿puedo ofrecerlo?","respuesta":"** Es para uso en investigación. Puedes ofrecerlo como prueba orientativa complementaria. El diagnóstico formal sigue la NOM-010-SSA2 (prueba rápida + confirmatoria). La PCR molecular complementa el algoritmo para casos de exposición reciente."}]'::jsonb,
  '[{"name":"Tiras Bionet MULTI:","reason":"Componente indispensable para la lectura visual de resultados de amplificación molecular.","url":"https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/"},{"name":"Combo VIH/Sífilis:","reason":"VIH positivo genético asolpado con treponemas: descartar sífilis con casete rápido en 5 min.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"Kit PCR VPH:","reason":"Complemento molecular ginecológico.","url":"https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/"},{"name":"VIH 4ta Generación:","reason":"Tamizaje serológico rápido complementario.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-vih-4ta-generacion/"}]'::jsonb, '[{"name":"Combo VIH/Sífilis + Prueba de Tuberculosis:","reason":"En VIH positivo, sífilis y TB son coinfecciones obligatorias de tamizar (guías OMS). \"Panel Coinfecciones VIH\". URL TB: https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/ URL VIH/Sífilis: https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/","url":null}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
