-- Product: Prueba rápida de Antidoping (Detección de 5 drogas de abuso en Saliva)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antidoping (Detección de 5 drogas de abuso en Saliva)', 'drogas', 'https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-en-saliva/', 'Perfil Múltiple Competitivo Inmunológico (Frotis en Saliva Orla)', 'Amunet',
  308, 138.6, '$350.00 - $600.00 (Por evaluado en tamizaje ocupacional).', '150% - 300% (La facturación se da por Volumen Industrial "Examen Físico de 50 empleados por turno" con una facturación general alta).', '[{"cantidad":2,"precio":308},{"cantidad":5,"precio":730},{"cantidad":10,"precio":1386}]'::jsonb,
  'Marihuana (THC), Anfetamina (AMP), Cocaína (COC), Opioides/Heroína (OPI) y Metanfetaminas/Cristal (MET). Metabolitos o droga activa excretada fluidamente al epitelio bucal.', 'saliva', '"Llenado visible de la esponja salival de succión" incrustada mecánicamente en los viales rotulados estériles.', 'Rápido; en unos 15 min de saturación vertical.', 95, 95,
  'Detección por inmunoensayo competitivo (THC: 35 ng/mL; AMP: 50 ng/mL; COC: 50 ng/mL; OPI: 40 ng/mL; MET: 50 ng/mL). **Interpretación inversa:** línea visible = negativo (no se detecta droga), línea ausente = positivo (droga detectada por encima del corte).', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', '(Antidoping, NOM-241 COFEPRIS DMADB01)',
  'Tamizaje Toxicológico Rápido No Invasivo', 'Prueba de detección de 5 drogas de abuso (THC, AMP, COC, OPI, MET) en saliva. La principal ventaja de la muestra salival frente a la urinaria es la toma supervisada sin necesidad de instalaciones sanitarias, la eliminación del riesgo de adulteración de muestra, y la detección de consumo reciente (últimas 24-72 horas). Ideal para entornos de salud ocupacional, operativos de seguridad vial y programas antidoping donde la logística de recolección de orina es compleja.', ARRAY['Medicina de Salud Ocupacional', 'Recursos Humanos (tamizaje laboral)', 'Toxicología', 'Seguridad Vial'], '- **Tamizaje de ingreso laboral:** En una jornada de reclutamiento con 30+ candidatos, la prueba salival permite aplicar el tamizaje directamente en la sala de espera, sin necesidad de baños o recolectores de orina. La toma supervisada elimina el riesgo de adulteración de muestra, un problema frecuente con las pruebas urinarias.',
  'Trabajadores operativos, operadores de maquinaria pesada, conductores de transporte, candidatos a ingreso laboral, personas en programas de rehabilitación.', 'Tamizaje aleatorio programado en empresas o screening pre-ingreso laboral.', 'La ventana de detección en saliva es más corta que en orina (1-3 días vs. hasta 30 días para THC en orina). Es ideal para detectar consumo reciente, no consumo histórico. En pacientes con xerostomía (boca seca, común en consumidores de metanfetaminas), la recolección puede ser lenta; ofrecer enjuague con agua 10 minutos antes. **Un resultado positivo reactivo debe confirmarse por cromatografía de gases/espectrometría de masas (GC-MS) para validez legal en procesos de despido.**', 'Línea ausente en uno o más parámetros = resultado reactivo. Proceder según protocolo ocupacional: suspensión preventiva y envío de muestra confirmatoria a laboratorio de referencia (GC-MS) si se requiere validez legal.', 'Todas las líneas visibles = resultado no reactivo. El evaluado puede continuar en funciones según protocolo ocupacional.',
  'Realice tamizajes antidoping de 5 parámetros directamente en campo, sala de juntas o caseta de seguridad, sin necesidad de baños ni riesgo de adulteración, a un costo de ~$140 por prueba.', 'Ofrece servicio de "antidoping en sitio" a empresas. Tú mandas al técnico con el kit salival, toma supervisada sin baños, resultado en 15 min. Factura por servicio a domicilio + prueba. Doble ingreso.', 'Un antidoping en laboratorio externo cuesta $800+ con espera de días y riesgo de adulteración de muestra. Aplicando la prueba salival directamente en la empresa (sala de juntas, caseta), se eliminan estos riesgos y se procesan docenas de evaluados por hora con un solo aplicador capacitado, a un costo de ~$140 por prueba.', NULL, 'Tu laboratorio probablemente ya ofrece antidoping en orina. La versión salival es tu servicio complementario para clientes corporativos que requieren tamizaje IN SITU (en planta, en oficina, sin baños). La toma supervisada elimina adulteración — el argumento principal del RH.',
  '[{"pregunta":"¿Pero las rayas están pintadas o borradas? ¡Salieron rojo pero dicen que es mariguano!","respuesta":"Capacitar al personal aplicador en la interpretación inversa: línea visible = negativo (no se detecta droga), línea ausente = positivo (droga detectada). Esto es común a todas las pruebas de inmunoensayo competitivo."},{"pregunta":"¿Por qué no detectó consumo de hace una semana?","respuesta":"La saliva detecta consumo reciente (24-72 horas). Para detectar consumo histórico (hasta 30 días para THC), utilice las tiras de orina. Seleccione la matriz de muestra según la ventana de detección requerida."}]'::jsonb, '[{"pregunta":"Ya ofrezco orina","respuesta":"** La saliva no sustituye la orina — la complementa. Saliva = consumo reciente + toma supervisada + sin baños. Orina = consumo histórico + mayor ventana. Ofrece ambas y deja que el cliente elija."}]'::jsonb,
  '[{"name":"Combo VIH/Sífilis:","reason":"Complemento para examen médico pre-ingreso integral. Tamizaje de VIH + sífilis junto con antidoping en una sola visita.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/"},{"name":"Prueba rápida de Fentanilo Individual:","reason":"Para programas antidoping institucionales que requieren detección de opioides sintéticos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/"},{"name":"Antidoping 5 Sangre:","reason":"Para urgencias donde el paciente no coopera.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-thc-coc-amp-met-y-opi/"}]'::jsonb, '[{"name":"Combo VIH/Sífilis + Tuberculosis:","reason":"En VIH positivo, sífilis y TB son coinfecciones obligatorias de tamizar (guías OMS). \"Panel Coinfecciones VIH\" = molecular + serológico + TB. URL TB: https://www.amunet.com.mx/tienda/prueba-rapida-de-tuberculosis/ URL VIH/Sífilis: https://www.amunet.com.mx/tienda/prueba-rapida-de-vih-sifilis-combo/","url":null}]'::jsonb, ARRAY['Antidoping saliva laboratorio corporativo in situ supervisado 5 parámetros'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
