  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antidoping 3 Parámetros (THC, AMP y COC) en Saliva', 'drogas', 'https://www.amunet.com.mx/tienda/prueba-de-antidoping-3-parametros-thc-coc-y-amp-en-saliva/', 'Perfil Múltiple Competitivo Inmunológico (Frotis en Saliva Oral)', 'Amunet',
  970, 97, '$250.00 - $400.00 (Por evaluado en tamizaje ocupacional o escolar).', '150% - 300%', '[{"cantidad":10,"precio":970}]'::jsonb,
  'Marihuana (THC), Anfetamina (AMP) y Cocaína (COC). Metabólitos excretados en fluidos orales.', 'saliva', 'Saturación visible de la esponja absorbente del dispositivo.', '15 minutos.', 95, 95,
  'Detección por inmunoensayo competitivo (AMP: 80 ng/mL; COC: 50 ng/mL; THC: 35 ng/mL). **Interpretación inversa:** línea visible = negativo, línea ausente = positivo.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMACT02',
  'Tamizaje Toxicológico Rápido No Invasivo (3 parámetros)', 'Prueba económica de detección de las 3 principales drogas recreativas (THC, Cocaína, Anfetaminas) en saliva. Diseñada para entornos escolares, programas de prevención juvenil y operativos de transporte donde no se requiere cobertura de opiáceos ni metanfetaminas. La muestra salival preserva la dignidad del evaluado y elimina la logística de recolección urinaria.', ARRAY['Médicos escolares', 'Salud Ocupacional (transporte', 'industria)', 'Programas de rehabilitación ambulatoria'], '- **Operativo Escolar Mochila Segura en Prepa:** Un programa escolar de prevención solicita tamizaje anónimo a estudiantes con indicadores de riesgo. La prueba salival se aplica de forma rápida y discreta en consultorio escolar. La muestra no puede ser adulterada. El resultado orienta la intervención preventiva y la canalización oportuna.',
  'Estudiantes en programas de prevención, operadores de transporte, candidatos a ingreso laboral en puestos operativos.', 'Operativos periódicos de prevención, tamizaje de ingreso, seguimiento post-vacacional.', 'La ventana de detección salival es corta (24-48 horas). No detecta consumo de más de 3 días. Para detectar consumo histórico (hasta 30 días para THC), utilice las tiras de orina Amunet.', 'Línea ausente = resultado reactivo. Proceder según protocolo institucional (confirmación por GC-MS si se requiere validez legal).', 'Todas las líneas visibles = resultado no reactivo para los 3 analitos.',
  'Tamizaje antidoping de 3 parámetros (THC, COC, AMP) en saliva a $97 por prueba. Ideal para programas escolares y flotillas de transporte donde no se requiere cobertura de opiáceos ni metanfetaminas.', 'A $97 por prueba, es tu opción de mayor volumen para contratos escolares y de transporte. Cotiza en paquete: "100 tamizajes a $200 c/u" = $20,000 de ingreso, $9,700 de costo.', 'El antidoping en laboratorio externo permite al evaluado prepararse o intentar adulteración. La prueba salival Amunet se aplica in situ, sin previo aviso, eliminando el riesgo de manipulación y reduciendo costos de logística.', NULL, 'Versión económica para clientes que solo necesitan las 3 principales: marihuana, cocaína y anfetaminas. Ideal para escuelas/universidades y flotillas de transporte donde opiáceos y metanfetaminas no son prioridad.',
  '[{"pregunta":"¿Detecta fentanilo y metanfetamina?","respuesta":"No. Para cobertura de opiáceos y metanfetaminas, utilice el Antidoping de 5 parámetros. El panel de 3 es ideal para entornos donde THC, cocaína y anfetaminas son las sustancias de mayor prevalencia."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Fentanilo Individual:","reason":"El fentanilo no se incluye en los paneles estándar. Complementar con tira de fentanilo ante sospecha de opioides sintéticos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/"},{"name":"Antidoping 5 Saliva:","reason":"Upgrade si el cliente necesita MET y OPI.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-en-saliva/"}]'::jsonb, '[{"name":"Prueba de Antidoping 5 Parámetros en Saliva:","reason":"Upgrade de 3 a 5 parámetros para cubrir opiáceos y metanfetaminas. Cuesta poco más pero amplía cobertura significativamente.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-en-saliva/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
