-- Product: Prueba rápida de Antidoping de 5 Parámetros SANGUÍNEO (Panel Múltiple SANGRE)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Antidoping de 5 Parámetros SANGUÍNEO (Panel Múltiple SANGRE)', 'drogas', 'https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-thc-coc-amp-met-y-opi/', 'Perfil Múltiple Competitivo Inmunológico (Sangre Capilar/Suero/Plasma)', 'Amunet',
  285, 129, '$400.00 - $600.00', '180% - 360%', '[{"cantidad":2,"precio":285},{"cantidad":5,"precio":675},{"cantidad":10,"precio":1291}]'::jsonb,
  'Marihuana (THC), Anfetamina (AMP), Cocaína (COC), Opiáceos (OPI) y Metanfetaminas (MET) en sangre.', 'sangre_total', '3 gotas de sangre total (~80 µL) + 2 gotas de buffer', '15 minutos.', 95, 95,
  'Detección por inmunoensayo competitivo. Cortes sanguíneos: THC ~25 ng/mL; AMP ~25-100 ng/mL; COC ~20 ng/mL; OPI ~10-200 ng/mL; MET ~0.5-100 ng/mL. **Interpretación inversa:** línea visible = negativo, línea ausente = positivo.', '15°C a 30°C', 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMADS01',
  'Tamizaje Toxicológico de Urgencia en Sangre (5 parámetros)', 'Prueba de detección de 5 drogas de abuso (THC, AMP, COC, OPI, MET) en sangre. A diferencia de las versiones en saliva u orina, la muestra sanguínea es obligatoria cuando el paciente está inconsciente, sedado o no cooperativo (urgencias, triage de trauma, intoxicación aguda). La detección en sangre confirma exposición activa sistemica al momento de la toma, lo que tiene valor pericial y toxicológico en urgencias y medicina legal.', ARRAY['Urgencias', 'Medicina Legal y Forense', 'Paramédicos (ambulancias)', 'Terapia Intensiva'], '- **Reanimación de Triage Comatoso:** Paciente joven ingresa a urgencias con taquicardia, diaforesis y alteración del estado de consciencia tras evento recreativo. No puede cooperar para muestra de orina o saliva. Con punción digital se obtiene resultado en 15 minutos, identificando opiáceos y/o metanfetaminas, orientando la decisión terapéutica (naloxona vs. benzodiacepinas) y documentando el expediente clínico.',
  'Pacientes inconscientes, sedados o no cooperativos con sospecha de intoxicación aguda por sustancias de abuso.', 'Ante paciente con alteración del estado de consciencia de causa desconocida, sospecha de intoxicación aguda, o evaluación médico-legal de conducción bajo influencia.', 'La detección en sangre confirma consumo activo al momento de la toma. La ventana de detección sanguínea es más corta que la urinaria (cocaína: ~24h; THC: días; metanfetaminas: 1-3 días). Es la matriz indicada para documentar intoxicación aguda con valor pericial. Para detección de consumo histórico, utilice las pruebas en orina.', 'Línea ausente = sustancia detectada en sangre (exposición activa). Iniciar manejo toxicológico según analito identificado (naloxona para opiáceos, soporte para estimulantes).', 'Todas las líneas visibles = no se detectan las 5 sustancias evaluadas. Considerar otras causas de alteración neurológica: traumatismo craneoencefálico, neuroinfección, epilepsia, trastorno metabólico.',
  'Identifique en 15 minutos qué sustancia de abuso está causando la intoxicación aguda de su paciente inconsciente, utilizando una muestra de sangre capilar. Oriente el tratamiento específico y documente el expediente con valor pericial.', 'Para laboratorios hospitalarios:** Si tu laboratorio atiende urgencias, necesitas antidoping sanguíneo. Es la ÚNICA opción cuando el paciente no coopera. Resultado en 15 min con la misma muestra del flebotomista.', 'Un panel toxicológico en laboratorio externo cuesta >$1,000 y tarda días. En urgencias, ese tiempo no existe. Esta es la única opción de tamizaje rápido para pacientes que no pueden cooperar (inconscientes, intubados, agitados), convirtiéndola en herramienta esencial del triage toxicológico.', NULL, 'La versión sanguínea es para urgencias: paciente inconsciente, sedado, intubado. No puede escupir ni orinar. La sangre confirma exposición activa sistémica al momento de la toma — tiene valor pericial.',
  '[{"pregunta":"¿Puedo usar la misma muestra de la biometría hemática?","respuesta":"Sí. Aproveche el tubo EDTA del flebotomista de urgencias, separe el plasma y aplíquelo al cartucho. Esto evita una segunda punción al paciente."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Prueba rápida de Fentanilo Individual:","reason":"Si se detectan opiáceos, agregar fentanilo para descartar opioides sintéticos adulterados.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/"}]'::jsonb, '[{"name":"Prueba rápida de Fentanilo Individual:","reason":"Los paneles estándar NO detectan fentanilo sintético. Complementar con tira de fentanilo = cobertura toxicológica completa.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
