-- Product: Tiras Antidoping de Detección de 5 Parámetros en Orina
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Tiras Antidoping de Detección de 5 Parámetros en Orina', 'metabolicas', 'https://www.amunet.com.mx/tienda/tiras-antidoping-deteccion-de-5-parametros-en-orina/', 'Tiras/Consumibles de Inmunoensayo Competitivo Individual (Tiras por Parámetros Orina)', 'Amunet',
  618, 12.36, '$100.00 - $150.00 por aplicación individual.', '700% - 1100%', '[]'::jsonb,
  'Marihuana (THC), Anfetamina (AMP), Cocaína (COC), Opiáceos (OPI) y Metanfetaminas (MET) — metabolitos renales.', 'orina', 'Sumergir la tira hasta la marca de nivel máximo por 10-15 segundos.', '5 a 10 minutos.', 95, 95,
  'Detección por inmunoensayo competitivo. **Interpretación inversa:** línea visible = negativo, línea ausente = positivo.', '15°C a 30°C', NULL, 'NOM-241 COFEPRIS , DMADO02',
  'Tamizaje Toxicológico Modular en Orina (Tiras Individuales)', 'Tiras individuales por parámetro para detección de drogas en orina. La ventana de detección urinaria es significativamente más amplia que la salival (THC: hasta 30 días en consumidores crónicos; cocaína: 2-4 días; anfetaminas: 1-3 días). Ideal para tamizaje donde se requiere detectar consumo histórico, no solo reciente. El formato de tiras individuales permite seleccionar y combinar solo los analitos necesarios según el perfil del evaluado, optimizando el costo.', ARRAY['Toxicología Forense', 'Centros de Rehabilitación', 'Medicina Deportiva (control antidoping)', 'Salud Ocupacional (tamizaje de alto volumen)', 'Ministerio Público (pruebas periciales)'], '- **Centro de Rehabilitación / Seguimiento individualizado:** En un programa de rehabilitación, se conoce la droga de preferencia de cada paciente. En lugar de aplicar un panel completo, se utiliza únicamente la tira correspondiente (ej. THC para cannabis, COC para cocaína), reduciendo el costo a ~$12 pesos por prueba. Permite monitoreo frecuente (semanal) sin impacto presupuestal significativo.',
  'Pacientes en centros de rehabilitación, deportistas en programas antidoping, candidatos a ingreso laboral.', 'Tamizaje periódico (mensual a anual) según protocolo institucional. La ventana de detección extendida en orina permite identificar consumo histórico.', 'El riesgo principal de las pruebas en orina es la sustitución o adulteración de muestra. Se recomienda supervisión directa de la toma según protocolos de cadena de custodia (NOM-174-SSA1) cuando se requiere validez legal.', 'Línea ausente = resultado reactivo para ese analito. Proceder según protocolo institucional (confirmación por GC-MS si se requiere validez legal).', 'Línea visible = resultado no reactivo. El evaluado cumple con los criterios de tamizaje para ese analito.',
  'Tamizaje antidoping modular a ~$12 por tira. Seleccione solo los analitos relevantes según el perfil del evaluado, optimizando costos sin sacrificar cobertura.', 'Para laboratorios de rehabilitación/forense:** Tamizaje modular a $12 por tira. Elige solo los analitos que necesitas. Para contratos de seguimiento semanal, el ahorro es enorme comparado con paneles completos.', 'Un perfil toxicológico de 5 parámetros en laboratorio externo cuesta $600-$800. Con las tiras Amunet, el costo total por las 5 es ~$62, permitiendo un margen significativo por cada evaluación.', NULL, 'A $12.36 POR TIRA, estas son tu arma de alto volumen. Los centros de rehabilitación y programas de seguimiento te piden tamizaje semanal de un solo analito (ej. solo THC para el paciente de cannabis). En vez de gastar un panel completo de $140, usas UNA tira de $12. Multiplica eso por 50 pacientes semanales.',
  '[{"pregunta":"¿Qué pasa si la muestra fue adulterada?","respuesta":"La adulteración con sustancias químicas (lejía, cloro) altera el pH y produce tiras inválidas (coloración anormal). Esto es detectable y requiere una segunda toma supervisada. Se recomienda verificar temperatura de la muestra (32-38°C) como control adicional."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Tira Individual THC:","reason":"THC es el analito de mayor demanda. Para alto volumen, considere la Tira Individual THC (50 pzas) como reposición frecuente.","url":"https://www.amunet.com.mx/tienda/tira-para-deteccion-de-marihuana-thc/"},{"name":"Prueba rápida de Fentanilo:","reason":"Complemento para tamizaje de opioides sintéticos.","url":"https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/"}]'::jsonb, '[{"name":"Prueba de Antidoping 5 Parámetros en Saliva:","reason":"Upgrade a panel integral en saliva: supervisión fácil, 5 analitos en un dispositivo, sin baños.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-en-saliva/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
