-- Product: Prueba rápida de Fentanilo Individual
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Prueba rápida de Fentanilo Individual', 'drogas', 'https://www.amunet.com.mx/tienda/prueba-rapida-de-fentanilo/', 'Tira Inmunoensayo Competitiva Única (Orina)', 'Amunet',
  1200, 24, '$200.00 - $300.00 (Tamizaje toxicológico especializado en opioides sintéticos).', '700% - 1100%', '[]'::jsonb,
  'Fentanilo (norfentanilo como metabolito). Opioide sintético con potencia 50-100x superior a la morfina.', 'orina', 'Sumergir la lengüeta estriada.', 'Rápido; en unos 10 min.', NULL, NULL,
  'Detección por inmunoensayo competitivo. Corte: 20 ng/mL. **Interpretación inversa:** línea visible = negativo, línea ausente = positivo.', NULL, 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMFEN01',
  'Tamizaje Toxicológico Específico para Opioides Sintéticos (Fentanilo)', 'Tira específica para detección de fentanilo en orina. El fentanilo es un opioide sintético con potencia 50-100 veces mayor que la morfina. Los paneles estándar de opiáceos frecuentemente no detectan opioides sintéticos. Esta tira detecta específicamente norfentanilo (metabolito) a un corte de 20 ng/mL. Especialmente relevante en: intoxicación aguda donde se sospecha adulteración de sustancias, urgencias toxicológicas, y programas de reducción de daños.', ARRAY['Medicina Forense (SEMEFO)', 'Toxicología de Urgencias', 'Paramédicos', 'Programas de Reducción de Daños (Secretaría de Salud)'], '- **Intoxicación aguda por sustancia adulterada:** Paciente joven ingresa a urgencias con depresión respiratoria severa tras consumo recreativo. Refiere haber consumido "éxtasis", pero el cuadro clínico sugiere intoxicación por opioides. Se aplica la tira de fentanilo en orina: resultado positivo confirma adulteración de la sustancia con fentanilo. Se administra naloxona de forma inmediata, orientando el tratamiento y documentando el caso para notificación epidemiológica.',
  NULL, NULL, NULL, NULL, NULL,
  'Detecte fentanilo en orina en 10 minutos. Herramienta esencial para urgencias toxicológicas, medicina forense y programas de reducción de daños ante la creciente prevalencia de opioides sintéticos adulterados.', 'Los paneles estándar de opiáceos te dan falsos negativos para fentanilo porque detectan opiáceos naturales (morfina, codeína), no sintéticos. Esta tira detecta ESPECÍFICAMENTE norfentanilo. A $24/tira, no hay razón para no tenerla.', 'Un análisis toxicológico forense completo tarda semanas. Esta tira permite identificar fentanilo in situ en minutos, orientando la dosis de naloxona y documentando el hallazgo en el expediente clínico, todo a un costo de $24 por tira.', NULL, 'Los paneles estándar de opiáceos NO detectan fentanilo. Si tu laboratorio atiende urgencias, medicina forense o programas de reducción de daños, esta tira es indispensable. El fentanilo es la primera causa de muerte por sobredosis en frontera norte.',
  '[{"pregunta":"¿Puede usarse para analizar sustancias decomisadas?","respuesta":"La prueba está validada para orina humana. Sin embargo, programas de reducción de daños disuelven pequeñas muestras de sustancias en agua destilada y aplican la tira como screening orientativo de adulteración con fentanilo. Este uso es extraoficial."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Tiras Antidoping 5 Parámetros en Orina:","reason":"En intoxicación severa, el policonsumo es la norma. Combine fentanilo + tiras de 5 parámetros para cobertura completa.","url":"https://www.amunet.com.mx/tienda/tiras-antidoping-deteccion-de-5-parametros-en-orina/"},{"name":"Antidoping Sangre 5:","reason":"Para pacientes inconscientes.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-thc-coc-amp-met-y-opi/"}]'::jsonb, '[{"name":"Prueba de Antidoping 5 Parámetros Sanguíneo:","reason":"Paciente intoxicado puede tener polisustancias — fentanilo solo detecta UNA droga. El panel sanguíneo cubre el espectro completo.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-5-parametros-thc-coc-amp-met-y-opi/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
