  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Tira para Detección de Marihuana THC Individual', 'drogas', 'https://www.amunet.com.mx/tienda/tira-para-deteccion-de-marihuana-thc/', 'Tira Inmunoensayo Competitiva Única (Orina)', 'Amunet',
  630, 12.6, '$100.00 - $200.00 por aplicación individual.', '600% - 1500%', '[]'::jsonb,
  'Tetrahidrocannabinol (THC) — metabolitos urinarios. Compuesto lipofílico con acumulación en tejido adiposo, lo que extiende la ventana de detección.', 'orina', NULL, NULL, NULL, NULL,
  NULL, NULL, 'Estable hasta la fecha de caducidad impresa en el empaque (consultar etiqueta del lote específico)', 'NOM-241 COFEPRIS , DMTHC02',
  'Tamizaje Toxicológico Individual para Cannabis (THC) en Orina', 'Tira individual para detección de THC (cannabis) en orina. La ventana de detección de THC en orina es la más amplia entre las drogas de abuso: 2-4 días en consumo ocasional, 7-15 días en consumo regular, y hasta 30+ días en consumo crónico o personas con alto índice de grasa corporal (el THC es lipofílico). Ideal para programas escolares de prevención, consultas de psiquiatría juvenil y control de ingreso laboral donde cannabis es la droga principal de preocupación.', ARRAY['Psiquiatría', 'Médicos escolares', 'Salud Ocupacional (control de operadores)', 'Centros de rehabilitación'], '- **Tamizaje escolar enfocado:** En un programa escolar de prevención donde cannabis es la sustancia de mayor prevalencia, no es necesario aplicar un panel de 5 parámetros. Con una tira individual de THC a ~$12, se realiza el tamizaje enfocado con el menor costo posible, permitiendo cubrir alto volumen de evaluados dentro del presupuesto del programa.',
  NULL, NULL, NULL, NULL, NULL,
  'Tira individual de THC a ~$12 con ventana de detección de hasta 30 días en consumidores crónicos. Ideal para programas de prevención escolar y seguimiento en rehabilitación donde cannabis es la sustancia principal de preocupación.', 'Tubo de 50 tiras THC para reposición rápida. Si procesas 20+ antidopings semanales, el THC se te acaba primero. Este tubo individual te mantiene en stock.', 'En consulta de psiquiatría o medicina familiar, los padres solicitan tamizaje de sus hijos. Con un costo de $12 por tira, se integra fácilmente a la consulta como servicio adicional, generando valor clínico y un margen atractivo.', NULL, 'THC es el analito de mayor demanda en antidoping. Si tu laboratorio consume muchas tiras de THC (rehabilitación, escolar, laboral), este tubo de 50 tiras dedicadas es tu reposición frecuente.',
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Tira para Detección de Cocaína COC Individual:","reason":"Complemento natural si se sospecha policonsumo.","url":"https://www.amunet.com.mx/tienda/tira-para-deteccion-de-cocaina-coc/"},{"name":"Tiras Orina 5 params:","reason":"Para clientes que necesitan panel completo.","url":"https://www.amunet.com.mx/tienda/tiras-antidoping-deteccion-de-5-parametros-en-orina/"},{"name":"Antidoping Saliva 3:","reason":"Complemento salival para consumo reciente.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-3-parametros-thc-coc-y-amp-en-saliva/"}]'::jsonb, '[{"name":"Prueba de Antidoping 3 Parámetros en Saliva (THC, AMP, COC):","reason":"Si necesita más que THC, la saliva de 3 parámetros cubre marihuana + cocaína + anfetamina con toma supervisada.","url":"https://www.amunet.com.mx/tienda/prueba-de-antidoping-3-parametros-thc-coc-y-amp-en-saliva/"}]'::jsonb, ARRAY['THC marihuana tira orina laboratorio alto volumen reposición cannabis'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
