  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Incubadora Portable PI2500AB', 'equipos', 'https://www.amunet.com.mx/tienda/incubadora-portable/', 'Incubadora Termostática de Convección Natural (RT+5 – 70 °C) Compacta', 'Amunet',
  NULL, NULL, NULL, '20% - 50% (Equipo de Inversión)', '[]'::jsonb,
  NULL, NULL, NULL, NULL, NULL, NULL,
  NULL, NULL, '[Mantenimiento Anual].', '[NO REQUIERE - Equipo no invasivo / Equipamiento General].',
  'Equipamiento de Incubación Microbiológica, Cultivo Celular y Pruebas Bioquímicas Biológicas.', 'Incubadora compacta de precisión portátil para consultorio, laboratorio clínico y brigadas de campo. Mantiene temperatura constante para: cultivos microbioológicos (37°C), amplificación isotérmica LAMP/Bionet (60-65°C), y reacciones enzimáticas que requieren control térmico preciso (±0.5°C).', ARRAY['Química Clínica', 'Bacteriología Científica', 'Biología Molecular RT-LAMP (Pruebas Bionet Rápidas)', 'Sector Universitario Investigador y Veterinarios Rurales Inseminadores'], '- **Amplificación de Bionet PCR Rápidas 60°C Constantes:** El Infectólogo acaba de hisopar una cervíx para el RT-LAMP PCR VPH Multi en su pequeño consultorio ginecológico "Sin equipo gigante pesado hospitalario". Enchufa en la mesa su Portable PI2500AB programada a 62.0°C. Entra en ciclo térmico PDI Inteligente garantizando la copia enzimatica del ADN Papiloma durante 30 minutos constantes de oro para detonar el Rosa en su prueba. ¡PCR de campo exitosa Termostática de bolsillo!.',
  NULL, NULL, 'No es una mufla; No quema ni esteriliza en seco super alta (70°C máx tope cálido corporal biológico). Exige ambiente ventilado externo sin calor directo solar.', NULL, NULL,
  'Incubadora portátil de acero inoxidable con control PDI para cultivos bacteriológicos (37°C) y amplificación molecular LAMP (60-65°C), con alarmas de sobretemperatura para protección de muestras.', 'Incubadora dual: cultivos a 37°C Y amplificación LAMP a 65°C. 80W de consumo, 9.2 litros, acero inoxidable. Es tu puerta de entrada a biología molecular sin invertir en termocicladores.', 'Las incubadoras convencionales pesan 50+ kg y consumen 1000W. La PI2500AB consume solo 80W con aislamiento de poliuretano, compatible con enchufes estándar 110V, ideal para brigadas epidemiológicas y consultorios con espacio limitado.', NULL, NULL,
  '[]'::jsonb, '[]'::jsonb,
  '[{"name":"Kit PCR VPH + Tiras Bionet + Cepillo Cervical:","reason":"La incubadora es el motor de su laboratorio molecular. URL VPH: https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/ URL Bionet: https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/ URL Cepillo: https://www.amunet.com.mx/tienda/cepillo-para-muestras-cervicales/","url":null},{"name":"Pipetas Ajustables:","reason":"Para dosificación precisa en protocolos moleculares.","url":"https://www.amunet.com.mx/tienda/pipetas/"}]'::jsonb, '[{"name":"Incubadora Laboratorista Amunet:","reason":"Si su volumen crece, la versión de mayor capacidad procesa más muestras simultáneas.","url":"https://www.amunet.com.mx/tienda/incubadora-laboratorista-amunet/"}]'::jsonb, '{}', ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
