  is_active, created_at, updated_at
) VALUES (
  'Incubadora Laboratorista Amunet', 'equipos', 'https://www.amunet.com.mx/tienda/incubadora-laboratorista-amunet/', 'Incubadora Termostática de Piso/Mesa Mayor Capacidad.', 'Amunet',
  NULL, NULL, NULL, '20% - 50% (Equipo de Inversión Hospitalaria)', '[]'::jsonb,
  NULL, NULL, NULL, NULL, NULL, NULL,
  NULL, NULL, NULL, '[NO REQUIERE].',
  'Equipamiento de Estación de Microbiología Central Clínica y Hospitalaria Industrial.', 'Procesar y anidar las centenas de "Cajas de Petri" de siembras matutinas urocultivos, hemocultivos y exudados diarios del hospital con recirculación o ambiente de convección homogéneo grande.', ARRAY['Jefatura de Laboratorio Clínico Centralizados', 'Infectología Mayor y Control de Calidad Alimentaria FDA/COFEPRIS Pyme'], '- **Maduración del Hemocultivo Sepsis a 48HRS:** Recepcionadas las 200 muestras bacteriológicas de piso hospitalario a las 9 am, el Químico titular alinea las torres apiladas de cajas de Petri en los amplios rieles configurados a 37°C. La Incubadora de mayor calado saca el "Trabajo Pesado Laboratorial Matutino" asegurando desarrollo homogéneo parejito sin puntos fríos para que se lean el miércoles sin contaminación de condensaciones agresivas.',
  NULL, NULL, NULL, NULL, NULL,
  'Incubadora central para siembras diarias microbiológicas hospitalarias, con exactitud térmica que garantiza desarrollo homogéneo de cultivos para no perder ni un Estafilococo en un mar de volumen clínico institucional.', 'Para laboratorios de alto volumen:** Cuando tu portátil se queda chica. Capacidad para carga diaria completa de urocultivos, hemocultivos y exudados.', '[Equipo Central Integrador Amunet].', NULL, NULL,
  '[]'::jsonb, '[]'::jsonb,
