-- Product: Pipetas Ajustables Multivolumen (5-50 µL y 100-1000 µL)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Pipetas Ajustables Multivolumen (5-50 µL y 100-1000 µL)', 'consumibles', 'https://www.amunet.com.mx/tienda/pipetas/', 'Pipeta Monocanal de Volumen Variable Transferencia de Líquidos.', 'Amunet',
  1300, NULL, NULL, NULL, '[]'::jsonb,
  NULL, NULL, NULL, NULL, NULL, NULL,
  NULL, NULL, NULL, '[NO REQUIERE].',
  'Instrumentación Calibradora Obligada Cero-Error de Mesada.', 'Dosificar con precisión volúmenes exactos de sueros, plasmas, eluyentes RT-LAMP y muestras virales para garantizar que las reacciones inmunocromatográficas y RT-PCR produzcan resultados confiables, evitando falsos positivos por exceso o falsos negativos por volumen insuficiente.', ARRAY['QFB Bioquímicos Universitarios Universales', 'Laboratoristas Técnicos Analíticos y Genetistas Moleculares del ADN Forense'], '- **La Alícuota de RT-PCR Virus de papiloma Perfecta:** El protocolo Bionet requiere añadir exactamente 10 µL de muestra de ADN al tubo de amplificación. La pipeta 5-50 µL permite dosificar este volumen con precisión, evitando errores por goteo manual que pueden afectar la eficiencia de la reacción LAMP y desperdiciar reactivos.',
  NULL, NULL, NULL, NULL, NULL,
  'Pipetas de precisión calibradas para volúmenes de 5-50 µL y 100-1000 µL, con mecanismo ergonómico de baja fatiga. Esenciales para protocolos RT-LAMP, serología y preparación de muestras donde la exactitud volumétrica determina la confiabilidad del resultado.', 'A $1,300 la pipeta, protege tus kits moleculares de $265-$500 por prueba. Un pipeteo impreciso = reacción fallida = $385 desperdiciados. La pipeta se paga sola en 3 pruebas salvadas.', NULL, NULL, NULL,
  '[{"pregunta":"¿Es compatible con puntas universales?","respuesta":"Sí, el cono es universal europeo compatible con la mayoría de puntas estándar. Se recomienda usar puntas con filtro para proteger el pistón de aerosoles y prolongar la vida útil del instrumento."}]'::jsonb, '[]'::jsonb,
  '[{"name":"Puntas para Pipetas:","reason":"Consumible obligatorio de reposición frecuente (200-500 puntas/mes por pipeta activa).","url":"https://www.amunet.com.mx/tienda/puntas-para-pipetas-50ul-96-piezas/"},{"name":"Incubadora Portátil + Kits PCR:","reason":"Las pipetas son parte del flujo de trabajo molecular.","url":"https://www.amunet.com.mx/tienda/incubadora-portable/"},{"name":"Puntas para Pipetas:","reason":"Consumible de reposición frecuente.","url":"https://www.amunet.com.mx/tienda/pipetas/"},{"name":"Kit VPH PCR / VIH PCR:","reason":"Los kits moleculares que justifican la inversión. URL VPH: https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/ URL VIH: https://www.amunet.com.mx/tienda/pcr-rapida-para-vih-1-y-2/","url":null}]'::jsonb, '[{"name":"Incubadora Laboratorista Amunet:","reason":"Si su volumen crece, la versión de mayor capacidad procesa más muestras simultáneas.","url":"https://www.amunet.com.mx/tienda/incubadora-laboratorista-amunet/"}]'::jsonb, ARRAY['Pipeta laboratorio calibrada ISO LAMP molecular micro macro volumen'], ARRAY['medico', 'laboratorio'],
  TRUE, NOW(), NOW()
)
