-- Product: Cepillo para Muestras Cervicales (PRODUCTO ESTRELLA)
INSERT INTO medical_products (
  name, diagnostic_category, url_tienda, tipo_producto, marca,
  precio_publico, precio_por_prueba, precio_sugerido_paciente, margen_estimado, presentaciones,
  analito, sample_type, volumen_muestra, result_time, sensitivity, specificity,
  punto_corte, storage_conditions, shelf_life, registro_sanitario,
  clasificacion_clinica, proposito_clinico, especialidades, escenarios_uso,
  perfil_paciente, frecuencia_uso, limitaciones, resultado_positivo, resultado_negativo,
  pitch_medico, pitch_laboratorio, ventaja_vs_lab, roi_medico, porque_agregarlo_lab,
  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'Cepillo para Muestras Cervicales (PRODUCTO ESTRELLA)', 'otros', 'https://www.amunet.com.mx/tienda/cepillo-para-muestras-cervicales/', NULL, 'Amunet',
  250, NULL, NULL, NULL, '[]'::jsonb,
  NULL, NULL, NULL, NULL, NULL, NULL,
  NULL, NULL, NULL, NULL,
  NULL, NULL, '{}', NULL,
  NULL, NULL, NULL, NULL, NULL,
  NULL, 'Tu cepillo cervical determina dos cosas: la calidad de tu muestra y si la paciente regresa el próximo año. El cepillo Amunet es suave (menos dolor), flexible (no se rompe), y estéril individual (cero contaminación). Tu tasa de falsos negativos baja y tu tasa de retención sube.', NULL, NULL, 'Este cepillo cambia la experiencia de la toma cervical. Las pacientes se quejan del cepillo rígido convencional — duele, asusta, y muchas no regresan a su tamizaje anual. El cepillo Amunet tiene punta suave y flexible que recoge más células con menos molestia. Resultado: mejor muestra Y paciente que regresa.
Si tu laboratorio toma muestras para VPH (ya sea PCR propia con kit Amunet o envío a referencia), este cepillo debe ser tu estándar. No solo mejora la experiencia de la paciente, sino que la calidad de la muestra impacta directamente la sensibilidad de la prueba.',
  '[]'::jsonb, '[{"pregunta":"Ya compro cepillos genéricos chinos","respuesta":"** ¿Y cuántas pacientes se quejan de dolor? ¿Cuántas no regresan? Un cepillo suave = paciente que regresa = otra prueba de VPH el año que viene. El cepillo genérico te ahorra $5 hoy y te cuesta una paciente recurrente."},{"pregunta":"¿Es compatible con mi PCR de referencia?","respuesta":"** Sí. El cepillo recoge células cervicales — funciona igual con LAMP Amunet, PCR convencional, o citología en líquido. Es el instrumento de toma, no cambia el análisis."}]'::jsonb,
  '[{"name":"Kit VPH PCR (LAMP):","reason":"Si ya usas el cepillo, dale el paso completo: haz tu PCR de VPH in-house con el kit Amunet.","url":"https://www.amunet.com.mx/tienda/pcr-rapid-para-vph/"},{"name":"Incubadora Portátil:","reason":"Necesaria para la amplificación LAMP.","url":"https://www.amunet.com.mx/tienda/incubadora-portable/"},{"name":"Tiras Bionet MULTI:","reason":"Lectura del resultado molecular.","url":"https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/"}]'::jsonb, '[]'::jsonb, '{}', ARRAY['laboratorio'],
  TRUE, NOW(), NOW()
)
