  objeciones_medico, objeciones_laboratorio,
  cross_sells, up_sells, palabras_clave, target_audience,
  is_active, created_at, updated_at
) VALUES (
  'PCR rápida LAMP para Salmonella spp', 'otros', 'https://www.amunet.com.mx/tienda/pcr-rapida-lamp-para-salmonella-ssp/', NULL, 'Amunet',
  NULL, NULL, NULL, NULL, '[]'::jsonb,
  'ADN de Salmonella spp (todas las especies, no solo typhi)', 'Muestras alimentarias (carnes, lácteos, mariscos),', NULL, '~60 minutos (enriquecimiento previo + lisis + amplificación + lectura en tira Bionet)', 99, 99,
  NULL, NULL, NULL, NULL,
  NULL, NULL, '{}', NULL,
  NULL, NULL, NULL, NULL, NULL,
  NULL, 'Para laboratorios de alimentos:** Tu cultivo de Salmonella tarda 5 días. La PCR LAMP te da resultado presuntivo en 60 minutos. Liberas lotes en el mismo turno de producción. Tu cliente deja de perder dinero en retención y tú cobras doble: PCR rápida + cultivo confirmatorio.', NULL, NULL, 'Tu laboratorio de alimentos hace cultivo ISO 6579 para Salmonella. Eso tarda 3-5 DÍAS. Tu cliente (la planta procesadora) tiene un lote de pollo retenido en cámara fría esperando tu resultado. Cada día de retención le cuesta miles de pesos en almacenamiento y logística.
Con la PCR LAMP, puedes emitir un resultado negativo presuntivo en 60 minutos. Si es negativo, el lote se libera. Si es positivo, confirmas con tu cultivo. Tu cliente te ama porque le ahorras 4 días de retención. Tu laboratorio cobra por dos servicios: PCR rápida + cultivo confirmatorio.',
  '[]'::jsonb, '[{"pregunta":"La NOM exige cultivo","respuesta":"** Correcto. La PCR LAMP no reemplaza el cultivo oficial (NOM-210-SSA1-2014). Es un SCREENING presuntivo rápido que permite decisiones operativas inmediatas. El cultivo sigue corriendo en paralelo como confirmatorio. Son servicios complementarios."},{"pregunta":"¿Necesito termociclador?","respuesta":"** No. La tecnología LAMP amplifica a temperatura constante (65°C). Tu incubadora Amunet o el Termobloque de 22 pozos hace el trabajo."}]'::jsonb,
  '[{"name":"Tiras Bionet MULTI:","reason":"Componente obligatorio de lectura.","url":"https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/"},{"name":"Termobloque 22 pozos o Incubadora Portátil:","reason":"Para la fase de amplificación. URL Termobloque: https://www.amunet.com.mx/tienda/termobloque-profesional-laboratorios/ URL Incubadora: https://www.amunet.com.mx/tienda/incubadora-portable/","url":null},{"name":"PCR Listeria monocytogenes:","reason":"El combo obligatorio de inocuidad alimentaria: Salmonella + Listeria.","url":"https://www.amunet.com.mx/tienda/pcr-rapida-para-listeria-monocytogenes/"}]'::jsonb, '[]'::jsonb, '{}', ARRAY['laboratorio'],
  TRUE, NOW(), NOW()
)
