  is_active, created_at, updated_at
) VALUES (
  'PCR rápida LAMP para Listeria monocytogenes', 'otros', 'https://www.amunet.com.mx/tienda/pcr-rapida-para-listeria-monocytogenes/', NULL, 'Amunet',
  NULL, NULL, NULL, NULL, '[]'::jsonb,
  'ADN de Listeria monocytogenes (gen hlyA — el gen de Listeriolisina O, factor de virulencia)', 'Muestras alimentarias (lácteos, embutidos, listos ', NULL, '~60 minutos', 97, NULL,
  NULL, NULL, NULL, NULL,
  NULL, NULL, '{}', NULL,
  NULL, NULL, NULL, NULL, NULL,
  NULL, 'Para laboratorios de alimentos:** Listeria es tolerancia cero. Tu cultivo tarda 7 días. Mientras tanto, tu cliente tiene 10 toneladas de queso fresco retenido. Con la PCR LAMP, das ausencia presuntiva en 60 minutos. Si sale limpio, liberas el lote. Si sale positivo, retienes y confirmas con cultivo. Tu cliente evita recalls millonarios y tú eres su laboratorio indispensable.', NULL, NULL, 'Listeria es el patógeno MÁS temido en la industria de alimentos listos para consumo (ready to eat). Un recall por Listeria destruye marcas. El cultivo tarda 5-7 DÍAS (ISO 11290). Con la PCR LAMP, tu laboratorio emite ausencia presuntiva en 60 minutos. Las plantas de quesos, embutidos y ensaladas listas van a NECESITAR este servicio.',
  '[]'::jsonb, '[{"pregunta":"¿Por qué el gen hlyA?","respuesta":"** Porque es el gen de la Listeriolisina O, el factor de virulencia de L. monocytogenes. No amplifica Listeria innocua ni otras especies no patógenas. Es específico para la especie patógena."}]'::jsonb,
  '[{"name":"PCR Salmonella spp:","reason":"El par obligatorio de inocuidad: Salmonella + Listeria = 90% de los recalls.","url":"https://www.amunet.com.mx/tienda/pcr-rapida-lamp-para-salmonella-ssp/"},{"name":"Tiras Bionet MULTI + Termobloque/Incubadora:","reason":"Equipamiento de plataforma. URL Bionet: https://www.amunet.com.mx/tienda/bionet-multi-pcr-rapida-rt-lamp/ URL Termobloque: https://www.amunet.com.mx/tienda/termobloque-profesional-laboratorios/ URL Incubadora: https://www.amunet.com.mx/tienda/incubadora-portable/","url":null}]'::jsonb, '[]'::jsonb, '{}', ARRAY['laboratorio'],
  TRUE, NOW(), NOW()
)
